def make_track_id(label: str, existing_ids: Optional[set[str]] = None) -> str:
    existing_ids = existing_ids or set()
    base = "".join(ch.lower() if ch.isalnum() else "_" for ch in (label or "track")).strip("_") or "track"
    while "__" in base:
        base = base.replace("__", "_")
    candidate = base
    index = 2
    while candidate in existing_ids:
        candidate = f"{base}_{index}"
        index += 1
    return candidate


def track_number_from_name(value: str) -> Optional[int]:
    """Return the stable number from labels/ids like 'Track 3' or 'track_3'."""
    raw = str(value or "").strip().lower().replace("_", " ").replace("-", " ")
    parts = raw.split()
    if len(parts) == 2 and parts[0] == "track":
        try:
            number = int(parts[1])
            return number if number > 0 else None
        except Exception:
            return None
    return None


def next_track_label_from_tracks(tracks: List["TimelineTrack"]) -> str:
    numbers: List[int] = []
    for track in tracks:
        number = track_number_from_name(getattr(track, "label", ""))
        if number is not None:
            numbers.append(number)
        number = track_number_from_name(getattr(track, "track_id", ""))
        if number is not None:
            numbers.append(number)
    return f"Track {max(numbers, default=0) + 1}"


def framevision_root() -> Path:
    # helpers/timeline_editor.py -> FrameVision root
    return Path(__file__).resolve().parents[1]


def settings_path() -> Path:
    return framevision_root() / "presets" / "setsave" / "timeline_editor.json"


def timeline_editor_default_project_path(app_root: Optional[Path] = None) -> Path:
    root = Path(app_root).resolve() if app_root is not None else framevision_root()
    return root / "temp" / "timeline_editor_project.json"


def default_project_path() -> Path:
    return timeline_editor_default_project_path()


def timeline_editor_autosave_path(app_root: Optional[Path] = None) -> Path:
    root = Path(app_root).resolve() if app_root is not None else framevision_root()
    return root / "temp" / TIMELINE_AUTOSAVE_JSON_NAME


def _timeline_editor_same_path(left: Any, right: Any) -> bool:
    try:
        return os.path.normcase(os.path.abspath(str(left))) == os.path.normcase(os.path.abspath(str(right)))
    except Exception:
        return str(left or "").strip().lower() == str(right or "").strip().lower()


def timeline_editor_atomic_save_json(path: Path, payload: Dict[str, Any]) -> None:
    target = Path(path)
    target.parent.mkdir(parents=True, exist_ok=True)
    tmp_path = target.with_name(target.name + ".tmp")
    tmp_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    os.replace(str(tmp_path), str(target))


def timeline_editor_is_real_project_save_path(path_value: Any, app_root: Optional[Path] = None) -> bool:
    raw = str(path_value or "").strip()
    if not raw:
        return False
    try:
        candidate = Path(raw).expanduser()
        if not candidate.is_absolute():
            root = Path(app_root).resolve() if app_root is not None else framevision_root()
            candidate = root / candidate
        candidate = candidate.resolve()
    except Exception:
        return False
    if not candidate.exists() or not candidate.is_file():
        return False
    if candidate.suffix.lower() != ".json":
        return False
    if _timeline_editor_same_path(candidate, timeline_editor_autosave_path(app_root)):
        return False
    if _timeline_editor_same_path(candidate, timeline_editor_default_project_path(app_root)):
        return False
    return True


def timeline_editor_resolve_autosave_target(last_project_path: Any, app_root: Optional[Path] = None) -> Tuple[Path, str]:
    if timeline_editor_is_real_project_save_path(last_project_path, app_root):
        try:
            candidate = Path(str(last_project_path)).expanduser()
            if not candidate.is_absolute():
                root = Path(app_root).resolve() if app_root is not None else framevision_root()
                candidate = root / candidate
            return candidate.resolve(), "project"
        except Exception:
            pass
    return timeline_editor_autosave_path(app_root), "recovery"


def normalize_project_canvas_size(width: Any = None, height: Any = None) -> Tuple[int, int]:
    """Return a safe project canvas size.

    The project canvas is the final composition size. Source media, images,
    transition masks, and preview-quality targets must never redefine it.
    """
    w = safe_int(width, DEFAULT_PROJECT_CANVAS_WIDTH)
    h = safe_int(height, DEFAULT_PROJECT_CANVAS_HEIGHT)
    if w <= 0:
        w = DEFAULT_PROJECT_CANVAS_WIDTH
    if h <= 0:
        h = DEFAULT_PROJECT_CANVAS_HEIGHT
    # Keep this editor from creating accidental huge preview/export canvases.
    w = int(clamp(w, 64, 8192))
    h = int(clamp(h, 64, 8192))
    return w, h


def project_canvas_label(width: Any, height: Any) -> str:
    w, h = normalize_project_canvas_size(width, height)
    return f"{w}x{h}"


def project_canvas_aspect_label(width: Any, height: Any) -> str:
    w, h = normalize_project_canvas_size(width, height)
    if h <= 0:
        return "?"
    value = w / float(h)
    known = [
        ("16:9", 16.0 / 9.0),
        ("9:16", 9.0 / 16.0),
        ("1:1", 1.0),
        ("4:3", 4.0 / 3.0),
        ("3:4", 3.0 / 4.0),
    ]
    for label, ratio in known:
        if abs(value - ratio) < 0.015:
            return label
    return f"{value:.2f}:1"


def normalize_preview_quality(value: Any) -> str:
    raw = str(value or "").strip().lower().replace(" ", "_").replace("-", "_")
    if raw in {"480", "480p", "low", "preview_480"}:
        return PREVIEW_QUALITY_480
    if raw in {"720", "720p", "medium", "preview_720"}:
        return PREVIEW_QUALITY_720
    if raw in {"full", "full_canvas", "canvas", "source", "original"}:
        return PREVIEW_QUALITY_FULL
    if raw in {"auto", "automatic"}:
        return PREVIEW_QUALITY_AUTO
    return DEFAULT_PREVIEW_QUALITY


def preview_quality_label(value: Any) -> str:
    return PREVIEW_QUALITY_LABELS.get(normalize_preview_quality(value), PREVIEW_QUALITY_LABELS[DEFAULT_PREVIEW_QUALITY])


def preview_quality_target_size(canvas_width: Any, canvas_height: Any, quality: Any) -> Tuple[int, int]:
    """Return the internal live preview composite target without changing project canvas.

    480p/720p are interpreted like normal video presets: the shorter side is
    480/720 for landscape, and the width is 480/720 for portrait. Full canvas
    returns the exact project canvas.
    """
    cw, ch = normalize_project_canvas_size(canvas_width, canvas_height)
    q = normalize_preview_quality(quality)
    if q == PREVIEW_QUALITY_FULL:
        return cw, ch
    target = 720 if q == PREVIEW_QUALITY_720 else 480
    if q == PREVIEW_QUALITY_AUTO:
        target = 720 if max(cw, ch) >= 1280 else min(cw, ch)
    if cw >= ch:
        if ch <= target:
            return cw, ch
        scale = target / float(ch)
    else:
        if cw <= target:
            return cw, ch
        scale = target / float(cw)
    w = max(64, int(round(cw * scale)))
    h = max(64, int(round(ch * scale)))
    # keep paint/export-friendly even dimensions
    if w % 2:
        w += 1
    if h % 2:
        h += 1
    return w, h

def project_canvas_preview_plan(project: Optional["TimelineProject"], preview_quality: Any = DEFAULT_PREVIEW_QUALITY) -> Dict[str, Any]:
    if project is None:
        cw, ch = DEFAULT_PROJECT_CANVAS_WIDTH, DEFAULT_PROJECT_CANVAS_HEIGHT
    else:
        cw, ch = normalize_project_canvas_size(getattr(project, "canvas_width", DEFAULT_PROJECT_CANVAS_WIDTH), getattr(project, "canvas_height", DEFAULT_PROJECT_CANVAS_HEIGHT))
    tw, th = preview_quality_target_size(cw, ch, preview_quality)
    return {
        "canvas_width": cw,
        "canvas_height": ch,
        "preview_quality": normalize_preview_quality(preview_quality),
        "preview_width": tw,
        "preview_height": th,
        "project_canvas_unchanged": (cw, ch),
    }


def transition_mask_target_size_for_canvas(project: Optional["TimelineProject"], preview_quality: Any = DEFAULT_PREVIEW_QUALITY) -> Tuple[int, int]:
    plan = project_canvas_preview_plan(project, preview_quality)
    return int(plan["preview_width"]), int(plan["preview_height"])


def transition_composite_target_size_for_preview(project: Optional["TimelineProject"], preview_quality: Any = DEFAULT_PREVIEW_QUALITY) -> Tuple[int, int]:
    """Return the fixed internal PNG transition composite size.

    This is the same preview-quality canvas target used for black/project
    preview planning. Source media size and PNG mask size must not redefine it.
    """
    return transition_mask_target_size_for_canvas(project, preview_quality)


def transition_preview_display_path_name() -> str:
    """Self-testable marker: transitions use the normal QLabel canvas display path."""
    return "normal_preview_canvas"


def transition_display_plan_for_preview(project: Optional["TimelineProject"], preview_quality: Any = DEFAULT_PREVIEW_QUALITY) -> Dict[str, Any]:
    width, height = transition_composite_target_size_for_preview(project, preview_quality)
    return {
        "composite_width": int(width),
        "composite_height": int(height),
        "display_path": transition_preview_display_path_name(),
        "uses_project_canvas_target": True,
    }


def source_resolution_does_not_change_canvas(project: "TimelineProject", source_width: Any, source_height: Any) -> bool:
    before = (getattr(project, "canvas_width", DEFAULT_PROJECT_CANVAS_WIDTH), getattr(project, "canvas_height", DEFAULT_PROJECT_CANVAS_HEIGHT))
    _ = normalize_project_canvas_size(source_width, source_height)
    after = (getattr(project, "canvas_width", DEFAULT_PROJECT_CANVAS_WIDTH), getattr(project, "canvas_height", DEFAULT_PROJECT_CANVAS_HEIGHT))
    return before == after


def project_window_title(base_title: str, dirty: bool) -> str:
    base = str(base_title or APP_NAME).strip() or APP_NAME
    return f"{base} *" if bool(dirty) else base


def new_project_editor_state_preserving_ui(source: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    """Return an editor-state payload for New Project without wiping UI/layout preferences."""
    state = dict(source or {})
    state["version"] = PROJECT_JSON_VERSION
    state["scroll_x"] = 0.0
    state["vertical_scroll"] = 0
    state["playhead_time"] = 0.0
    state["selected_clip_id"] = ""
    state["selected_media_id"] = ""
    state["target_track_id"] = ""
    # Preview zoom/pan/current playback are transient and should start clean.
    state["preview_zoom"] = 1.0
    state.pop("preview_qt_active", None)
    state.pop("timeline_playback_active", None)
    state.pop("hover_time", None)
    return state


def project_dirty_after_clean_state(clean_state: str, current_state: str) -> bool:
    return str(clean_state or "") != str(current_state or "")



def normalize_audio_mode(value: Any) -> str:
    raw_label = str(value or "").strip().lower()
    raw = raw_label.replace("-", "_").replace(" ", "_")
    if raw in {AUDIO_MODE_MIX_ALL, "mix", "mixed", "mix_all", "mixall", "all", "all_audio", "mixed_audio", "real_mix"}:
        return AUDIO_MODE_MIX_ALL
    if raw in {AUDIO_MODE_VIDEO, LEGACY_AUDIO_MODE_VIDEO, "video", "videoaudio", "video_only", "visual_audio", "clip_audio", "active_video_audio"}:
        return AUDIO_MODE_VIDEO
    if raw in {AUDIO_MODE_TRACK, LEGACY_AUDIO_MODE_TRACK, "track", "tracks", "audio", "audio_tracks", "audio_only", "audio_track_mode", "audio_tracks_only"}:
        return AUDIO_MODE_TRACK
    if raw in {AUDIO_MODE_MUTE, "muted", "silent", "silence", "off", "none", "no_audio"}:
        return AUDIO_MODE_MUTE
    # Compatibility with older saved UI labels.
    if raw_label == "video audio":
        return AUDIO_MODE_VIDEO
    if raw_label == "audio track":
        return AUDIO_MODE_TRACK
    return AUDIO_MODE_FROM_LABEL.get(raw_label, AUDIO_MODE_MIX_ALL)


def audio_mode_label(value: Any) -> str:
    return AUDIO_MODE_LABELS.get(normalize_audio_mode(value), AUDIO_MODE_LABELS[AUDIO_MODE_MIX_ALL])


def resolve_tool_path(tool_name: str, app_root: Optional[Path] = None, path_value: Optional[str] = None) -> Optional[Path]:
    """Resolve an FFmpeg-family executable using FrameVision's preferred order.

    Lookup order:
    1) <FrameVision root>/presets/bin/<tool>.exe or <tool>
    2) <FrameVision root>/bin/<tool>.exe or <tool>
    3) system PATH

    The optional app_root/path_value arguments are used by self-tests so the
    resolver can be tested without depending on the real user's install.
    """
    root = Path(app_root).resolve() if app_root is not None else framevision_root()
    base = Path(tool_name).stem
    names = [f"{base}.exe", base]

    for folder in (root / "presets" / "bin", root / "bin"):
        for name in names:
            candidate = folder / name
            if candidate.exists():
                return candidate

    for name in names:
        found = shutil.which(name, path=path_value) if path_value is not None else shutil.which(name)
        if found:
            return Path(found)
    return None


def ffmpeg_path() -> Optional[Path]:
    return resolve_tool_path("ffmpeg")


def ffprobe_path() -> Optional[Path]:
    return resolve_tool_path("ffprobe")


def ffplay_path() -> Optional[Path]:
    return resolve_tool_path("ffplay")


def tool_path_summary() -> str:
    def _one(name: str, path: Optional[Path]) -> str:
        return f"{name}: {path}" if path else f"{name}: not found"

    return " | ".join(
        [
            _one("ffmpeg", ffmpeg_path()),
            _one("ffprobe", ffprobe_path()),
            _one("ffplay", ffplay_path()),
        ]
    )




def timeline_media_cache_dir(app_root: Optional[Path] = None) -> Path:
    """Portable cache folder for timeline thumbnails/waveform previews."""
    root = Path(app_root).resolve() if app_root is not None else framevision_root()
    return root / "temp" / TIMELINE_MEDIA_CACHE_FOLDER_NAME


def _timeline_cache_path_key(path_value: Any) -> str:
    return normalized_project_path_key(path_value)


def _timeline_cache_hash(parts: List[Any]) -> str:
    raw = "|".join(str(part) for part in parts)
    return hashlib.sha1(raw.encode("utf-8", errors="ignore")).hexdigest()[:20]


def thumbnail_cache_key_for_clip(clip: Optional["Clip"]) -> str:
    """Stable thumbnail key. Source/trim changes invalidate; timeline moves do not."""
    if clip is None or not clip_is_visual(clip):
        return ""
    media_type = clip_media_type(clip)
    # Image thumbnails use the image file directly, but keep trim fields in the
    # key shape for consistent invalidation if image duration/trimming is added.
    return _timeline_cache_hash([
        "thumb",
        media_type,
        _timeline_cache_path_key(getattr(clip, "file_path", "")),
        round(safe_float(getattr(clip, "in_point", 0.0), 0.0), 3) if media_type == "video" else 0.0,
        round(safe_float(getattr(clip, "duration", 0.0), 0.0), 3) if media_type == "video" else 0.0,
    ])


def clip_waveform_eligible(clip: Optional["Clip"]) -> bool:
    if clip is None:
        return False
    media_type = clip_media_type(clip)
    if media_type == "audio":
        return True
    # Video waveform is optional in v30. Keep it conservative and only allow it
    # when the clip still has enabled embedded audio.
    if media_type == "video" and clip_audio_enabled_value(clip):
        return True
    return False


def waveform_cache_key_for_clip(clip: Optional["Clip"]) -> str:
    """Stable waveform key. Includes path and trim/in-point, but not timeline start."""
    if clip is None or not clip_waveform_eligible(clip):
        return ""
    return _timeline_cache_hash([
        "wave",
        clip_media_type(clip),
        _timeline_cache_path_key(getattr(clip, "file_path", "")),
        round(safe_float(getattr(clip, "in_point", 0.0), 0.0), 3),
        round(safe_float(getattr(clip, "duration", 0.0), 0.0), 3),
        round(clip_speed_value(clip), 3) if clip_supports_speed(clip) else 1.0,
    ])


def image_thumbnail_uses_image_path(clip: Optional["Clip"]) -> bool:
    return bool(clip is not None and clip_media_type(clip) == "image" and str(getattr(clip, "file_path", "")).strip())


def timeline_thumbnail_display_mode_default() -> str:
    """Default drawing policy: a single readable thumbnail block at clip start."""
    return TIMELINE_THUMBNAIL_DISPLAY_MODE


def timeline_thumbnail_area_width(clip_width: Any) -> float:
    """Return start-only thumbnail width, or 0 when the clip is too narrow."""
    available = max(0.0, safe_float(clip_width, 0.0) - (TIMELINE_THUMBNAIL_PAD * 2.0))
    if available < TIMELINE_THUMBNAIL_MIN_WIDTH:
        return 0.0
    target = min(TIMELINE_THUMBNAIL_MAX_WIDTH, max(TIMELINE_THUMBNAIL_BASE_WIDTH, available * TIMELINE_THUMBNAIL_MAX_CLIP_RATIO))
    width = min(available, target)
    return width if width >= TIMELINE_THUMBNAIL_MIN_WIDTH else 0.0


def timeline_thumbnail_area_rect(rect_left: Any, rect_top: Any, rect_width: Any, rect_height: Any) -> Dict[str, float]:
    """Pure geometry helper used by paint and self-tests."""
    width = timeline_thumbnail_area_width(rect_width)
    height = max(0.0, safe_float(rect_height, 0.0) - (TIMELINE_THUMBNAIL_PAD * 2.0))
    if width <= 0.0 or height < 20.0:
        return {"visible": False, "x": 0.0, "y": 0.0, "w": 0.0, "h": 0.0}
    return {
        "visible": True,
        "x": safe_float(rect_left, 0.0) + TIMELINE_THUMBNAIL_PAD,
        "y": safe_float(rect_top, 0.0) + TIMELINE_THUMBNAIL_PAD,
        "w": width,
        "h": height,
    }


def timeline_thumbnail_brighten_alpha() -> int:
    """Small Qt overlay used to keep dark thumbnails readable on colored clips."""
    return int(clamp(TIMELINE_THUMBNAIL_BRIGHTEN_ALPHA, 0, 120))


def timeline_thumbnail_border_alpha() -> int:
    return int(clamp(TIMELINE_THUMBNAIL_BORDER_ALPHA, 40, 220))


def timeline_waveform_dimmed_background_enabled(show_waveform: Any, has_waveform_bars: Any) -> bool:
    """Clip color should calm down only when a real waveform is visible."""
    return bool(show_waveform) and bool(has_waveform_bars)


def timeline_waveform_dimmed_rgb(red: Any, green: Any, blue: Any) -> Tuple[int, int, int]:
    def _dim(value: Any) -> int:
        return int(clamp(TIMELINE_WAVEFORM_DIM_FLOOR + safe_float(value, 0.0) * TIMELINE_WAVEFORM_DIM_MULTIPLIER, 0.0, 255.0))
    return _dim(red), _dim(green), _dim(blue)


def timeline_waveform_toggle_invalidates_cache() -> bool:
    """Toggling display style must not invalidate media-derived waveform data."""
    return False


def timeline_missing_thumbnail_placeholder_info(clip_name: Any = "") -> Dict[str, Any]:
    return {"placeholder": True, "kind": "thumbnail", "clip": str(clip_name or ""), "reason": "missing thumbnail"}


def timeline_selected_clip_border_enabled_with_visual_aids(selected: Any, thumbnails: Any = True, waveforms: Any = True) -> bool:
    # Visual aids are drawn inside the clip rect and must not disable the normal selected border.
    return bool(selected)


def timeline_paint_path_requests_media_generation() -> bool:
    """Paint must only draw cached thumbnail/waveform data."""
    return False


def timeline_transition_paint_path_rescans_or_loads_masks() -> bool:
    """Transition indicators are lightweight timeline drawing only."""
    return False

def timeline_missing_source_placeholder_info(kind: str, clip_name: Any = "") -> Dict[str, Any]:
    label = str(kind or "media").strip().lower() or "media"
    return {"placeholder": True, "kind": label, "clip": str(clip_name or ""), "reason": "missing source"}


def timeline_waveform_cache_invalidated(old_clip: Optional["Clip"], new_clip: Optional["Clip"]) -> bool:
    return waveform_cache_key_for_clip(old_clip) != waveform_cache_key_for_clip(new_clip)


def timeline_waveform_cache_preserved_by_clip_move(clip: Optional["Clip"], new_start: Any) -> bool:
    if clip is None:
        return True
    try:
        moved = Clip.from_dict(clip.to_dict())
        moved.start = safe_float(new_start, getattr(clip, "start", 0.0))
        return waveform_cache_key_for_clip(clip) == waveform_cache_key_for_clip(moved)
    except Exception:
        return False
def clamp(value: float, low: float, high: float) -> float:
    if high < low:
        return low
    return max(low, min(high, value))


def fmt_time(seconds: float) -> str:
    seconds = max(0.0, float(seconds))
    ms = int(round((seconds - int(seconds)) * 1000))
    total = int(seconds)
    h = total // 3600
    m = (total % 3600) // 60
    s = total % 60
    if h:
        return f"{h:02d}:{m:02d}:{s:02d}.{ms:03d}"
    return f"{m:02d}:{s:02d}.{ms:03d}"


def fmt_ruler_time(seconds: float, major_tick: float) -> str:
    """Compact ruler label that keeps sub-second detail when zoomed in."""
    seconds = max(0.0, float(seconds))

    if major_tick < 1.0:
        decimals = 2 if major_tick < 0.1 else 1
        if seconds < 60.0:
            return f"{seconds:.{decimals}f}s"
        whole_minutes = int(seconds // 60)
        sec_part = seconds - whole_minutes * 60
        return f"{whole_minutes:02d}:{sec_part:0{3 + decimals}.{decimals}f}"

    total = int(round(seconds))
    h = total // 3600
    m = (total % 3600) // 60
    s = total % 60
    if h:
        return f"{h:02d}:{m:02d}:{s:02d}"
    if m:
        return f"{m:02d}:{s:02d}"
    return f"{s}s"


def timeline_fit_pixels_per_second(visible_width: float, duration: float) -> float:
    """Return a timeline zoom value that can fit the full project duration.

    This uses the same global min/max zoom clamp as normal timeline zooming, so
    Fit Timeline and the Zoom - button agree on the longest timeline the view
    can show.
    """
    safe_duration = max(1.0, safe_float(duration, 1.0))
    safe_width = max(1.0, safe_float(visible_width, 1.0))
    return clamp(safe_width / safe_duration, MIN_PPS, MAX_PPS)


def detect_media_type(path: Path) -> str:
    ext = path.suffix.lower()
    if path.name.lower() == TEXT_ASSET_JSON_NAME:
        return TEXT_MEDIA_TYPE
    if ext in VIDEO_EXTS:
        return "video"
    if ext in AUDIO_EXTS:
        return "audio"
    if ext in IMAGE_EXTS:
        return "image"
    return "unknown"


def default_duration_for_media_type(media_type: str) -> float:
    media_type = str(media_type or "").lower()
    if media_type == "image":
        return DEFAULT_IMAGE_DURATION
    if media_type == TEXT_MEDIA_TYPE:
        return DEFAULT_IMAGE_DURATION
    return DEFAULT_UNKNOWN_DURATION


def probe_duration(path: Path, media_type: Optional[str] = None) -> Tuple[float, bool, str]:
    """Return duration, detected flag, and note. Never raises."""
    media_type = media_type or detect_media_type(path)
    if media_type == "image":
        return DEFAULT_IMAGE_DURATION, False, "image default duration"

    probe = ffprobe_path()
    if probe is None:
        return default_duration_for_media_type(media_type), False, "ffprobe not found; fallback duration used"

    try:
        result = subprocess.run(
            [
                str(probe),
                "-v",
                "error",
                "-show_entries",
                "format=duration",
                "-of",
                "default=noprint_wrappers=1:nokey=1",
                str(path),
            ],
            capture_output=True,
            text=True,
            timeout=20,
            check=False,
        )
        raw = (result.stdout or "").strip().splitlines()[0].strip()
        duration = float(raw)
        if math.isfinite(duration) and duration > 0.0:
            return duration, True, "duration detected with ffprobe"
    except Exception as exc:
        return default_duration_for_media_type(media_type), False, f"ffprobe failed; fallback duration used: {exc}"

    return default_duration_for_media_type(media_type), False, "ffprobe returned no usable duration; fallback duration used"



def probe_media_size(path: Path) -> Tuple[int, int, bool, str]:
    """Return media width/height when ffprobe can detect it. Never raises."""
    if not path or not Path(path).exists():
        return 0, 0, False, "source file not found"
    probe = ffprobe_path()
    if probe is None:
        return 0, 0, False, "ffprobe not found"
    try:
        result = subprocess.run(
            [
                str(probe),
                "-v",
                "error",
                "-select_streams",
                "v:0",
                "-show_entries",
                "stream=width,height",
                "-of",
                "csv=p=0:s=x",
                str(path),
            ],
            capture_output=True,
            text=True,
            timeout=20,
            check=False,
        )
        raw = (result.stdout or "").strip().splitlines()[0].strip()
        if "x" in raw:
            left, right = raw.lower().split("x", 1)
            width = int(float(left.strip()))
            height = int(float(right.strip()))
            if width > 0 and height > 0:
                return width, height, True, "video size detected with ffprobe"
    except Exception as exc:
        return 0, 0, False, f"ffprobe size failed: {exc}"
    return 0, 0, False, "ffprobe returned no usable video size"

def track_label(track: int) -> str:
    """Legacy fallback label used by old project data and tests."""
    track = int(clamp(track, 0, len(DEFAULT_TRACK_DEFS) - 1))
    return DEFAULT_TRACK_DEFS[track]["label"]


def default_track_for_media_type(media_type: str) -> int:
    """Legacy fallback index used by old project data and tests."""
    if media_type == "audio":
        return 2
    return 1


def color_for_media_type(media_type: str, index: int = 0) -> str:
    media_type = str(media_type or "").lower()
    if media_type == "audio":
        return "#9b59b6"
    if media_type == "image":
        return "#20bf6b"
    if media_type == TEXT_MEDIA_TYPE:
        return "#f7b731"
    if media_type == "video":
        palette = ["#3867d6", "#2d98da", "#eb3b5a", "#fa8231", "#26de81"]
        return palette[index % len(palette)]
    return "#697083"


@dataclass
class TimelineMath:
    """Single source of truth for timeline pixel/time conversion."""

    pixels_per_second: float = DEFAULT_PPS
    scroll_x: float = 0.0

    def time_to_x(self, time_seconds: float) -> float:
        return float(time_seconds) * self.pixels_per_second - self.scroll_x

    def x_to_time(self, x: float) -> float:
        return (float(x) + self.scroll_x) / self.pixels_per_second

    def zoom_around_x(
        self,
        anchor_x: float,
        new_pixels_per_second: float,
        max_scroll_x: Optional[float] = None,
    ) -> float:
        """Change zoom while keeping the time under anchor_x visually stable."""
        old_anchor_time = self.x_to_time(anchor_x)
        self.pixels_per_second = clamp(
            float(new_pixels_per_second), MIN_PPS, MAX_PPS
        )
        self.scroll_x = old_anchor_time * self.pixels_per_second - float(anchor_x)
        if max_scroll_x is not None:
            self.scroll_x = clamp(self.scroll_x, 0.0, max_scroll_x)
        return old_anchor_time

    def zoom_around_time(
        self,
        target_time: float,
        anchor_x: float,
        new_pixels_per_second: float,
        max_scroll_x: Optional[float] = None,
    ) -> None:
        """Change zoom while keeping target_time at anchor_x."""
        self.pixels_per_second = clamp(
            float(new_pixels_per_second), MIN_PPS, MAX_PPS
        )
        self.scroll_x = float(target_time) * self.pixels_per_second - float(anchor_x)
        if max_scroll_x is not None:
            self.scroll_x = clamp(self.scroll_x, 0.0, max_scroll_x)


def safe_float(value: Any, default: float = 0.0) -> float:
    try:
        result = float(value)
        if math.isfinite(result):
            return result
    except Exception:
        pass
    return float(default)


def safe_int(value: Any, default: int = 0) -> int:
    try:
        return int(float(value))
    except Exception:
        return int(default)


def project_path_missing(path_value: Any) -> bool:
    raw = str(path_value or "").strip()
    if not raw:
        return False
    try:
        return not Path(raw).exists()
    except Exception:
        return True


def normalized_project_path_key(path_value: Any) -> str:
    raw = str(path_value or "").strip()
    if not raw:
        return ""
    try:
        return os.path.normcase(os.path.abspath(raw))
    except Exception:
        return raw.lower()


def make_unique_loaded_id(raw_id: Any, used_ids: set[str], prefix: str) -> str:
    base = str(raw_id or "").strip()
    if base and base not in used_ids:
        return base
    while True:
        candidate = f"{prefix}_{uuid.uuid4().hex[:10]}"
        if candidate not in used_ids:
            return candidate


@dataclass
class MediaItem:
    path: str
    name: str
    media_type: str
    duration: float
    detected_duration: bool = False
    media_id: str = field(default_factory=lambda: uuid.uuid4().hex[:12])
    missing: bool = False
    # Media Bin polish metadata. These are editor-only fields:
    # display_name never renames the real source file, and favorite only affects Media Bin ordering.
    display_name: str = ""
    favorite: bool = False

    def to_dict(self) -> Dict[str, Any]:
        data = asdict(self)
        data["display_name"] = str(getattr(self, "display_name", "") or "")
        data["favorite"] = bool(getattr(self, "favorite", False))
        return data

    @staticmethod
    def from_path(path: Path) -> "MediaItem":
        media_type = detect_media_type(path)
        duration, detected, _note = probe_duration(path, media_type)
        return MediaItem(
            path=str(path),
            name=path.name,
            media_type=media_type,
            duration=max(0.05, float(duration)),
            detected_duration=bool(detected),
        )

    @staticmethod
    def from_dict(data: Dict[str, Any]) -> "MediaItem":
        data = data if isinstance(data, dict) else {}
        path = str(data.get("path") or data.get("file_path") or "")
        name = str(data.get("name") or data.get("display_name") or Path(path).name or "Media")
        media_type = str(data.get("media_type") or data.get("type") or detect_media_type(Path(path)))
        return MediaItem(
            path=path,
            name=name,
            media_type=media_type,
            duration=max(MIN_CLIP_DURATION, safe_float(data.get("duration"), default_duration_for_media_type(media_type))),
            detected_duration=bool_from_project_value(data.get("detected_duration", data.get("duration_detected", False)), False),
            media_id=str(data.get("media_id") or data.get("id") or uuid.uuid4().hex[:12]),
            missing=bool_from_project_value(data.get("missing", False), False),
            display_name=str(data.get("display_name") or data.get("editor_name") or ""),
            favorite=bool_from_project_value(data.get("favorite", data.get("is_favorite", False)), False),
        )


def media_item_display_name(item: Optional[MediaItem]) -> str:
    if item is None:
        return ""
    display = str(getattr(item, "display_name", "") or "").strip()
    if display:
        return display
    name = str(getattr(item, "name", "") or "").strip()
    if name:
        return name
    path = str(getattr(item, "path", "") or "").strip()
    return Path(path).name if path else "Media"


def media_item_original_name(item: Optional[MediaItem]) -> str:
    if item is None:
        return ""
    name = str(getattr(item, "name", "") or "").strip()
    if name:
        return name
    path = str(getattr(item, "path", "") or "").strip()
    return Path(path).name if path else "Media"


def media_item_set_display_name(item: Optional[MediaItem], value: Any) -> bool:
    if item is None:
        return False
    new_name = str(value or "").strip()
    old_name = str(getattr(item, "display_name", "") or "").strip()
    # Empty rename clears the editor-only override and falls back to the source filename.
    if new_name == media_item_original_name(item):
        new_name = ""
    if new_name == old_name:
        return False
    item.display_name = new_name
    return True


def media_item_is_favorite(item: Optional[MediaItem]) -> bool:
    return bool(item is not None and bool(getattr(item, "favorite", False)))


def media_item_set_favorite(item: Optional[MediaItem], favorite: Any) -> bool:
    if item is None:
        return False
    new_value = bool(favorite)
    if bool(getattr(item, "favorite", False)) == new_value:
        return False
    item.favorite = new_value
    return True


def media_type_label(value: Any) -> str:
    media_type = str(value or "").strip().lower()
    if media_type == TEXT_MEDIA_TYPE:
        return "Text"
    if media_type == "audio":
        return "Audio"
    if media_type == "video":
        return "Video"
    if media_type == "image":
        return "Image"
    return media_type.title() if media_type else "Unknown"


def media_type_dot_color(value: Any) -> str:
    media_type = str(value or "").strip().lower()
    if media_type == "video":
        return "#2d98da"  # blue
    if media_type == "audio":
        return "#20bf6b"  # green
    if media_type == TEXT_MEDIA_TYPE:
        return "#f7b731"  # yellow
    if media_type == "image":
        return "#fa8231"  # orange
    return "#8b93a7"


def media_bin_sort_value(item: MediaItem, column_key: str = "name") -> Any:
    key = str(column_key or "name").strip().lower()
    if key in {"favorite", "star"}:
        return 0 if media_item_is_favorite(item) else 1
    if key in {"dot", "indicator", "media_type", "type"}:
        return (media_type_label(getattr(item, "media_type", "")).lower(), media_item_display_name(item).lower())
    if key in {"duration", "time"}:
        return (max(0.0, safe_float(getattr(item, "duration", 0.0), 0.0)), media_item_display_name(item).lower())
    if key in {"path", "folder"}:
        return (str(getattr(item, "path", "") or "").lower(), media_item_display_name(item).lower())
    return media_item_display_name(item).lower()


def media_bin_sorted_items(media_items: Iterable[MediaItem], column_key: str = "name", reverse: bool = False) -> List[MediaItem]:
    items = [item for item in list(media_items or []) if isinstance(item, MediaItem)]
    favorites = [item for item in items if media_item_is_favorite(item)]
    normal = [item for item in items if not media_item_is_favorite(item)]
    favorites.sort(key=lambda item: media_bin_sort_value(item, column_key), reverse=bool(reverse))
    normal.sort(key=lambda item: media_bin_sort_value(item, column_key), reverse=bool(reverse))
    return favorites + normal


def bool_from_project_value(value: Any, default: bool = False) -> bool:
    """Parse project JSON booleans while keeping older loose values compatible."""
    if value is None:
        return bool(default)
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    raw = str(value).strip().lower()
    if raw in {"1", "true", "yes", "on", "visible", "enabled", "solo", "muted", "locked"}:
        return True
    if raw in {"0", "false", "no", "off", "hidden", "disabled", "unmuted", "unlocked"}:
        return False
    return bool(default)


@dataclass
class TimelineTrack:
    track_id: str
    label: str
    visible: bool = True
    muted: bool = False
    solo: bool = False
    locked: bool = False
    track_volume: float = DEFAULT_TRACK_VOLUME

    def to_dict(self) -> Dict[str, Any]:
        return {
            "id": self.track_id,
            "label": self.label,
            "visible": bool(self.visible),
            "muted": bool(self.muted),
            "solo": bool(self.solo),
            "locked": bool(self.locked),
            "track_volume": track_volume_percent_value(self),
        }

    @staticmethod
    def from_dict(data: Dict[str, Any], fallback_index: int = 0, existing_ids: Optional[set[str]] = None) -> "TimelineTrack":
        data = data if isinstance(data, dict) else {}
        existing_ids = existing_ids or set()
        label = str(data.get("label") or data.get("name") or f"Track {fallback_index + 1}")
        raw_id = str(data.get("track_id") or data.get("id") or "").strip()
        track_id = raw_id if raw_id and raw_id not in existing_ids else make_track_id(label, existing_ids)
        visible = bool_from_project_value(data.get("visible", data.get("is_visible", True)), True)
        muted = bool_from_project_value(data.get("muted", data.get("mute", False)), False)
        solo = bool_from_project_value(data.get("solo", False), False)
        locked = bool_from_project_value(data.get("locked", data.get("lock", False)), False)
        track_volume = clamp_audio_volume_percent(data.get("track_volume", data.get("volume", data.get("volume_percent", DEFAULT_TRACK_VOLUME))), DEFAULT_TRACK_VOLUME)
        return TimelineTrack(track_id=track_id, label=label, visible=visible, muted=muted, solo=solo, locked=locked, track_volume=track_volume)


def default_tracks() -> List[TimelineTrack]:
    tracks: List[TimelineTrack] = []
    used: set[str] = set()
    for i, item in enumerate(DEFAULT_TRACK_DEFS):
        track = TimelineTrack.from_dict(item, i, used)
        used.add(track.track_id)
        tracks.append(track)
    return tracks



def clamp_clip_speed(value: Any, default: float = 1.0) -> float:
    """Clamp clip speed to the safe editor range."""
    try:
        speed = float(value)
    except Exception:
        speed = float(default)
    if not math.isfinite(speed):
        speed = float(default)
    return float(clamp(speed, MIN_CLIP_SPEED, MAX_CLIP_SPEED))


def clip_media_type(clip_or_media_type: Any) -> str:
    """Return a normalized media type from a clip, media item, or raw string."""
    if isinstance(clip_or_media_type, str):
        value = clip_or_media_type
    else:
        value = getattr(clip_or_media_type, "media_type", "")
    return str(value or "").strip().lower()


def clip_is_visual(clip_or_media_type: Any) -> bool:
    """Visual transform controls apply to video and image clips only."""
    return clip_media_type(clip_or_media_type) in {"video", "image"}


def clip_mirror_x_value(clip_or_data: Any) -> bool:
    """Return the stored horizontal mirror flag for visual clips only."""
    if clip_or_data is None:
        return False
    if isinstance(clip_or_data, dict):
        media_type = clip_media_type(clip_or_data.get("media_type", clip_or_data.get("type", "")))
        if media_type not in {"video", "image"}:
            return False
        return bool_from_project_value(clip_or_data.get("mirror_x", clip_or_data.get("flip_x", False)), False)
    if not clip_is_visual(clip_or_data):
        return False
    return bool_from_project_value(getattr(clip_or_data, "mirror_x", False), False)


def clip_mirror_y_value(clip_or_data: Any) -> bool:
    """Return the stored vertical mirror flag for visual clips only."""
    if clip_or_data is None:
        return False
    if isinstance(clip_or_data, dict):
        media_type = clip_media_type(clip_or_data.get("media_type", clip_or_data.get("type", "")))
        if media_type not in {"video", "image"}:
            return False
        return bool_from_project_value(clip_or_data.get("mirror_y", clip_or_data.get("flip_y", False)), False)
    if not clip_is_visual(clip_or_data):
        return False
    return bool_from_project_value(getattr(clip_or_data, "mirror_y", False), False)


def clip_mirror_state(clip_or_data: Any) -> Dict[str, bool]:
    return {"mirror_x": clip_mirror_x_value(clip_or_data), "mirror_y": clip_mirror_y_value(clip_or_data)}


def clip_has_mirror(clip_or_data: Any) -> bool:
    state = clip_mirror_state(clip_or_data)
    return bool(state.get("mirror_x", False) or state.get("mirror_y", False))


def set_clip_mirror_state(clip: Optional["Clip"], mirror_x: Any = None, mirror_y: Any = None) -> bool:
    """Set visual mirror flags without touching transform fields."""
    if clip is None or not clip_is_visual(clip):
        return False
    old_x = clip_mirror_x_value(clip)
    old_y = clip_mirror_y_value(clip)
    new_x = old_x if mirror_x is None else bool_from_project_value(mirror_x, old_x)
    new_y = old_y if mirror_y is None else bool_from_project_value(mirror_y, old_y)
    clip.mirror_x = bool(new_x)
    clip.mirror_y = bool(new_y)
    return bool(old_x != new_x or old_y != new_y)


def clip_reverse_playback_value(clip_or_data: Any) -> bool:
    """Return the non-destructive reverse-playback flag for video clips only."""
    if clip_or_data is None:
        return False
    if isinstance(clip_or_data, dict):
        media_type = clip_media_type(clip_or_data.get("media_type", clip_or_data.get("type", "")))
        if media_type != "video":
            return False
        return bool_from_project_value(
            clip_or_data.get("reverse_playback", clip_or_data.get("play_backwards", clip_or_data.get("reverse", False))),
            False,
        )
    if clip_media_type(clip_or_data) != "video":
        return False
    return bool_from_project_value(getattr(clip_or_data, "reverse_playback", False), False)


def set_clip_reverse_playback_state(clip: Optional["Clip"], enabled: Any) -> bool:
    """Set video reverse playback without touching timeline duration or source media."""
    if clip is None or clip_media_type(clip) != "video":
        return False
    old_value = clip_reverse_playback_value(clip)
    new_value = bool_from_project_value(enabled, old_value)
    clip.reverse_playback = bool(new_value)
    return bool(old_value != new_value)


def clip_source_time_from_local_time(
    clip: Optional["Clip"],
    local_time: Any,
    *,
    avoid_exact_out: bool = False,
) -> Optional[float]:
    """Map local clip time to source time, including speed and video reverse playback.

    Timeline start/end and clip duration stay normal. Only the source-time lookup
    is reversed, which keeps old timeline math and trim behavior intact.
    """
    if clip is None:
        return None
    media_type = clip_media_type(clip)
    try:
        local = safe_float(local_time, 0.0)
    except Exception:
        local = 0.0
    clip_duration = max(0.0, safe_float(getattr(clip, "duration", 0.0), 0.0))
    local = clamp(local, 0.0, clip_duration)
    in_point = max(0.0, safe_float(getattr(clip, "in_point", 0.0), 0.0))
    if media_type == "image":
        return in_point
    speed = clip_speed_value(clip)
    source_end = max(in_point, safe_float(getattr(clip, "source_end", in_point + clip_duration * speed), in_point + clip_duration * speed))
    if clip_reverse_playback_value(clip):
        source_time = source_end - local * speed
        if avoid_exact_out and source_end > in_point and local <= 0.0005:
            source_time = source_end - 0.001
    else:
        source_time = in_point + local * speed
        if avoid_exact_out and source_end > in_point:
            source_time = min(source_time, max(in_point, source_end - 0.001))
    return float(clamp(source_time, in_point, source_end))


def timeline_export_reverse_filter_list_for_segment(segment: Dict[str, Any]) -> List[str]:
    """Return FFmpeg visual reverse filters for video segments only."""
    if not isinstance(segment, dict):
        return []
    if str(segment.get("type") or "").lower() != "video":
        return []
    if bool_from_project_value(segment.get("reverse_playback", segment.get("play_backwards", False)), False):
        return ["reverse"]
    return []


def reverse_live_preview_proxy_required_for_plan(plan: Optional[Dict[str, Any]]) -> bool:
    """Return whether live Qt preview should use a forward-playing reversed proxy.

    Qt's media player is forward-only for practical timeline playback. Reversed
    video clips therefore get a temporary non-destructive proxy so the player can
    still run from local proxy time 0 instead of seeking to the source out-point.
    """
    if not isinstance(plan, dict):
        return False
    if str(plan.get("media_type") or "").lower() != "video":
        return False
    return bool_from_project_value(plan.get("reverse_playback", False), False)


def reverse_live_preview_audio_proxy_required_for_source(source: Optional[Dict[str, Any]]) -> bool:
    """Return whether a preview audio source must use a reversed video proxy.

    This is preview-only routing: standalone audio clips are intentionally left
    alone. Only embedded audio from video clips with reverse_playback=True needs
    a proxy because QMediaPlayer cannot play the original source backwards.
    """
    if not isinstance(source, dict):
        return False
    if not bool_from_project_value(source.get("embedded_video_audio", False), False):
        return False
    if str(source.get("media_type") or "video").lower() != "video":
        return False
    return bool_from_project_value(source.get("reverse_playback", False), False)


def reverse_live_preview_proxy_audio_source_start(timeline_time: Any, proxy_timeline_start: Any) -> float:
    """Map timeline time to local proxy audio time for a warmed reverse proxy."""
    return max(0.0, safe_float(timeline_time, 0.0) - safe_float(proxy_timeline_start, 0.0))


def reverse_live_preview_proxy_source_range(plan: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    """Return the stable whole-clip source span for one reversed live-preview proxy.

    The proxy is only for live Qt playback. It must be cacheable for the whole
    timeline clip, so the range intentionally does not depend on the current
    playhead/source_start. That prevents scrub/tick paths from producing a new
    cache key for every playhead position inside the same reversed clip.
    """
    if not reverse_live_preview_proxy_required_for_plan(plan):
        return {"ok": False, "reason": "not reversed video"}
    assert isinstance(plan, dict)
    speed = clamp_clip_speed(plan.get("speed", 1.0), 1.0)
    play_duration = max(0.0, safe_float(plan.get("play_duration", plan.get("clip_duration", 0.0)), 0.0))
    if play_duration <= 0.0005:
        return {"ok": False, "reason": "empty duration"}
    source_in = max(0.0, safe_float(plan.get("in_point", 0.0), 0.0))
    fallback_out = source_in + play_duration * speed
    source_out = safe_float(plan.get("out_point", plan.get("source_out", fallback_out)), fallback_out)
    if not math.isfinite(source_out) or source_out <= source_in + 0.0005:
        source_out = fallback_out
    source_out = max(source_in + 0.001, source_out)
    requested_span = max(0.001, play_duration * speed)
    available_span = max(0.001, source_out - source_in)
    source_span = min(requested_span, available_span)
    input_start = max(source_in, source_out - source_span)
    return {
        "ok": True,
        "source_file": str(plan.get("source_path") or ""),
        "source_in": float(source_in),
        "source_out": float(source_out),
        "input_start": float(input_start),
        "source_span": float(source_span),
        "output_duration": float(play_duration),
        "speed": float(speed),
    }


def reverse_live_preview_proxy_cache_key(plan: Optional[Dict[str, Any]]) -> str:
    """Stable cache key for reversed live-preview proxies. GUI-free for tests."""
    info = reverse_live_preview_proxy_source_range(plan)
    if not bool(info.get("ok")):
        return ""
    source_file = str(info.get("source_file") or "")
    try:
        stat = Path(source_file).stat()
        size = int(stat.st_size)
        mtime_ns = int(getattr(stat, "st_mtime_ns", int(stat.st_mtime * 1_000_000_000)))
    except Exception:
        size = 0
        mtime_ns = 0
    parts = [
        "reverse_live_preview_v1",
        normalized_project_path_key(source_file),
        size,
        mtime_ns,
        f"{safe_float(info.get('source_in'), 0.0):.6f}",
        f"{safe_float(info.get('source_out'), 0.0):.6f}",
        f"{safe_float(info.get('input_start'), 0.0):.6f}",
        f"{safe_float(info.get('source_span'), 0.0):.6f}",
        f"{safe_float(info.get('output_duration'), 0.0):.6f}",
        f"{safe_float(info.get('speed'), 1.0):.8f}",
    ]
    return _timeline_cache_hash(parts)


def reverse_live_preview_proxy_path_for_plan(plan: Optional[Dict[str, Any]], app_root: Optional[Path] = None) -> Optional[Path]:
    key = reverse_live_preview_proxy_cache_key(plan)
    if not key:
        return None
    root = Path(app_root).resolve() if app_root is not None else framevision_root()
    return timeline_media_cache_dir(root) / "reverse_preview_proxy" / f"{key}.mp4"


def reverse_live_preview_proxy_cached_path_for_plan(plan: Optional[Dict[str, Any]], app_root: Optional[Path] = None) -> Optional[Path]:
    """Return an existing reversed proxy, or None. Never creates media."""
    proxy_path = reverse_live_preview_proxy_path_for_plan(plan, app_root)
    if proxy_path is None:
        return None
    try:
        if proxy_path.exists() and proxy_path.stat().st_size > 4096:
            return proxy_path
    except Exception:
        return None
    return None


def should_build_reverse_proxy_for_live_playback(
    plan: Optional[Dict[str, Any]],
    *,
    timeline_playback_active: Any = False,
    timeline_playback_paused: Any = False,
    preview_paused: Any = False,
    timeline_user_seeking: Any = False,
    preview_user_seeking: Any = False,
) -> bool:
    """True only when it is safe to start background reverse-proxy work.

    Scrubbing, paused/stopped preview, and selected/source preview must stay on
    the lightweight single-frame path and must never launch FFmpeg proxy builds.
    """
    if not reverse_live_preview_proxy_required_for_plan(plan):
        return False
    if not bool(timeline_playback_active):
        return False
    if bool(timeline_playback_paused) or bool(preview_paused):
        return False
    if bool(timeline_user_seeking) or bool(preview_user_seeking):
        return False
    return True


def reverse_live_preview_proxy_job_guard_allows(active_jobs: Any, key: Any, max_jobs: int = 1) -> bool:
    """Pure duplicate/saturation guard for reverse proxy background jobs."""
    clean_key = str(key or "").strip()
    if not clean_key:
        return False
    active = set(active_jobs or [])
    if clean_key in active:
        return False
    return len(active) < max(1, int(max_jobs or 1))


def reverse_live_preview_playback_decision(
    plan: Optional[Dict[str, Any]],
    *,
    cached_proxy_available: Any = False,
    timeline_mode: Any = True,
    proxy_build_allowed: Any = False,
) -> str:
    """Return how live preview should handle a reversed video plan.

    The important safety rule is that a reversed video clip with no cached proxy
    must never fall back to original-source playback from the reversed source
    end. That fallback makes Qt instantly run past the trim range and skip.
    """
    if not reverse_live_preview_proxy_required_for_plan(plan):
        return "normal_source"
    if bool(cached_proxy_available):
        return "cached_proxy"
    if bool(timeline_mode) and bool(proxy_build_allowed):
        return "pending_proxy"
    return "hold_static_frame"


def preview_prepare_state_default() -> Dict[str, Any]:
    """Runtime-only state for preview-readiness UI. GUI-free for self-tests."""
    return {
        "busy": False,
        "visible": False,
        "reason": "",
        "message": "",
        "failed": False,
        "failure_message": "",
        "runtime_only": True,
    }


def preview_prepare_begin_state(state: Optional[Dict[str, Any]], reason: Any, message: Any) -> Dict[str, Any]:
    data = preview_prepare_state_default()
    if isinstance(state, dict):
        data.update({k: state.get(k) for k in data.keys() if k in state})
    data.update({
        "busy": True,
        "reason": str(reason or "preview"),
        "message": str(message or "Preparing preview…"),
        "failed": False,
        "failure_message": "",
        "runtime_only": True,
    })
    return data


def preview_prepare_done_state(state: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    data = preview_prepare_state_default()
    if isinstance(state, dict):
        data.update({k: state.get(k) for k in data.keys() if k in state})
    data.update({
        "busy": False,
        "message": "Preview ready",
        "failed": False,
        "failure_message": "",
        "runtime_only": True,
    })
    return data


def preview_prepare_failed_state(state: Optional[Dict[str, Any]], message: Any) -> Dict[str, Any]:
    data = preview_prepare_state_default()
    if isinstance(state, dict):
        data.update({k: state.get(k) for k in data.keys() if k in state})
    msg = str(message or "Preview preparation failed")
    data.update({
        "busy": False,
        "message": msg,
        "failed": True,
        "failure_message": msg,
        "runtime_only": True,
    })
    return data


def preview_prepare_is_busy_state(state: Optional[Dict[str, Any]]) -> bool:
    return bool(isinstance(state, dict) and bool(state.get("busy")))


def preview_prepare_public_state(state: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    """Return only display-safe runtime fields; never project persistence data."""
    if not isinstance(state, dict):
        state = preview_prepare_state_default()
    return {
        "busy": bool(state.get("busy", False)),
        "visible": bool(state.get("visible", False)),
        "reason": str(state.get("reason", "") or ""),
        "message": str(state.get("message", "") or ""),
        "failed": bool(state.get("failed", False)),
        "runtime_only": True,
    }


def preview_prepare_state_is_runtime_only(state: Optional[Dict[str, Any]]) -> bool:
    public = preview_prepare_public_state(state)
    return bool(public.get("runtime_only", False)) and "project" not in public and "autosave" not in public


def reverse_proxy_pending_prepare_message(plan: Optional[Dict[str, Any]]) -> str:
    if reverse_live_preview_proxy_required_for_plan(plan):
        return "Preparing reverse preview…"
    return "Preparing preview…"


def build_reverse_live_preview_proxy_command(
    ffmpeg: Path,
    source_file: str,
    output_path: Path,
    input_start: Any,
    source_span: Any,
    output_duration: Any,
    speed: Any,
    *,
    include_audio: bool = True,
) -> List[str]:
    """Build the FFmpeg command for a temporary reversed preview proxy."""
    safe_speed = clamp_clip_speed(speed, 1.0)
    safe_input_start = max(0.0, safe_float(input_start, 0.0))
    safe_source_span = max(0.001, safe_float(source_span, 0.001))
    safe_output_duration = max(0.001, safe_float(output_duration, 0.001))
    vf = ",".join([
        "reverse",
        f"setpts=(PTS-STARTPTS)/{safe_speed:.8f}",
        f"trim=duration={safe_output_duration:.6f}",
        "setpts=PTS-STARTPTS",
        "format=yuv420p",
    ])
    command: List[str] = [
        str(ffmpeg), "-y", "-hide_banner", "-nostdin", "-loglevel", "error",
        "-ss", f"{safe_input_start:.6f}", "-t", f"{safe_source_span:.6f}", "-i", str(source_file),
        "-map", "0:v:0",
    ]
    if include_audio:
        af_parts = ["areverse"]
        af_parts.extend(_timeline_export_atempo_filters_for_speed(safe_speed))
        af_parts.extend([f"atrim=0:{safe_output_duration:.6f}", "asetpts=PTS-STARTPTS"])
        command.extend([
            "-map", "0:a:0",
            "-vf", vf,
            "-af", ",".join(af_parts),
            "-t", f"{safe_output_duration:.6f}",
            "-c:v", "libx264", "-preset", "ultrafast", "-crf", "23", "-pix_fmt", "yuv420p",
            "-c:a", "aac", "-b:a", "160k",
            "-movflags", "+faststart",
            str(output_path),
        ])
    else:
        command.extend([
            "-vf", vf,
            "-t", f"{safe_output_duration:.6f}",
            "-an",
            "-c:v", "libx264", "-preset", "ultrafast", "-crf", "23", "-pix_fmt", "yuv420p",
            "-movflags", "+faststart",
            str(output_path),
        ])
    return command


def timeline_export_mirror_filter_list(mirror_x: Any = False, mirror_y: Any = False) -> List[str]:
    """Return FFmpeg visual mirror filters in deterministic order."""
    filters: List[str] = []
    if bool_from_project_value(mirror_x, False):
        filters.append("hflip")
    if bool_from_project_value(mirror_y, False):
        filters.append("vflip")
    return filters


def timeline_export_mirror_filter_list_for_segment(segment: Dict[str, Any]) -> List[str]:
    if not isinstance(segment, dict):
        return []
    mirror_data = segment.get("mirror") if isinstance(segment.get("mirror"), dict) else {}
    return timeline_export_mirror_filter_list(
        segment.get("mirror_x", mirror_data.get("mirror_x", False)),
        segment.get("mirror_y", mirror_data.get("mirror_y", False)),
    )


def normalize_transform_fit_mode(value: Any) -> str:
    mode = str(value or "fit").strip().lower()
    return mode if mode in TRANSFORM_FIT_MODES else "fit"


def clamp_transform_scale(value: Any, default: float = 1.0) -> float:
    scale = safe_float(value, default)
    if not math.isfinite(scale):
        scale = default
    return float(clamp(scale, TRANSFORM_SCALE_MIN, TRANSFORM_SCALE_MAX))


def clamp_transform_opacity(value: Any, default: float = 1.0) -> float:
    opacity = safe_float(value, default)
    if not math.isfinite(opacity):
        opacity = default
    return float(clamp(opacity, TRANSFORM_OPACITY_MIN, TRANSFORM_OPACITY_MAX))


def normalize_transform_rotation(value: Any) -> float:
    rotation = safe_float(value, 0.0)
    if not math.isfinite(rotation):
        rotation = 0.0
    # Keep values predictable for dialogs/save/load while still allowing repeated rotation.
    return float(rotation % 360.0)


def default_visual_transform() -> Dict[str, Any]:
    return {
        "transform_x": 0.0,
        "transform_y": 0.0,
        "transform_scale": 1.0,
        "transform_rotation": 0.0,
        "transform_opacity": 1.0,
        "transform_fit_mode": "fit",
    }


def normalize_clip_visual_transform(clip: Optional["Clip"]) -> Dict[str, Any]:
    transform = default_visual_transform()
    if clip is None:
        return transform
    transform["transform_x"] = safe_float(getattr(clip, "transform_x", 0.0), 0.0)
    transform["transform_y"] = safe_float(getattr(clip, "transform_y", 0.0), 0.0)
    transform["transform_scale"] = clamp_transform_scale(getattr(clip, "transform_scale", 1.0), 1.0)
    transform["transform_rotation"] = normalize_transform_rotation(getattr(clip, "transform_rotation", 0.0))
    transform["transform_opacity"] = clamp_transform_opacity(getattr(clip, "transform_opacity", 1.0), 1.0)
    transform["transform_fit_mode"] = normalize_transform_fit_mode(getattr(clip, "transform_fit_mode", "fit"))
    return transform


def apply_visual_transform_to_clip(clip: Optional["Clip"], transform: Dict[str, Any]) -> bool:
    if clip is None or not clip_is_visual(clip):
        return False
    data = dict(default_visual_transform())
    if isinstance(transform, dict):
        data.update(transform)
    clip.transform_x = safe_float(data.get("transform_x", 0.0), 0.0)
    clip.transform_y = safe_float(data.get("transform_y", 0.0), 0.0)
    clip.transform_scale = clamp_transform_scale(data.get("transform_scale", 1.0), 1.0)
    clip.transform_rotation = normalize_transform_rotation(data.get("transform_rotation", 0.0))
    clip.transform_opacity = clamp_transform_opacity(data.get("transform_opacity", 1.0), 1.0)
    clip.transform_fit_mode = normalize_transform_fit_mode(data.get("transform_fit_mode", "fit"))
    return True



def visual_keyframes_supported_for_clip(clip: Optional["Clip"]) -> bool:
    """Visual transform keyframes are for normal media clips only."""
    if clip is None:
        return False
    return clip_media_type(clip) in {"video", "image"}


def normalize_visual_keyframe(item: Any, clip_duration: Any = None) -> Optional[Dict[str, Any]]:
    """Normalize one visual transform keyframe without requiring Qt."""
    if not isinstance(item, dict):
        return None
    t = safe_float(item.get("time", item.get("local_time", 0.0)), 0.0)
    if not math.isfinite(t):
        t = 0.0
    t = max(0.0, t)
    if clip_duration is not None:
        t = min(t, max(0.0, safe_float(clip_duration, t)))
    data = dict(default_visual_transform())
    data.update(item)
    return {
        "time": float(t),
        "transform_x": safe_float(data.get("transform_x", 0.0), 0.0),
        "transform_y": safe_float(data.get("transform_y", 0.0), 0.0),
        "transform_scale": clamp_transform_scale(data.get("transform_scale", 1.0), 1.0),
        "transform_rotation": normalize_transform_rotation(data.get("transform_rotation", 0.0)),
        "transform_opacity": clamp_transform_opacity(data.get("transform_opacity", 1.0), 1.0),
        "transform_fit_mode": normalize_transform_fit_mode(data.get("transform_fit_mode", "fit")),
    }


def normalize_visual_keyframes(items: Any, clip_duration: Any = None) -> List[Dict[str, Any]]:
    """Return sorted, de-duplicated local-time visual keyframes."""
    raw_items = items if isinstance(items, list) else []
    out: List[Dict[str, Any]] = []
    for item in raw_items:
        kf = normalize_visual_keyframe(item, clip_duration)
        if kf is None:
            continue
        # Keep the latest value for near-identical times to avoid duplicates.
        replaced = False
        for idx, existing in enumerate(out):
            if abs(float(existing.get("time", 0.0)) - float(kf.get("time", 0.0))) <= VISUAL_KEYFRAME_TOLERANCE_SECONDS:
                out[idx] = kf
                replaced = True
                break
        if not replaced:
            out.append(kf)
    out.sort(key=lambda k: float(k.get("time", 0.0)))
    return out


def visual_keyframes_for_clip(clip: Optional["Clip"]) -> List[Dict[str, Any]]:
    if clip is None or not visual_keyframes_supported_for_clip(clip):
        return []
    return normalize_visual_keyframes(getattr(clip, "visual_keyframes", []), getattr(clip, "duration", None))


def clip_has_visual_keyframes(clip: Optional["Clip"]) -> bool:
    return bool(visual_keyframes_for_clip(clip))


def visual_keyframe_count(clip: Optional["Clip"]) -> int:
    return len(visual_keyframes_for_clip(clip))


def visual_keyframe_times_for_clip(clip: Optional["Clip"]) -> List[float]:
    return [float(k.get("time", 0.0)) for k in visual_keyframes_for_clip(clip)]


def _interpolate_float_value(a: Any, b: Any, progress: float, default: float = 0.0) -> float:
    av = safe_float(a, default)
    bv = safe_float(b, default)
    return float(av + (bv - av) * clamp(progress, 0.0, 1.0))


def visual_transform_at_clip_time(clip: Optional["Clip"], local_time: Any) -> Dict[str, Any]:
    """Return the interpolated visual transform at local clip time.

    With no keyframes this intentionally returns the existing static transform,
    preserving old projects and all static transform behavior.
    """
    if clip is None or not visual_keyframes_supported_for_clip(clip):
        return normalize_clip_visual_transform(clip)
    keys = visual_keyframes_for_clip(clip)
    if not keys:
        return normalize_clip_visual_transform(clip)
    t = clamp(safe_float(local_time, 0.0), 0.0, max(0.0, safe_float(getattr(clip, "duration", 0.0), 0.0)))
    if len(keys) == 1:
        k = dict(keys[0])
        k.pop("time", None)
        return normalize_visual_keyframe({"time": t, **k}, getattr(clip, "duration", None)) or normalize_clip_visual_transform(clip)
    if t <= float(keys[0].get("time", 0.0)):
        k = dict(keys[0]); k.pop("time", None)
        return normalize_visual_keyframe({"time": t, **k}, getattr(clip, "duration", None)) or normalize_clip_visual_transform(clip)
    if t >= float(keys[-1].get("time", 0.0)):
        k = dict(keys[-1]); k.pop("time", None)
        return normalize_visual_keyframe({"time": t, **k}, getattr(clip, "duration", None)) or normalize_clip_visual_transform(clip)
    left = keys[0]
    right = keys[-1]
    for idx in range(len(keys) - 1):
        a = keys[idx]
        b = keys[idx + 1]
        if float(a.get("time", 0.0)) <= t <= float(b.get("time", 0.0)):
            left, right = a, b
            break
    start = float(left.get("time", 0.0))
    end = float(right.get("time", start))
    progress = 0.0 if end <= start + 1e-9 else clamp((t - start) / (end - start), 0.0, 1.0)
    fit_mode = str(left.get("transform_fit_mode", "fit") or "fit")
    if progress >= 0.999:
        fit_mode = str(right.get("transform_fit_mode", fit_mode) or fit_mode)
    return {
        "transform_x": _interpolate_float_value(left.get("transform_x", 0.0), right.get("transform_x", 0.0), progress, 0.0),
        "transform_y": _interpolate_float_value(left.get("transform_y", 0.0), right.get("transform_y", 0.0), progress, 0.0),
        "transform_scale": clamp_transform_scale(_interpolate_float_value(left.get("transform_scale", 1.0), right.get("transform_scale", 1.0), progress, 1.0), 1.0),
        "transform_rotation": normalize_transform_rotation(_interpolate_float_value(left.get("transform_rotation", 0.0), right.get("transform_rotation", 0.0), progress, 0.0)),
        "transform_opacity": clamp_transform_opacity(_interpolate_float_value(left.get("transform_opacity", 1.0), right.get("transform_opacity", 1.0), progress, 1.0), 1.0),
        "transform_fit_mode": normalize_transform_fit_mode(fit_mode),
    }


def visual_transform_at_timeline_time(clip: Optional["Clip"], timeline_time: Any) -> Dict[str, Any]:
    if clip is None:
        return default_visual_transform()
    local = clamp(safe_float(timeline_time, 0.0) - safe_float(getattr(clip, "start", 0.0), 0.0), 0.0, max(0.0, safe_float(getattr(clip, "duration", 0.0), 0.0)))
    return visual_transform_at_clip_time(clip, local)


def set_visual_keyframe_at_clip_time(clip: Optional["Clip"], local_time: Any, transform: Dict[str, Any]) -> bool:
    if clip is None or not visual_keyframes_supported_for_clip(clip):
        return False
    t = clamp(safe_float(local_time, 0.0), 0.0, max(0.0, safe_float(getattr(clip, "duration", 0.0), 0.0)))
    data = dict(default_visual_transform())
    if isinstance(transform, dict):
        data.update(transform)
    kf = normalize_visual_keyframe({"time": t, **data}, getattr(clip, "duration", None))
    if kf is None:
        return False
    keys = visual_keyframes_for_clip(clip)
    replaced = False
    for idx, existing in enumerate(keys):
        if abs(float(existing.get("time", 0.0)) - t) <= VISUAL_KEYFRAME_TOLERANCE_SECONDS:
            # Updating a nearby keyframe keeps the original time marker stable;
            # it changes the transform value, not the keyframe's timeline anchor.
            kf["time"] = float(existing.get("time", t))
            keys[idx] = kf
            replaced = True
            break
    if not replaced:
        keys.append(kf)
    keys.sort(key=lambda item: float(item.get("time", 0.0)))
    clip.visual_keyframes = keys
    return True


def remove_visual_keyframe_near_clip_time(clip: Optional["Clip"], local_time: Any, tolerance: float = VISUAL_KEYFRAME_TOLERANCE_SECONDS) -> bool:
    if clip is None or not visual_keyframes_supported_for_clip(clip):
        return False
    keys = visual_keyframes_for_clip(clip)
    if not keys:
        return False
    t = clamp(safe_float(local_time, 0.0), 0.0, max(0.0, safe_float(getattr(clip, "duration", 0.0), 0.0)))
    distances = [(abs(float(k.get("time", 0.0)) - t), idx) for idx, k in enumerate(keys)]
    distances.sort(key=lambda item: item[0])
    if not distances or distances[0][0] > max(0.0, safe_float(tolerance, VISUAL_KEYFRAME_TOLERANCE_SECONDS)):
        return False
    keys.pop(int(distances[0][1]))
    clip.visual_keyframes = keys
    return True


def clear_visual_keyframes_for_clip(clip: Optional["Clip"]) -> bool:
    if clip is None or not visual_keyframes_supported_for_clip(clip):
        return False
    if not visual_keyframes_for_clip(clip):
        return False
    clip.visual_keyframes = []
    # After removing keyframes, the clip falls back to static/base transform.
    # Keep that base anchored to true default so a cleared clip returns on-screen
    # instead of staying at the last keyframed preview position.
    apply_visual_transform_to_clip(clip, default_visual_transform())
    return True

def clip_has_default_visual_transform(clip: Optional["Clip"]) -> bool:
    """Return True when a visual clip is still using the default saved transform."""
    if clip is None or not clip_is_visual(clip):
        return True
    transform = normalize_clip_visual_transform(clip)
    default = default_visual_transform()
    return (
        abs(float(transform["transform_x"]) - float(default["transform_x"])) <= 1e-6
        and abs(float(transform["transform_y"]) - float(default["transform_y"])) <= 1e-6
        and abs(float(transform["transform_scale"]) - float(default["transform_scale"])) <= 1e-6
        and abs(float(transform["transform_rotation"]) - float(default["transform_rotation"])) <= 1e-6
        and abs(float(transform["transform_opacity"]) - float(default["transform_opacity"])) <= 1e-6
        and str(transform["transform_fit_mode"]) == str(default["transform_fit_mode"])
    )


def clip_has_non_default_visual_transform(clip: Optional["Clip"]) -> bool:
    return clip is not None and clip_is_visual(clip) and not clip_has_default_visual_transform(clip)


def clip_visual_transform_marker(clip: Optional["Clip"]) -> str:
    """Compact marker for timeline labels; derived from fields, never stored."""
    if clip_has_visual_keyframes(clip):
        return "K"
    return "T" if clip_has_non_default_visual_transform(clip) else ""


def visual_transform_summary(clip: Optional["Clip"]) -> str:
    transform = normalize_clip_visual_transform(clip)
    return (
        f"x {float(transform['transform_x']):.1f}, y {float(transform['transform_y']):.1f}, "
        f"scale {float(transform['transform_scale']):.3g}, rot {float(transform['transform_rotation']):.1f}°, "
        f"opacity {float(transform['transform_opacity']):.2f}, mode {transform['transform_fit_mode']}"
    )


def visual_transform_readout_text(clip: Optional["Clip"], timeline_time: Any = None, local_time: Any = None) -> str:
    """Compact UI readout for the transform currently visible in the preview pane."""
    if clip is None or not clip_is_visual(clip):
        return "Transform: no visual clip"
    if local_time is not None:
        transform = visual_transform_at_clip_time(clip, local_time)
    elif timeline_time is not None:
        transform = visual_transform_at_timeline_time(clip, timeline_time)
    else:
        transform = normalize_clip_visual_transform(clip)
    return (
        f"X {safe_float(transform.get('transform_x', 0.0), 0.0):.1f}  "
        f"Y {safe_float(transform.get('transform_y', 0.0), 0.0):.1f}  "
        f"S {clamp_transform_scale(transform.get('transform_scale', 1.0), 1.0):.3g}  "
        f"R {normalize_transform_rotation(transform.get('transform_rotation', 0.0)):.1f}°  "
        f"O {clamp_transform_opacity(transform.get('transform_opacity', 1.0), 1.0):.2f}"
    )


def set_default_visual_keyframe_at_clip_time(clip: Optional["Clip"], local_time: Any) -> bool:
    """Store a true default/original transform keyframe at local clip time."""
    return set_visual_keyframe_at_clip_time(clip, local_time, default_visual_transform())


def make_media_only_clip_payload(clip: "Clip") -> Dict[str, Any]:
    data = timeline_copy_clip_payload(clip)
    defaults = default_visual_transform()
    for field_name, value in defaults.items():
        data[field_name] = value
    data["mirror_x"] = False
    data["mirror_y"] = False
    data["reverse_playback"] = False
    data["audio_enabled"] = default_clip_audio_enabled(data.get("media_type", "video"))
    if clip_media_type(data.get("media_type", "")) == "image":
        data["audio_enabled"] = False
    data["clip_volume"] = DEFAULT_CLIP_VOLUME
    data["fade_in_duration"] = 0.0
    data["fade_out_duration"] = 0.0
    data["video_fade_in_duration"] = 0.0
    data["video_fade_out_duration"] = 0.0
    data["audio_keyframes"] = []
    data["detached_audio_clip_id"] = ""
    data["source_video_clip_id"] = ""
    return data


def make_effects_only_payload(clip: "Clip") -> Dict[str, Any]:
    mirror = clip_mirror_state(clip)
    return {
        "type": "effects_only",
        "visual_transform": normalize_clip_visual_transform(clip),
        "mirror": mirror,
        "mirror_x": bool(mirror.get("mirror_x", False)),
        "mirror_y": bool(mirror.get("mirror_y", False)),
        "source_clip_id": str(getattr(clip, "clip_id", "") or ""),
        "source_clip_name": str(getattr(clip, "name", "") or "Clip"),
    }


def paste_visual_effects_to_clip(clip: Optional["Clip"], payload: Dict[str, Any]) -> bool:
    if clip is None or not clip_is_visual(clip):
        return False
    transform = payload.get("visual_transform") if isinstance(payload, dict) else None
    if not isinstance(transform, dict):
        transform = {key: payload.get(key) for key in TRANSFORM_FIELDS} if isinstance(payload, dict) else {}
    changed_transform = apply_visual_transform_to_clip(clip, transform)
    mirror_payload = payload.get("mirror") if isinstance(payload, dict) else None
    if not isinstance(mirror_payload, dict):
        mirror_payload = payload if isinstance(payload, dict) else {}
    changed_mirror = set_clip_mirror_state(
        clip,
        mirror_payload.get("mirror_x", False),
        mirror_payload.get("mirror_y", False),
    )
    return bool(changed_transform or changed_mirror)


def visual_effects_state_for_clip(clip: Optional["Clip"]) -> Dict[str, Any]:
    return {"visual_transform": normalize_clip_visual_transform(clip), "mirror": clip_mirror_state(clip)}


def paste_visual_effects_to_clips(project: "TimelineProject", clips: List["Clip"], payload: Dict[str, Any]) -> Dict[str, Any]:
    """Apply a visual-effects clipboard payload to compatible unlocked visual clips.

    This is GUI-free so tests can prove that effects paste is conservative: it
    skips audio-only clips, skips locked tracks, and never touches media/timing.
    """
    result: Dict[str, Any] = {
        "changed": 0,
        "skipped_audio": 0,
        "skipped_locked": 0,
        "skipped_invalid": 0,
        "changed_clip_ids": [],
    }
    if not isinstance(payload, dict) or str(payload.get("type") or "") != "effects_only":
        result["invalid_clipboard"] = True
        return result
    seen: set[str] = set()
    for clip in clips or []:
        if clip is None:
            result["skipped_invalid"] += 1
            continue
        clip_id = str(getattr(clip, "clip_id", "") or "")
        if clip_id and clip_id in seen:
            continue
        if clip_id:
            seen.add(clip_id)
        if not clip_is_visual(clip):
            result["skipped_audio"] += 1
            continue
        can_edit, _message = project.can_edit_clip(clip_id) if project is not None else (True, "")
        if not can_edit:
            result["skipped_locked"] += 1
            continue
        before = visual_effects_state_for_clip(clip)
        if paste_visual_effects_to_clip(clip, payload):
            after = visual_effects_state_for_clip(clip)
            if after != before:
                result["changed"] += 1
                result["changed_clip_ids"].append(clip_id)
    return result


def apply_visual_transform_to_clips(project: "TimelineProject", clips: List["Clip"], transform: Dict[str, Any]) -> Dict[str, Any]:
    """Apply the same visual transform to selected compatible clips, GUI-free."""
    result: Dict[str, Any] = {
        "changed": 0,
        "skipped_audio": 0,
        "skipped_locked": 0,
        "skipped_invalid": 0,
        "changed_clip_ids": [],
    }
    seen: set[str] = set()
    for clip in clips or []:
        if clip is None:
            result["skipped_invalid"] += 1
            continue
        clip_id = str(getattr(clip, "clip_id", "") or "")
        if clip_id and clip_id in seen:
            continue
        if clip_id:
            seen.add(clip_id)
        if not clip_is_visual(clip):
            result["skipped_audio"] += 1
            continue
        can_edit, _message = project.can_edit_clip(clip_id) if project is not None else (True, "")
        if not can_edit:
            result["skipped_locked"] += 1
            continue
        before = normalize_clip_visual_transform(clip)
        if apply_visual_transform_to_clip(clip, transform):
            after = normalize_clip_visual_transform(clip)
            if after != before:
                result["changed"] += 1
                result["changed_clip_ids"].append(clip_id)
    return result


def visual_effects_payload_contains_media_or_timing(payload: Dict[str, Any]) -> bool:
    forbidden = {
        "media_id", "file_path", "media_type", "start", "duration", "in_point", "out_point",
        "speed", "clip_volume", "fade_in_duration", "fade_out_duration",
        "video_fade_in_duration", "video_fade_out_duration", "audio_keyframes",
        "detached_audio_clip_id", "source_video_clip_id", "track", "track_id",
    }
    return any(key in payload for key in forbidden) if isinstance(payload, dict) else False


def transformed_preview_data_for_clip(clip: Optional["Clip"], timeline_time: Any = None, local_time: Any = None) -> Dict[str, Any]:
    """GUI-free data used by preview drawing/tests. Does not touch timeline timing."""
    if local_time is not None:
        transform = visual_transform_at_clip_time(clip, local_time)
    elif timeline_time is not None:
        transform = visual_transform_at_timeline_time(clip, timeline_time)
    else:
        transform = normalize_clip_visual_transform(clip)
    return {
        "is_visual": clip_is_visual(clip),
        "transform": transform,
        "mirror": clip_mirror_state(clip),
        "keyframes": visual_keyframe_count(clip),
        "video_fade_in_duration": clip_video_fade_in_duration_value(clip),
        "video_fade_out_duration": clip_video_fade_out_duration_value(clip),
    }


def clip_supports_speed(clip_or_media_type: Any) -> bool:
    """Speed changes are intentionally video-only for stable audio playback."""
    return clip_media_type(clip_or_media_type) == "video"


def clip_speed_value(clip: Optional["Clip"]) -> float:
    if clip is None or not clip_supports_speed(clip):
        return 1.0
    return clamp_clip_speed(getattr(clip, "speed", 1.0), 1.0)


def clamp_audio_volume_percent(value: Any, default: float = DEFAULT_CLIP_VOLUME) -> float:
    """Clamp clip/track volume to the editor's safe percent range."""
    try:
        volume = float(value)
    except Exception:
        volume = float(default)
    if not math.isfinite(volume):
        volume = float(default)
    return float(clamp(volume, MIN_AUDIO_VOLUME, MAX_AUDIO_VOLUME))


def default_clip_audio_enabled(media_type: Any) -> bool:
    """Images are visual-only. Video/audio clips can provide audio by default."""
    kind = clip_media_type(media_type)
    return bool(kind in {"video", "audio"})


def clip_audio_enabled_value(clip: Optional["Clip"]) -> bool:
    if clip is None:
        return False
    kind = clip_media_type(clip)
    if kind == "image":
        return False
    if kind not in {"video", "audio"}:
        return False
    return bool(getattr(clip, "audio_enabled", default_clip_audio_enabled(kind)))


def clip_volume_percent_value(clip: Optional["Clip"]) -> float:
    if clip is None or clip_media_type(clip) == "image":
        return DEFAULT_CLIP_VOLUME
    return clamp_audio_volume_percent(getattr(clip, "clip_volume", DEFAULT_CLIP_VOLUME), DEFAULT_CLIP_VOLUME)


def track_volume_percent_value(track: Optional["TimelineTrack"]) -> float:
    if track is None:
        return DEFAULT_TRACK_VOLUME
    return clamp_audio_volume_percent(getattr(track, "track_volume", DEFAULT_TRACK_VOLUME), DEFAULT_TRACK_VOLUME)


def clip_can_have_audio_fades(clip: Optional["Clip"]) -> bool:
    return clip_media_type(clip) in {"video", "audio"}


def clamp_clip_fade_duration(clip: Optional["Clip"], value: Any) -> float:
    """Clamp a simple fade to half the visible timeline duration."""
    if clip is None or not clip_can_have_audio_fades(clip):
        return 0.0
    try:
        duration = max(MIN_CLIP_DURATION, float(getattr(clip, "duration", MIN_CLIP_DURATION) or MIN_CLIP_DURATION))
    except Exception:
        duration = MIN_CLIP_DURATION
    try:
        fade = float(value)
    except Exception:
        fade = 0.0
    if not math.isfinite(fade):
        fade = 0.0
    return float(clamp(fade, 0.0, max(0.0, duration / 2.0)))


def clip_fade_in_duration_value(clip: Optional["Clip"]) -> float:
    if clip is None or not clip_can_have_audio_fades(clip):
        return 0.0
    return clamp_clip_fade_duration(clip, getattr(clip, "fade_in_duration", 0.0))


def clip_fade_out_duration_value(clip: Optional["Clip"]) -> float:
    if clip is None or not clip_can_have_audio_fades(clip):
        return 0.0
    return clamp_clip_fade_duration(clip, getattr(clip, "fade_out_duration", 0.0))


def clip_can_have_video_fades(clip: Optional["Clip"]) -> bool:
    return clip_is_visual(clip)


def clamp_clip_video_fade_duration(clip: Optional["Clip"], value: Any) -> float:
    """Clamp a visual fade to half the visible timeline duration."""
    if clip is None or not clip_can_have_video_fades(clip):
        return 0.0
    try:
        duration = max(MIN_CLIP_DURATION, float(getattr(clip, "duration", MIN_CLIP_DURATION) or MIN_CLIP_DURATION))
    except Exception:
        duration = MIN_CLIP_DURATION
    try:
        fade = float(value)
    except Exception:
        fade = 0.0
    if not math.isfinite(fade):
        fade = 0.0
    return float(clamp(fade, 0.0, max(0.0, duration / 2.0)))


def clip_video_fade_in_duration_value(clip: Optional["Clip"]) -> float:
    if clip is None or not clip_can_have_video_fades(clip):
        return 0.0
    return clamp_clip_video_fade_duration(clip, getattr(clip, "video_fade_in_duration", 0.0))


def clip_video_fade_out_duration_value(clip: Optional["Clip"]) -> float:
    if clip is None or not clip_can_have_video_fades(clip):
        return 0.0
    return clamp_clip_video_fade_duration(clip, getattr(clip, "video_fade_out_duration", 0.0))


def video_fade_multiplier_for_clip(clip: Optional["Clip"], timeline_time: Any) -> float:
    """Linear visual fade multiplier at timeline_time, separate from audio fades."""
    if clip is None or not clip_can_have_video_fades(clip):
        return 1.0
    local_time = clip_local_time_from_timeline(clip, timeline_time, clamp_to_clip=False)
    if local_time is None:
        return 0.0
    duration = max(MIN_CLIP_DURATION, safe_float(getattr(clip, "duration", MIN_CLIP_DURATION), MIN_CLIP_DURATION))
    multiplier = 1.0
    fade_in = clip_video_fade_in_duration_value(clip)
    if fade_in > 0.0:
        multiplier = min(multiplier, clamp(local_time / fade_in, 0.0, 1.0))
    fade_out = clip_video_fade_out_duration_value(clip)
    if fade_out > 0.0:
        fade_start = max(0.0, duration - fade_out)
        if local_time >= fade_start:
            multiplier = min(multiplier, clamp((duration - local_time) / fade_out, 0.0, 1.0))
    return float(clamp(multiplier, 0.0, 1.0))


def clip_effective_visual_opacity(clip: Optional["Clip"], timeline_time: Any) -> float:
    """Combine transform opacity with the separate video fade multiplier."""
    if clip is None or not clip_is_visual(clip):
        return 1.0
    transform = visual_transform_at_timeline_time(clip, timeline_time)
    base_opacity = clamp_transform_opacity(transform.get("transform_opacity", 1.0), 1.0)
    return float(clamp(base_opacity * video_fade_multiplier_for_clip(clip, timeline_time), 0.0, 1.0))


def clip_local_time_from_timeline(clip: Optional["Clip"], timeline_time: Any, *, clamp_to_clip: bool = True) -> Optional[float]:
    if clip is None:
        return None
    try:
        t = float(timeline_time or 0.0)
    except Exception:
        t = 0.0
    start = max(0.0, safe_float(getattr(clip, "start", 0.0), 0.0))
    duration = max(MIN_CLIP_DURATION, safe_float(getattr(clip, "duration", MIN_CLIP_DURATION), MIN_CLIP_DURATION))
    local_time = t - start
    if not clamp_to_clip and (local_time < -0.0005 or local_time > duration + 0.0005):
        return None
    return float(clamp(local_time, 0.0, duration))


def audio_fade_multiplier_for_clip(clip: Optional["Clip"], timeline_time: Any) -> float:
    """Linear fade multiplier at timeline_time for the one active audio source."""
    if clip is None or not clip_can_have_audio_fades(clip):
        return 0.0
    local_time = clip_local_time_from_timeline(clip, timeline_time, clamp_to_clip=False)
    if local_time is None:
        return 0.0
    duration = max(MIN_CLIP_DURATION, safe_float(getattr(clip, "duration", MIN_CLIP_DURATION), MIN_CLIP_DURATION))
    multiplier = 1.0
    fade_in = clip_fade_in_duration_value(clip)
    if fade_in > 0.0:
        multiplier = min(multiplier, clamp(local_time / fade_in, 0.0, 1.0))
    fade_out = clip_fade_out_duration_value(clip)
    if fade_out > 0.0:
        fade_start = max(0.0, duration - fade_out)
        if local_time >= fade_start:
            multiplier = min(multiplier, clamp((duration - local_time) / fade_out, 0.0, 1.0))
    return float(clamp(multiplier, 0.0, 1.0))


def clip_can_have_audio_automation(clip: Optional["Clip"]) -> bool:
    return clip_media_type(clip) in {"video", "audio"}


def normalize_audio_keyframes_for_clip(clip: Optional["Clip"], raw_keyframes: Any = None) -> List[Dict[str, float]]:
    """Return sorted, clamped local-time volume automation points."""
    if clip is None or not clip_can_have_audio_automation(clip):
        return []
    duration = max(MIN_CLIP_DURATION, safe_float(getattr(clip, "duration", MIN_CLIP_DURATION), MIN_CLIP_DURATION))
    raw_items = getattr(clip, "audio_keyframes", []) if raw_keyframes is None else raw_keyframes
    if not isinstance(raw_items, list):
        return []
    points: List[Dict[str, float]] = []
    for item in raw_items:
        if isinstance(item, dict):
            raw_time = item.get("time", item.get("local_time", item.get("t", 0.0)))
            raw_volume = item.get("volume", item.get("volume_percent", item.get("v", DEFAULT_CLIP_VOLUME)))
        elif isinstance(item, (list, tuple)) and len(item) >= 2:
            raw_time, raw_volume = item[0], item[1]
        else:
            continue
        time_value = clamp(safe_float(raw_time, 0.0), 0.0, duration)
        volume_value = clamp_audio_volume_percent(raw_volume, DEFAULT_CLIP_VOLUME)
        points.append({"time": float(time_value), "volume": float(volume_value)})
    points.sort(key=lambda point: (point["time"], point["volume"]))
    merged: List[Dict[str, float]] = []
    for point in points:
        if merged and abs(merged[-1]["time"] - point["time"]) <= 0.001:
            merged[-1] = point
        else:
            merged.append(point)
    return merged


def set_normalized_audio_keyframes(clip: Optional["Clip"], raw_keyframes: Any) -> List[Dict[str, float]]:
    points = normalize_audio_keyframes_for_clip(clip, raw_keyframes)
    if clip is not None:
        clip.audio_keyframes = points
    return points


def nearest_audio_keyframe_index(clip: Optional["Clip"], local_time: Any, max_distance: float = AUDIO_KEYFRAME_NEAREST_RANGE) -> Optional[int]:
    points = normalize_audio_keyframes_for_clip(clip)
    if not points:
        return None
    local = clamp(safe_float(local_time, 0.0), 0.0, max(MIN_CLIP_DURATION, safe_float(getattr(clip, "duration", MIN_CLIP_DURATION), MIN_CLIP_DURATION)))
    best_index = min(range(len(points)), key=lambda i: abs(points[i]["time"] - local))
    if abs(points[best_index]["time"] - local) <= max(0.0, float(max_distance)):
        return int(best_index)
    return None


def add_or_update_audio_keyframe_for_clip(clip: Optional["Clip"], local_time: Any, volume_percent: Any, tolerance: float = AUDIO_KEYFRAME_UPDATE_TOLERANCE) -> Tuple[bool, str]:
    if clip is None:
        return False, "Clip not found."
    if not clip_can_have_audio_automation(clip):
        set_normalized_audio_keyframes(clip, [])
        return False, "Clip has no audio automation."
    duration = max(MIN_CLIP_DURATION, safe_float(getattr(clip, "duration", MIN_CLIP_DURATION), MIN_CLIP_DURATION))
    local = clamp(safe_float(local_time, 0.0), 0.0, duration)
    volume = clamp_audio_volume_percent(volume_percent, DEFAULT_CLIP_VOLUME)
    points = normalize_audio_keyframes_for_clip(clip)
    for point in points:
        if abs(point["time"] - local) <= max(0.0, float(tolerance)):
            point["time"] = float(local)
            point["volume"] = float(volume)
            set_normalized_audio_keyframes(clip, points)
            return True, "updated"
    points.append({"time": float(local), "volume": float(volume)})
    set_normalized_audio_keyframes(clip, points)
    return True, "added"


def audio_automation_multiplier_for_clip(clip: Optional["Clip"], timeline_time: Any) -> float:
    """Linear volume automation multiplier at timeline_time."""
    if clip is None or not clip_can_have_audio_automation(clip):
        return 1.0
    points = normalize_audio_keyframes_for_clip(clip)
    if not points:
        return 1.0
    local_time = clip_local_time_from_timeline(clip, timeline_time, clamp_to_clip=True)
    if local_time is None:
        return 1.0
    if len(points) == 1:
        return float(clamp(points[0]["volume"] / 100.0, 0.0, MAX_AUDIO_VOLUME / 100.0))
    if local_time <= points[0]["time"]:
        return float(clamp(points[0]["volume"] / 100.0, 0.0, MAX_AUDIO_VOLUME / 100.0))
    if local_time >= points[-1]["time"]:
        return float(clamp(points[-1]["volume"] / 100.0, 0.0, MAX_AUDIO_VOLUME / 100.0))
    for left, right in zip(points, points[1:]):
        if left["time"] <= local_time <= right["time"]:
            span = max(1e-9, right["time"] - left["time"])
            alpha = clamp((local_time - left["time"]) / span, 0.0, 1.0)
            volume = left["volume"] + (right["volume"] - left["volume"]) * alpha
            return float(clamp(volume / 100.0, 0.0, MAX_AUDIO_VOLUME / 100.0))
    return 1.0


def automation_points_summary(clip: Optional["Clip"]) -> str:
    points = normalize_audio_keyframes_for_clip(clip)
    if not points:
        return "None"
    return ", ".join(f"{point['time']:g}s={point['volume']:g}%" for point in points)


def clamp_clip_audio_keyframes_to_duration(clip: Optional["Clip"]) -> List[Dict[str, float]]:
    return set_normalized_audio_keyframes(clip, normalize_audio_keyframes_for_clip(clip))


def shift_clip_audio_keyframes_after_left_trim(clip: Optional["Clip"], removed_local_time: float) -> List[Dict[str, float]]:
    if clip is None:
        return []
    shifted: List[Dict[str, float]] = []
    duration = max(MIN_CLIP_DURATION, safe_float(getattr(clip, "duration", MIN_CLIP_DURATION), MIN_CLIP_DURATION))
    for point in normalize_audio_keyframes_for_clip(clip):
        new_time = point["time"] - float(removed_local_time)
        if 0.0 <= new_time <= duration:
            shifted.append({"time": float(new_time), "volume": float(point["volume"])})
    return set_normalized_audio_keyframes(clip, shifted)


def effective_audio_volume_percent(project: Optional["TimelineProject"], clip: Optional["Clip"], timeline_time: Any = None) -> float:
    """Return the final audible volume for the one active audio source."""
    if project is None or clip is None:
        return 0.0
    if not clip_audio_enabled_value(clip):
        return 0.0
    track_id = str(getattr(clip, "track_id", "") or "")
    if not track_id:
        try:
            track_id = project.track_id_from_index(project.clip_track_index(clip))
        except Exception:
            track_id = ""
    track_index = project.track_index_for_id(track_id) if track_id else None
    track = project.tracks[track_index] if track_index is not None and 0 <= track_index < len(project.tracks) else None
    if track is not None and bool(getattr(track, "muted", False)):
        return 0.0
    fade_multiplier = 1.0 if timeline_time is None else audio_fade_multiplier_for_clip(clip, timeline_time)
    automation_multiplier = 1.0 if timeline_time is None else audio_automation_multiplier_for_clip(clip, timeline_time)
    return float(clip_volume_percent_value(clip) * track_volume_percent_value(track) * fade_multiplier * automation_multiplier / 100.0)


def audio_output_linear_volume(percent: Any) -> float:
    """Map editor percent to QAudioOutput's expected volume number.

    Qt usually clamps internally; keeping the 0-200% value here preserves the
    model while still staying safe if a backend accepts only 0-1.
    """
    return float(clamp_audio_volume_percent(percent, 0.0) / 100.0)


def clamp_master_volume_percent(value: Any, default: float = DEFAULT_MASTER_VOLUME) -> float:
    """Clamp the final editor output level. Kept separate from clip/track volume for clarity."""
    return clamp_audio_volume_percent(value, default)


def clip_protection_scale_for_count(active_count: Any, enabled: Any = True) -> float:
    """Simple preview-safe gain scale for overlapping audio sources.

    This is not heavy DSP. It gives predictable headroom by lowering each
    audible source when multiple sources are mixed together.
    """
    count = max(0, safe_int(active_count, 0))
    if not bool(enabled) or count <= 1:
        return 1.0
    return float(1.0 / math.sqrt(float(count)))


def mixer_output_volume_percent(
    base_volume_percent: Any,
    master_volume_percent: Any = DEFAULT_MASTER_VOLUME,
    *,
    master_muted: Any = False,
    clip_protection_scale: Any = 1.0,
    audio_mode: Any = AUDIO_MODE_MIX_ALL,
) -> float:
    """Combine source volume with master volume, master mute, and mix protection."""
    if bool(master_muted) or normalize_audio_mode(audio_mode) == AUDIO_MODE_MUTE:
        return 0.0
    base = clamp_audio_volume_percent(base_volume_percent, 0.0)
    master = clamp_master_volume_percent(master_volume_percent, DEFAULT_MASTER_VOLUME) / 100.0
    scale = clamp(safe_float(clip_protection_scale, 1.0), 0.0, 1.0)
    return float(clamp_audio_volume_percent(base * master * scale, 0.0))


def apply_audio_mixer_gain_to_sources(
    sources: List[Dict[str, Any]],
    *,
    master_volume_percent: Any = DEFAULT_MASTER_VOLUME,
    master_muted: Any = DEFAULT_MASTER_MUTE,
    clip_protection_enabled: Any = DEFAULT_CLIP_PROTECTION_ENABLED,
    audio_mode: Any = AUDIO_MODE_MIX_ALL,
) -> Tuple[List[Dict[str, Any]], float]:
    """Return sources with final preview output volume applied.

    The source list keeps its raw track/clip/fade/automation value in
    base_effective_volume. The effective_volume key becomes the real output
    percent used by QAudioOutput.
    """
    audible_count = sum(1 for source in sources if clamp_audio_volume_percent(source.get("effective_volume", 0.0), 0.0) > 0.0)
    scale = clip_protection_scale_for_count(audible_count, clip_protection_enabled)
    adjusted: List[Dict[str, Any]] = []
    for source in sources:
        item = dict(source)
        base = clamp_audio_volume_percent(item.get("effective_volume", 0.0), 0.0)
        item["base_effective_volume"] = base
        item["master_volume"] = clamp_master_volume_percent(master_volume_percent, DEFAULT_MASTER_VOLUME)
        item["master_muted"] = bool(master_muted)
        item["clip_protection_enabled"] = bool(clip_protection_enabled)
        item["clip_protection_scale"] = scale
        item["effective_volume"] = mixer_output_volume_percent(
            base,
            master_volume_percent,
            master_muted=master_muted,
            clip_protection_scale=scale,
            audio_mode=audio_mode,
        )
        adjusted.append(item)
    return adjusted, float(scale)


def audio_mixer_status_text(
    audio_mode: Any,
    count: int = 0,
    *,
    silent: bool = False,
    master_volume_percent: Any = DEFAULT_MASTER_VOLUME,
    master_muted: Any = DEFAULT_MASTER_MUTE,
    clip_protection_enabled: Any = DEFAULT_CLIP_PROTECTION_ENABLED,
    clip_protection_scale: Any = 1.0,
) -> str:
    label = audio_mode_label(audio_mode)
    master = clamp_master_volume_percent(master_volume_percent, DEFAULT_MASTER_VOLUME)
    muted = bool(master_muted) or normalize_audio_mode(audio_mode) == AUDIO_MODE_MUTE or bool(silent)
    protect = "on" if bool(clip_protection_enabled) else "off"
    scale = clamp(safe_float(clip_protection_scale, 1.0), 0.0, 1.0)
    source_part = "silent" if muted or int(count or 0) <= 0 else f"{int(count)} src"
    text = f"Audio: {label} | {source_part} | M {master:.0f}% | Protect {protect}"
    if bool(clip_protection_enabled) and scale < 0.999 and not muted:
        text += f" x{scale:.2f}"
    return text[:120]


def clip_source_span(clip: Optional["Clip"]) -> float:
    if clip is None:
        return MIN_CLIP_DURATION
    in_point = max(0.0, safe_float(getattr(clip, "in_point", 0.0), 0.0))
    out_point = getattr(clip, "out_point", None)
    if out_point is not None:
        return max(MIN_CLIP_DURATION, safe_float(out_point, in_point + MIN_CLIP_DURATION) - in_point)
    return max(MIN_CLIP_DURATION, safe_float(getattr(clip, "duration", MIN_CLIP_DURATION), MIN_CLIP_DURATION) * clip_speed_value(clip))


def clip_timeline_duration_from_source_span(source_span: float, speed: float) -> float:
    return max(MIN_CLIP_DURATION, safe_float(source_span, MIN_CLIP_DURATION) / clamp_clip_speed(speed))


def clip_source_time_from_timeline(
    clip: Optional["Clip"],
    timeline_time: float,
    *,
    avoid_exact_out: bool = False,
) -> Optional[float]:
    if clip is None:
        return None
    try:
        t = max(0.0, float(timeline_time or 0.0))
    except Exception:
        t = 0.0
    clip_start = max(0.0, float(getattr(clip, "start", 0.0) or 0.0))
    clip_duration = max(0.0, float(getattr(clip, "duration", 0.0) or 0.0))
    if t < clip_start - 0.0005 or t >= clip_start + clip_duration - 0.0005:
        return None
    return clip_source_time_from_local_time(clip, t - clip_start, avoid_exact_out=avoid_exact_out)


@dataclass
class Clip:
    name: str
    start: float
    duration: float
    track: int = 1
    clip_id: str = field(default_factory=lambda: uuid.uuid4().hex[:12])
    color: str = "#3867d6"
    media_id: str = ""
    file_path: str = ""
    media_type: str = "video"
    in_point: float = 0.0
    out_point: Optional[float] = None
    track_id: str = ""
    missing_media: bool = False
    speed: float = 1.0
    reverse_playback: bool = False
    audio_enabled: bool = True
    clip_volume: float = DEFAULT_CLIP_VOLUME
    fade_in_duration: float = 0.0
    fade_out_duration: float = 0.0
    video_fade_in_duration: float = 0.0
    video_fade_out_duration: float = 0.0
    audio_keyframes: List[Dict[str, float]] = field(default_factory=list)
    detached_audio_clip_id: str = ""
    source_video_clip_id: str = ""
    transform_x: float = 0.0
    transform_y: float = 0.0
    transform_scale: float = 1.0
    transform_rotation: float = 0.0
    transform_opacity: float = 1.0
    transform_fit_mode: str = "fit"
    mirror_x: bool = False
    mirror_y: bool = False
    visual_keyframes: List[Dict[str, Any]] = field(default_factory=list)
    text_position_override: bool = False
    text_pos_x: float = 0.0
    text_pos_y: float = 0.0
    text_anchor: str = "asset"
    text_anim_in_type: str = "none"
    text_anim_in_duration: float = 0.0
    text_anim_out_type: str = "none"
    text_anim_out_duration: float = 0.0
    text_scroll_mode: str = "none"
    text_rotation_deg: float = 0.0
    text_reveal_mode: str = "none"
    text_reveal_duration: float = 0.0
    text_rotate_in_mode: str = "none"
    text_rotate_in_duration: float = 0.0
    text_rotate_out_mode: str = "none"
    text_rotate_out_duration: float = 0.0
    text_pop_in_mode: str = "none"
    text_pop_in_duration: float = 0.0
    text_pop_out_mode: str = "none"
    text_pop_out_duration: float = 0.0
    text_easing_curve: str = "linear"

    @property
    def end(self) -> float:
        return self.start + self.duration

    @property
    def source_end(self) -> float:
        # Source out-point is source-time based. For speed-adjusted clips the
        # timeline duration is source span / speed, so source_end is not simply
        # in_point + duration anymore.
        if self.out_point is not None:
            return max(float(self.in_point or 0.0), float(self.out_point or 0.0))
        return max(float(self.in_point or 0.0), float(self.in_point or 0.0) + float(self.duration or 0.0) * clip_speed_value(self))

    def to_dict(self) -> Dict[str, Any]:
        data = asdict(self)
        data["speed"] = clip_speed_value(self)
        data["reverse_playback"] = clip_reverse_playback_value(self)
        data["audio_enabled"] = clip_audio_enabled_value(self)
        data["clip_volume"] = clip_volume_percent_value(self)
        data["fade_in_duration"] = clip_fade_in_duration_value(self)
        data["fade_out_duration"] = clip_fade_out_duration_value(self)
        data["video_fade_in_duration"] = clip_video_fade_in_duration_value(self)
        data["video_fade_out_duration"] = clip_video_fade_out_duration_value(self)
        data["audio_keyframes"] = normalize_audio_keyframes_for_clip(self)
        visual_transform = normalize_clip_visual_transform(self)
        for field_name, value in visual_transform.items():
            data[field_name] = value
        data["mirror_x"] = clip_mirror_x_value(self)
        data["mirror_y"] = clip_mirror_y_value(self)
        data["visual_keyframes"] = visual_keyframes_for_clip(self)
        data["text_position_override"] = bool(getattr(self, "text_position_override", False))
        data["text_pos_x"] = safe_float(getattr(self, "text_pos_x", 0.0), 0.0)
        data["text_pos_y"] = safe_float(getattr(self, "text_pos_y", 0.0), 0.0)
        data["text_anchor"] = str(getattr(self, "text_anchor", "asset") or "asset")
        text_animation = normalize_text_clip_animation_metadata(self, safe_float(getattr(self, "duration", 0.0), 0.0))
        data["text_anim_in_type"] = str(text_animation.get("in_type", "none") or "none")
        data["text_anim_in_duration"] = safe_float(text_animation.get("in_duration", 0.0), 0.0)
        data["text_anim_out_type"] = str(text_animation.get("out_type", "none") or "none")
        data["text_anim_out_duration"] = safe_float(text_animation.get("out_duration", 0.0), 0.0)
        data["text_scroll_mode"] = normalize_text_scroll_mode(text_animation.get("scroll_mode", getattr(self, "text_scroll_mode", "none")))
        data["text_rotation_deg"] = normalize_text_rotation_deg(text_animation.get("rotation_deg", getattr(self, "text_rotation_deg", 0.0)))
        data["text_reveal_mode"] = normalize_text_reveal_mode(text_animation.get("reveal_mode", getattr(self, "text_reveal_mode", "none")))
        data["text_reveal_duration"] = safe_float(text_animation.get("reveal_duration", getattr(self, "text_reveal_duration", 0.0)), 0.0)
        data["text_rotate_in_mode"] = normalize_text_rotate_anim_mode(text_animation.get("rotate_in_mode", getattr(self, "text_rotate_in_mode", "none")))
        data["text_rotate_in_duration"] = safe_float(text_animation.get("rotate_in_duration", getattr(self, "text_rotate_in_duration", 0.0)), 0.0)
        data["text_rotate_out_mode"] = normalize_text_rotate_anim_mode(text_animation.get("rotate_out_mode", getattr(self, "text_rotate_out_mode", "none")))
        data["text_rotate_out_duration"] = safe_float(text_animation.get("rotate_out_duration", getattr(self, "text_rotate_out_duration", 0.0)), 0.0)
        data["text_pop_in_mode"] = normalize_text_pop_anim_mode(text_animation.get("pop_in_mode", getattr(self, "text_pop_in_mode", "none")))
        data["text_pop_in_duration"] = safe_float(text_animation.get("pop_in_duration", getattr(self, "text_pop_in_duration", 0.0)), 0.0)
        data["text_pop_out_mode"] = normalize_text_pop_anim_mode(text_animation.get("pop_out_mode", getattr(self, "text_pop_out_mode", "none")))
        data["text_pop_out_duration"] = safe_float(text_animation.get("pop_out_duration", getattr(self, "text_pop_out_duration", 0.0)), 0.0)
        data["text_easing_curve"] = normalize_text_easing_curve(text_animation.get("easing_curve", getattr(self, "text_easing_curve", "linear")))
        data["detached_audio_clip_id"] = str(getattr(self, "detached_audio_clip_id", "") or "")
        data["source_video_clip_id"] = str(getattr(self, "source_video_clip_id", "") or "")
        data["out_point"] = self.source_end if self.out_point is None else self.out_point
        return data

    @staticmethod
    def from_dict(data: Dict[str, Any]) -> "Clip":
        data = data if isinstance(data, dict) else {}
        media_type = str(data.get("media_type") or data.get("type") or "video")
        duration = max(MIN_CLIP_DURATION, safe_float(data.get("duration"), 1.0))
        in_point = max(0.0, safe_float(data.get("in_point", data.get("in", 0.0)), 0.0))
        out_raw = data.get("out_point", data.get("out", in_point + duration))
        out_point = max(in_point + MIN_CLIP_DURATION, safe_float(out_raw, in_point + duration))
        legacy_track = max(0, safe_int(data.get("track", default_track_for_media_type(media_type)), default_track_for_media_type(media_type)))
        raw_speed = clamp_clip_speed(data.get("speed", 1.0)) if clip_supports_speed(media_type) else 1.0
        audio_default = default_clip_audio_enabled(media_type)
        raw_audio_enabled = bool_from_project_value(data.get("audio_enabled", data.get("clip_audio_enabled", audio_default)), audio_default)
        if clip_media_type(media_type) == "image":
            raw_audio_enabled = False
        raw_clip_volume = clamp_audio_volume_percent(data.get("clip_volume", data.get("volume", data.get("volume_percent", DEFAULT_CLIP_VOLUME))), DEFAULT_CLIP_VOLUME)
        raw_fade_in = max(0.0, safe_float(data.get("fade_in_duration", data.get("fade_in", 0.0)), 0.0))
        raw_fade_out = max(0.0, safe_float(data.get("fade_out_duration", data.get("fade_out", 0.0)), 0.0))
        raw_video_fade_in = max(0.0, safe_float(data.get("video_fade_in_duration", data.get("video_fade_in", 0.0)), 0.0))
        raw_video_fade_out = max(0.0, safe_float(data.get("video_fade_out_duration", data.get("video_fade_out", 0.0)), 0.0))
        max_fade = max(0.0, duration / 2.0) if clip_media_type(media_type) in {"video", "audio"} else 0.0
        max_video_fade = max(0.0, duration / 2.0) if clip_media_type(media_type) in {"video", "image"} else 0.0
        clip = Clip(
            name=str(data.get("name") or data.get("display_name") or "Clip"),
            start=max(0.0, safe_float(data.get("start", data.get("start_time", 0.0)), 0.0)),
            duration=duration,
            track=legacy_track,
            clip_id=str(data.get("clip_id") or data.get("id") or uuid.uuid4().hex[:12]),
            color=str(data.get("color", color_for_media_type(media_type))),
            media_id=str(data.get("media_id", "")),
            file_path=str(data.get("file_path") or data.get("path") or ""),
            media_type=media_type,
            in_point=in_point,
            out_point=out_point,
            track_id=str(data.get("track_id") or data.get("trackId") or ""),
            missing_media=bool_from_project_value(data.get("missing_media", False), False),
            speed=raw_speed,
            reverse_playback=clip_reverse_playback_value({"media_type": media_type, **data}),
            audio_enabled=raw_audio_enabled,
            clip_volume=raw_clip_volume,
            fade_in_duration=float(clamp(raw_fade_in, 0.0, max_fade)),
            fade_out_duration=float(clamp(raw_fade_out, 0.0, max_fade)),
            video_fade_in_duration=float(clamp(raw_video_fade_in, 0.0, max_video_fade)),
            video_fade_out_duration=float(clamp(raw_video_fade_out, 0.0, max_video_fade)),
            detached_audio_clip_id=str(data.get("detached_audio_clip_id", data.get("linked_audio_clip_id", "")) or ""),
            source_video_clip_id=str(data.get("source_video_clip_id", data.get("linked_video_clip_id", "")) or ""),
            transform_x=safe_float(data.get("transform_x", 0.0), 0.0),
            transform_y=safe_float(data.get("transform_y", 0.0), 0.0),
            transform_scale=clamp_transform_scale(data.get("transform_scale", 1.0), 1.0),
            transform_rotation=normalize_transform_rotation(data.get("transform_rotation", 0.0)),
            transform_opacity=clamp_transform_opacity(data.get("transform_opacity", 1.0), 1.0),
            transform_fit_mode=normalize_transform_fit_mode(data.get("transform_fit_mode", "fit")),
            mirror_x=clip_mirror_x_value({"media_type": media_type, **data}),
            mirror_y=clip_mirror_y_value({"media_type": media_type, **data}),
            text_position_override=bool_from_project_value(data.get("text_position_override", data.get("text_position_enabled", False)), False),
            text_pos_x=safe_float(data.get("text_pos_x", data.get("text_x", 0.0)), 0.0),
            text_pos_y=safe_float(data.get("text_pos_y", data.get("text_y", 0.0)), 0.0),
            text_anchor=str(data.get("text_anchor", "asset") or "asset"),
            text_anim_in_type=normalize_text_animation_type(data.get("text_anim_in_type", data.get("text_animation_in", "none")), "in"),
            text_anim_in_duration=max(0.0, safe_float(data.get("text_anim_in_duration", data.get("text_animation_in_duration", 0.0)), 0.0)),
            text_anim_out_type=normalize_text_animation_type(data.get("text_anim_out_type", data.get("text_animation_out", "none")), "out"),
            text_anim_out_duration=max(0.0, safe_float(data.get("text_anim_out_duration", data.get("text_animation_out_duration", 0.0)), 0.0)),
            text_scroll_mode=normalize_text_scroll_mode(data.get("text_scroll_mode", data.get("text_animation_scroll", "none"))),
            text_rotation_deg=normalize_text_rotation_deg(data.get("text_rotation_deg", data.get("text_anim_rotation_deg", 0.0))),
            text_reveal_mode=normalize_text_reveal_mode(data.get("text_reveal_mode", data.get("text_typewriter_mode", "none"))),
            text_reveal_duration=max(0.0, safe_float(data.get("text_reveal_duration", data.get("text_typewriter_duration", 0.0)), 0.0)),
            text_rotate_in_mode=normalize_text_rotate_anim_mode(data.get("text_rotate_in_mode", "none")),
            text_rotate_in_duration=max(0.0, safe_float(data.get("text_rotate_in_duration", 0.0), 0.0)),
            text_rotate_out_mode=normalize_text_rotate_anim_mode(data.get("text_rotate_out_mode", "none")),
            text_rotate_out_duration=max(0.0, safe_float(data.get("text_rotate_out_duration", 0.0), 0.0)),
            text_pop_in_mode=normalize_text_pop_anim_mode(data.get("text_pop_in_mode", data.get("text_pop_bounce_in", "none"))),
            text_pop_in_duration=max(0.0, safe_float(data.get("text_pop_in_duration", 0.0), 0.0)),
            text_pop_out_mode=normalize_text_pop_anim_mode(data.get("text_pop_out_mode", data.get("text_pop_bounce_out", "none"))),
            text_pop_out_duration=max(0.0, safe_float(data.get("text_pop_out_duration", 0.0), 0.0)),
            text_easing_curve=normalize_text_easing_curve(data.get("text_easing_curve", data.get("text_ease", "linear"))),
        )
        clip.audio_keyframes = normalize_audio_keyframes_for_clip(clip, data.get("audio_keyframes", data.get("volume_keyframes", [])))
        clip.visual_keyframes = normalize_visual_keyframes(data.get("visual_keyframes", data.get("transform_keyframes", [])), duration) if visual_keyframes_supported_for_clip(clip) else []
        return clip



@dataclass
class TimelineTransition:
    transition_id: str = field(default_factory=lambda: uuid.uuid4().hex[:12])
    mask_path: str = ""
    mask_name: str = ""
    outgoing_clip_id: str = ""
    incoming_clip_id: str = ""
    boundary_time: float = 0.0
    duration: float = DEFAULT_TRANSITION_DURATION
    enabled: bool = True
    reverse: bool = False
    invert: bool = False
    softness: float = 0.0
    label: str = ""
    placement_mode: str = "manual"

    def to_dict(self) -> Dict[str, Any]:
        return {
            "transition_id": str(self.transition_id or ""),
            "type": "mask_reveal",
            "mask_path": str(self.mask_path or ""),
            "mask_name": str(self.mask_name or ""),
            "outgoing_clip_id": str(self.outgoing_clip_id or ""),
            "incoming_clip_id": str(self.incoming_clip_id or ""),
            "boundary_time": float(max(0.0, self.boundary_time)),
            "start_time": float(max(0.0, self.boundary_time)),
            "duration": float(max(MIN_TRANSITION_DURATION, self.duration)),
            "enabled": bool(self.enabled),
            "reverse": bool(self.reverse),
            "invert": bool(self.invert),
            "softness": float(max(0.0, self.softness)),
            "label": str(self.label or transition_display_name_from_filename(self.mask_name or self.mask_path)),
            "placement_mode": str(getattr(self, "placement_mode", "manual") or "manual"),
        }

    @staticmethod
    def from_dict(data: Dict[str, Any]) -> "TimelineTransition":
        data = data if isinstance(data, dict) else {}
        raw_path = str(data.get("mask_path") or data.get("path") or "")
        raw_name = str(data.get("mask_name") or Path(raw_path).name or data.get("name") or "")
        duration = max(MIN_TRANSITION_DURATION, safe_float(data.get("duration", DEFAULT_TRANSITION_DURATION), DEFAULT_TRANSITION_DURATION))
        boundary = max(0.0, safe_float(data.get("boundary_time", data.get("start_time", 0.0)), 0.0))
        return TimelineTransition(
            transition_id=str(data.get("transition_id") or data.get("id") or uuid.uuid4().hex[:12]),
            mask_path=raw_path,
            mask_name=raw_name,
            outgoing_clip_id=str(data.get("outgoing_clip_id") or data.get("out_clip_id") or ""),
            incoming_clip_id=str(data.get("incoming_clip_id") or data.get("in_clip_id") or ""),
            boundary_time=boundary,
            duration=duration,
            enabled=bool_from_project_value(data.get("enabled", True), True),
            reverse=bool_from_project_value(data.get("reverse", False), False),
            invert=bool_from_project_value(data.get("invert", False), False),
            softness=max(0.0, safe_float(data.get("softness", data.get("feather", 0.0)), 0.0)),
            label=str(data.get("label") or transition_display_name_from_filename(raw_name or raw_path)),
            placement_mode=str(data.get("placement_mode") or data.get("mode") or "manual"),
        )


def transition_assets_dir(root: Optional[Path] = None) -> Path:
    base = Path(root) if root is not None else framevision_root()
    return base / "assets" / "transitions"


def transition_display_name_from_filename(path_or_name: Any) -> str:
    stem = Path(str(path_or_name or "transition")).stem
    clean = stem.replace("_", " ").replace("-", " ").strip()
    if not clean:
        clean = "Transition"
    return " ".join(part.capitalize() for part in clean.split())


def scan_transition_mask_assets(root: Optional[Path] = None, create_missing: bool = False) -> List[Dict[str, Any]]:
    folder = transition_assets_dir(root)
    if create_missing:
        try:
            folder.mkdir(parents=True, exist_ok=True)
        except Exception:
            return []
    if not folder.exists() or not folder.is_dir():
        return []
    found: List[Dict[str, Any]] = []
    for path in sorted(folder.iterdir(), key=lambda item: item.name.lower()):
        if not path.is_file() or path.suffix.lower() not in TRANSITION_MASK_EXTS:
            continue
        try:
            stat = path.stat()
            mtime = float(stat.st_mtime)
        except Exception:
            mtime = 0.0
        found.append({
            "path": str(path),
            "name": path.name,
            "display_name": transition_display_name_from_filename(path.name),
            "mtime": mtime,
        })
    return found


def transition_mask_asset_by_name(mask_assets: List[Dict[str, Any]], mask_name_or_path: Any) -> Optional[Dict[str, Any]]:
    wanted = str(mask_name_or_path or "").strip()
    if not wanted:
        return None
    wanted_name = Path(wanted).name.lower()
    wanted_path = str(Path(wanted)).replace("\\", "/").lower()
    for asset in mask_assets:
        name = str(asset.get("name") or "").lower()
        path = str(asset.get("path") or "").replace("\\", "/").lower()
        if wanted_name and wanted_name == name:
            return asset
        if wanted_path and wanted_path == path:
            return asset
    return None



def effect_presets_dir(root: Optional[Path] = None) -> Path:
    base = Path(root) if root is not None else framevision_root()
    return base / EFFECT_PRESET_FOLDER


def effect_presets_json_path(root: Optional[Path] = None) -> Path:
    return effect_presets_dir(root) / EFFECT_PRESETS_JSON_NAME


def _effect_preset_point(t: float, **values: Any) -> Dict[str, Any]:
    data: Dict[str, Any] = {"t": float(clamp(safe_float(t, 0.0), 0.0, 1.0))}
    data.update(values)
    return data


