        class FakePreviewProcess:
            def __init__(self) -> None:
                self.running = True
                self.terminated = False
                self.killed = False
                self.waited = False

            def poll(self) -> Optional[int]:
                return None if self.running else 0

            def terminate(self) -> None:
                self.terminated = True
                self.running = False

            def wait(self, timeout: Optional[float] = None) -> int:
                self.waited = True
                return 0

            def kill(self) -> None:
                self.killed = True
                self.running = False

        fake_process = FakePreviewProcess()
        terminate_preview_process(fake_process)
        check(fake_process.terminated and fake_process.waited and not fake_process.killed, "stopping preview clears a process safely with a fake process")

        preview_state = dict(state)
        preview_state["preview_collapsed"] = True
        preview_state["embed_preview_enabled"] = False
        with tempfile.TemporaryDirectory() as tmpdir:
            preview_state_path = Path(tmpdir) / "timeline_editor.json"
            save_json(preview_state_path, preview_state)
            loaded_preview_state = load_json(preview_state_path)
        check(loaded_preview_state.get("preview_collapsed") is True, "preview collapsed state can be saved")
        check(loaded_preview_state.get("embed_preview_enabled") is False, "preview settings save/load preserves Embed preview toggle")

        # first real timeline playback v1 tests
        timeline_tracks = default_tracks()
        top_track = timeline_tracks[0].track_id
        lower_track = timeline_tracks[1].track_id if len(timeline_tracks) > 1 else timeline_tracks[0].track_id
        timeline_media = MediaItem(path="C:/media/timeline_test.mp4", name="timeline_test.mp4", media_type="video", duration=60.0)
        lower_clip = Clip(
            name="Lower overlap",
            start=8.0,
            duration=12.0,
            track=1,
            media_id=timeline_media.media_id,
            file_path=timeline_media.path,
            media_type="video",
            in_point=4.0,
            out_point=16.0,
            track_id=lower_track,
        )
        top_clip = Clip(
            name="Top overlap",
            start=10.0,
            duration=6.0,
            track=0,
            media_id=timeline_media.media_id,
            file_path=timeline_media.path,
            media_type="video",
            in_point=20.0,
            out_point=26.0,
            track_id=top_track,
        )
        gap_clip = Clip(
            name="Later clip",
            start=30.0,
            duration=5.0,
            track=1,
            media_id=timeline_media.media_id,
            file_path=timeline_media.path,
            media_type="video",
            in_point=0.0,
            out_point=5.0,
            track_id=lower_track,
        )
        timeline_project = TimelineProject(media_items=[timeline_media], clips=[lower_clip, top_clip, gap_clip], tracks=timeline_tracks)
        found_under_playhead = timeline_clip_at_time(timeline_project, 11.25)
        check(found_under_playhead is not None and found_under_playhead.clip_id == top_clip.clip_id, "finding the clip under the playhead chooses a playable clip")
        overlap_plan = timeline_playback_plan_under_playhead(timeline_project, 11.25)
        check(bool(overlap_plan.get("ok")) and overlap_plan.get("clip_id") == top_clip.clip_id, "overlapping clips choose the topmost track/clip")
        check(abs(float(overlap_plan.get("source_start") or 0.0) - 21.25) < 1e-9, "playhead time maps to correct source_start using clip.in_point")
        check(abs(float(overlap_plan.get("play_duration") or 0.0) - 4.75) < 1e-9, "trimmed clip playback duration is calculated correctly")
        gap_plan = timeline_playback_plan_under_playhead(timeline_project, 24.0)
        check(not bool(gap_plan.get("ok")) and gap_plan.get("reason") == "No clip under playhead", "gap playback fails safely")
        pause_timeline_state = timeline_pause_state(12.345)
        resume_timeline_state = timeline_resume_state(float(pause_timeline_state["resume_time"]))
        check(abs(float(resume_timeline_state["resume_time"]) - 12.345) < 1e-9, "pause/resume preserves timeline time")
        timeline_policy = timeline_playback_process_policy(existing_process_running=True)
        check(timeline_policy["stop_existing_first"] and timeline_policy["allow_only_one_active_process"], "only one playback process can be active")
        ruler_seek_policy = timeline_ruler_seek_policy(timeline_playing=True, timeline_paused=False, preview_playing=False)
        check(ruler_seek_policy["freeze_timer_updates_during_drag"] and ruler_seek_policy["restart_from_new_playhead_on_release"], "ruler seek freezes timer and restarts playback on release")
        stopped_seek_policy = timeline_ruler_seek_policy(timeline_playing=False, timeline_paused=False, preview_playing=False)
        check(not stopped_seek_policy["restart_from_new_playhead_on_release"], "ruler seek does not restart when nothing is playing")
        check(pause_button_text_for_state(True) == "Pause" and pause_button_text_for_state(False) == "Pause", "pause button stays Pause; Play handles resume")
        separate_media_preview = preview_playback_spec_for_media(timeline_media)
        separate_clip_preview = preview_playback_spec_for_clip(timeline_project, top_clip)
        check(separate_media_preview is not None and not bool(separate_media_preview.get("is_clip")), "selected media preview still works separately from timeline playback")
        check(separate_clip_preview is not None and bool(separate_clip_preview.get("is_clip")) and not bool(separate_clip_preview.get("is_timeline_playback")), "selected clip preview still works separately from timeline playback")

        touching_media = MediaItem(path="C:/media/touching.mp4", name="touching.mp4", media_type="video", duration=120.0)
        chain_track = timeline_tracks[0].track_id
        chain_clip_1 = Clip(
            name="Chain 1",
            start=0.0,
            duration=5.0,
            track=0,
            media_id=touching_media.media_id,
            file_path=touching_media.path,
            media_type="video",
            in_point=2.0,
            out_point=7.0,
            track_id=chain_track,
        )
        chain_clip_2 = Clip(
            name="Chain 2",
            start=5.05,
            duration=4.0,
            track=0,
            media_id=touching_media.media_id,
            file_path=touching_media.path,
            media_type="video",
            in_point=10.0,
            out_point=14.0,
            track_id=chain_track,
        )
        chain_project = TimelineProject(media_items=[touching_media], clips=[chain_clip_1, chain_clip_2], tracks=timeline_tracks)
        near_touch = timeline_handoff_plan_after_clip_end(chain_project, chain_clip_1, tolerance=0.1)
        check(bool(near_touch.get("ok")) and near_touch.get("plan", {}).get("clip_id") == chain_clip_2.clip_id, "next touching/near-touching clip on same track is found")
        check(abs(float(near_touch.get("plan", {}).get("source_start") or 0.0) - 10.0) < 1e-9, "trimmed near-touching handoff starts at next clip in-point")

        gap_clip_2 = Clip(
            name="Gap 2",
            start=5.25,
            duration=4.0,
            track=0,
            media_id=touching_media.media_id,
            file_path=touching_media.path,
            media_type="video",
            in_point=10.0,
            out_point=14.0,
            track_id=chain_track,
        )
        gap_project = TimelineProject(media_items=[touching_media], clips=[chain_clip_1, gap_clip_2], tracks=timeline_tracks)
        gap_handoff = timeline_handoff_plan_after_clip_end(gap_project, chain_clip_1, tolerance=0.1)
        check(not bool(gap_handoff.get("ok")) and gap_handoff.get("reason") == "Gap reached", "real gap stops playback and reports Gap reached")
        gap_lookup = timeline_gap_plan_under_playhead(gap_project, 5.10)
        check(bool(gap_lookup.get("ok")) and gap_lookup.get("next_clip_id") == gap_clip_2.clip_id, "finding the next clip after a gap stays on the same track")
        gap_playback = timeline_gap_plan_from_handoff(gap_handoff)
        check(bool(gap_playback.get("ok")) and gap_playback.get("reason") == "Gap playback", "a real gap enters GAP playback state")
        gap_tick = timeline_gap_tick_state(5.0, 5.25, 5.10, 0.10)
        check(abs(float(gap_tick.get("timeline_time") or 0.0) - 5.20) < 1e-9 and not bool(gap_tick.get("uses_media_time")), "gap playhead advances using timeline time, not media time")
        gap_tick_end = timeline_gap_tick_state(5.0, 5.25, 5.20, 0.10)
        next_after_gap_plan = timeline_playback_plan_for_clip(gap_project, gap_clip_2, 5.25)
        check(bool(gap_tick_end.get("reached_next_clip")) and next_after_gap_plan is not None and abs(float(next_after_gap_plan.get("source_start") or 0.0) - 10.0) < 1e-9, "reaching the next clip exits GAP state and starts that clip from its in-point")
        gap_pause = timeline_gap_pause_state(5.12)
        gap_resume = timeline_gap_resume_state(float(gap_pause.get("timeline_time") or 0.0))
        check(abs(float(gap_resume.get("timeline_time") or 0.0) - 5.12) < 1e-9 and not bool(gap_resume.get("paused")), "pause/resume inside a gap preserves timeline time")
        gap_stop = timeline_gap_stop_state()
        check(not bool(gap_stop.get("playback_active")) and not bool(gap_stop.get("gap_active")), "Stop inside a gap does not leave playback marked active")
        check(not bool(gap_playback.get("player_active")) and not bool(gap_playback.get("uses_media_player")), "no player process/session is active during GAP playback")

        other_track_clip = Clip(
            name="Other track touching",
            start=5.0,
            duration=4.0,
            track=1,
            media_id=touching_media.media_id,
            file_path=touching_media.path,
            media_type="video",
            in_point=20.0,
            out_point=24.0,
            track_id=lower_track,
        )
        no_cross_project = TimelineProject(media_items=[touching_media], clips=[chain_clip_1, other_track_clip], tracks=timeline_tracks)
        no_cross = timeline_handoff_plan_after_clip_end(no_cross_project, chain_clip_1, tolerance=0.1)
        check(not bool(no_cross.get("ok")) and no_cross.get("reason") == "End of track playback", "playback does not cross to another track in v13")

        overlap_next = Clip(
            name="Overlap next",
            start=4.5,
            duration=4.0,
            track=0,
            media_id=touching_media.media_id,
            file_path=touching_media.path,
            media_type="video",
            in_point=30.0,
            out_point=34.0,
            track_id=chain_track,
        )
        overlap_chain_project = TimelineProject(media_items=[touching_media], clips=[chain_clip_1, overlap_next], tracks=timeline_tracks)
        overlap_handoff = timeline_handoff_plan_after_clip_end(overlap_chain_project, chain_clip_1, tolerance=0.1)
        check(bool(overlap_handoff.get("ok")) and abs(float(overlap_handoff.get("plan", {}).get("source_start") or 0.0) - 30.5) < 1e-9, "overlapping trimmed clip handoff respects next clip in/out points")

        pause_policy = timeline_pause_state(3.25)
        play_resume_policy = timeline_resume_state(float(pause_policy["resume_time"]))
        check(abs(float(play_resume_policy["resume_time"]) - 3.25) < 1e-9 and not bool(play_resume_policy["paused"]), "Play resumes from paused position")
        one_session = playback_session_start_policy(0, True)
        duplicate_session = playback_session_start_policy(1, True)
        check(bool(one_session["allow_start"]) and not bool(duplicate_session["allow_start"]), "only one playback session can be active")

        fs_enter = fullscreen_state_after_action(False, "enter", playback_active=True)
        fs_duplicate = fullscreen_state_after_action(bool(fs_enter["active"]), "enter", playback_active=True)
        fs_escape = fullscreen_state_after_action(bool(fs_duplicate["active"]), "escape", playback_active=True)
        fs_double_enter = fullscreen_state_after_action(False, "double_click", playback_active=False)
        fs_double_exit = fullscreen_state_after_action(bool(fs_double_enter["active"]), "double_click", playback_active=False)
        check(bool(fs_enter["active"]) and bool(fs_enter["created_window"]), "fullscreen state enters fullscreen")
        check(bool(fs_duplicate["active"]) and not bool(fs_duplicate["created_window"]) and fs_duplicate["log"] == "ignored duplicate fullscreen request", "duplicate fullscreen request does not create a second fullscreen")
        check(not bool(fs_escape["active"]) and bool(fs_escape["playback_active"]), "Escape exits fullscreen without stopping playback")
        check(bool(fs_double_enter["active"]) and not bool(fs_double_exit["active"]), "double-click toggles fullscreen instead of stacking another fullscreen")

        # v15 top-track priority playback tests
        visual_tracks = default_tracks()
        visual_top = visual_tracks[0].track_id
        visual_lower = visual_tracks[1].track_id if len(visual_tracks) > 1 else visual_tracks[0].track_id
        visual_audio = visual_tracks[2].track_id if len(visual_tracks) > 2 else visual_tracks[-1].track_id
        visual_media = MediaItem(path="C:/media/visual.mp4", name="visual.mp4", media_type="video", duration=90.0)
        lower_visual = Clip(
            name="Lower base",
            start=0.0,
            duration=10.0,
            track=1,
            media_id=visual_media.media_id,
            file_path=visual_media.path,
            media_type="video",
            in_point=5.0,
            out_point=15.0,
            track_id=visual_lower,
        )
        higher_visual = Clip(
            name="Higher insert",
            start=3.0,
            duration=2.0,
            track=0,
            media_id=visual_media.media_id,
            file_path=visual_media.path,
            media_type="video",
            in_point=20.0,
            out_point=22.0,
            track_id=visual_top,
        )
        later_visual = Clip(
            name="Later any track",
            start=14.0,
            duration=3.0,
            track=0,
            media_id=visual_media.media_id,
            file_path=visual_media.path,
            media_type="image",
            in_point=0.0,
            out_point=3.0,
            track_id=visual_top,
        )
        visual_project = TimelineProject(media_items=[visual_media], clips=[lower_visual, higher_visual, later_visual], tracks=visual_tracks)
        top_choice = timeline_top_visual_clip_at_time(visual_project, 3.25)
        check(top_choice is not None and top_choice.clip_id == higher_visual.clip_id, "choosing the highest active visual track at a given playhead time")
        lower_choice = timeline_top_visual_clip_at_time(visual_project, 1.25)
        check(lower_choice is not None and lower_choice.clip_id == lower_visual.clip_id, "lower visual clip is chosen when no higher visual clip is active")
        higher_switch = timeline_visual_switch_plan(visual_project, lower_visual.clip_id, 3.25)
        check(bool(higher_switch.get("ok")) and higher_switch.get("plan", {}).get("clip_id") == higher_visual.clip_id, "switching from lower track clip to higher track clip when the higher track begins")
        lower_return = timeline_visual_switch_plan(visual_project, higher_visual.clip_id, 5.0)
        check(bool(lower_return.get("ok")) and lower_return.get("plan", {}).get("clip_id") == lower_visual.clip_id, "switching back to lower active clip when the higher track ends")
        check(abs(float(higher_switch.get("plan", {}).get("source_start") or 0.0) - 20.25) < 1e-9, "clip trim/source_start is calculated correctly after a top-track switch")

        hidden_tracks = default_tracks()
        hidden_tracks[0].visible = False
        hidden_project = TimelineProject(media_items=[visual_media], clips=[lower_visual, higher_visual], tracks=hidden_tracks)
        hidden_choice = timeline_top_visual_clip_at_time(hidden_project, 3.25)
        check(hidden_choice is not None and hidden_choice.clip_id == lower_visual.clip_id, "hidden tracks are ignored by visual playback choice")
        hidden_roundtrip = TimelineProject.from_dict(hidden_project.to_dict())
        check(not bool(hidden_roundtrip.tracks[0].visible), "track visibility saves and loads in project JSON")

        audio_overlay = Clip(
            name="High audio only",
            start=1.0,
            duration=6.0,
            track=0,
            media_type="audio",
            media_id=audio.media_id,
            file_path=audio.path,
            track_id=visual_top,
        )
        audio_ignore_project = TimelineProject(media_items=[visual_media, audio], clips=[lower_visual, audio_overlay], tracks=visual_tracks)
        audio_ignored = timeline_top_visual_clip_at_time(audio_ignore_project, 2.0)
        check(audio_ignored is not None and audio_ignored.clip_id == lower_visual.clip_id, "audio clips are ignored for visual playback choice")

        visual_gap_project = TimelineProject(media_items=[visual_media], clips=[lower_visual, later_visual], tracks=visual_tracks)
        visual_gap = timeline_visual_gap_plan_under_playhead(visual_gap_project, 11.0)
        check(bool(visual_gap.get("ok")) and visual_gap.get("next_clip_id") == later_visual.clip_id and not bool(visual_gap.get("uses_media_player")), "gap playback still works when no visual clip is active")
        check(abs(float(visual_gap.get("gap_end") or 0.0) - 14.0) < 1e-9, "next visual clip after a gap can be on any visible track")

        reevaluate_after_pause = timeline_visual_switch_plan(visual_project, lower_visual.clip_id, 3.25)
        check(bool(reevaluate_after_pause.get("ok")) and reevaluate_after_pause.get("plan", {}).get("clip_id") == higher_visual.clip_id, "pause/resume re-evaluates top-track priority correctly")
        visual_one_session = timeline_visual_session_policy(0, True)
        visual_duplicate_session = timeline_visual_session_policy(1, True)
        check(bool(visual_one_session.get("allow_start")) and not bool(visual_duplicate_session.get("allow_start")), "only one top-track playback session remains active")

        # v16 track-control foundation tests
        solo_tracks = default_tracks()
        solo_tracks[1].solo = True
        solo_project = TimelineProject(media_items=[visual_media], clips=[lower_visual, higher_visual], tracks=solo_tracks)
        solo_choice = timeline_top_visual_clip_at_time(solo_project, 3.25)
        check(solo_choice is not None and solo_choice.clip_id == lower_visual.clip_id, "soloed tracks override normal visibility priority")

        no_solo_tracks = default_tracks()
        no_solo_project = TimelineProject(media_items=[visual_media], clips=[lower_visual, higher_visual], tracks=no_solo_tracks)
        no_solo_choice = timeline_top_visual_clip_at_time(no_solo_project, 3.25)
        check(no_solo_choice is not None and no_solo_choice.clip_id == higher_visual.clip_id, "no soloed tracks means all visible tracks are eligible")

        locked_tracks = default_tracks()
        locked_tracks[1].locked = True
        locked_project = TimelineProject(media_items=[visual_media], clips=[lower_visual], tracks=locked_tracks)
        check(locked_project.add_clip_from_media(visual_media.media_id, 1.0, track=1) is None, "locked tracks reject dropped media")
        check(not locked_project.move_clip(lower_visual.clip_id, 2.0), "locked tracks reject clip move operations")
        check(not locked_project.trim_clip_right(lower_visual.clip_id, 6.0), "locked tracks reject clip trim operations")
        check(not locked_project.delete_clip(lower_visual.clip_id), "locked tracks reject clip delete operations")

