        video_muted_project = TimelineProject(media_items=[visual_media], clips=[lower_visual], tracks=video_muted_tracks)
        video_muted_plan = timeline_audio_follow_plan(video_muted_project, 3.0, AUDIO_MODE_VIDEO, active_visual_clip=lower_visual)
        check(video_muted_plan.get("reason") == "Audio muted by track", "Video audio mode respects muted visual tracks")

        audio_session = timeline_audio_session_policy(visual_active=True, audio_active=True, master_session_active=True)
        check(bool(audio_session.get("one_master_session")) and not bool(audio_session.get("allow_duplicate_master")), "Play/Pause/Stop state controls visual and audio through one master session")

        audio_state = dict(state)
        audio_state["audio_mode"] = AUDIO_MODE_TRACK
        with tempfile.TemporaryDirectory() as tmpdir:
            audio_state_path = Path(tmpdir) / "timeline_editor.json"
            save_json(audio_state_path, audio_state)
            loaded_audio_state = load_json(audio_state_path)
        check(normalize_audio_mode(loaded_audio_state.get("audio_mode")) == AUDIO_MODE_TRACK, "selected audio mode saves/loads correctly")
        check("Audio: Audio track" in timeline_audio_status_text(AUDIO_MODE_TRACK, "Top audio", "Track 1"), "audio status text can be generated without GUI")

        # v17/2 audio-track glitch/pulsing prevention tests.
        check(audio_visual_output_should_be_muted(AUDIO_MODE_TRACK), "Audio Track mode mutes/disables visual player audio")
        check(not audio_visual_output_should_be_muted(AUDIO_MODE_VIDEO), "Video Audio mode leaves visual player audio available")
        check(audio_visual_output_should_be_muted(AUDIO_MODE_MUTE), "Mute mode disables visual player audio")

        same_audio_plan = timeline_audio_follow_plan(audio_project, 3.25, AUDIO_MODE_TRACK)
        same_audio_policy = audio_track_runtime_policy(
            AUDIO_MODE_TRACK,
            str(same_audio_plan.get("clip_id") or ""),
            str(same_audio_plan.get("source_path") or ""),
            same_audio_plan,
            current_position_seconds=float(same_audio_plan.get("source_start") or 0.0) + 0.05,
        )
        check(
            not bool(same_audio_policy.get("restart_audio")) and not bool(same_audio_policy.get("seek_correction")) and bool(same_audio_policy.get("keep_audio")),
            "same active audio clip is not restarted on repeated timeline ticks",
        )

        visual_switch_policy = audio_track_runtime_policy(
            AUDIO_MODE_TRACK,
            str(same_audio_plan.get("clip_id") or ""),
            str(same_audio_plan.get("source_path") or ""),
            same_audio_plan,
            visual_switch=True,
            current_position_seconds=float(same_audio_plan.get("source_start") or 0.0),
        )
        check(
            bool(visual_switch_policy.get("visual_switch_keeps_audio")) and not bool(visual_switch_policy.get("restart_audio")),
            "switching visual clips does not restart unchanged audio-track source",
        )

        other_audio_clip = Clip(
            name="Other audio",
            start=12.0,
            duration=5.0,
            track=0,
            media_id=audio_media.media_id,
            file_path=audio_media.path,
            media_type="audio",
            in_point=0.0,
            out_point=5.0,
            track_id=audio_top_track,
        )
        other_audio_project = TimelineProject(media_items=[audio_media], clips=[audio_top_clip, other_audio_clip], tracks=audio_tracks)
        other_plan = timeline_audio_follow_plan(other_audio_project, 12.5, AUDIO_MODE_TRACK)
        switched_policy = audio_track_runtime_policy(
            AUDIO_MODE_TRACK,
            str(same_audio_plan.get("clip_id") or ""),
            str(same_audio_plan.get("source_path") or ""),
            other_plan,
            current_position_seconds=float(other_plan.get("source_start") or 0.0),
        )
        check(bool(switched_policy.get("restart_audio")) and not bool(switched_policy.get("same_source")), "changing audio clip does switch audio source")

        seek_policy = audio_track_runtime_policy(
            AUDIO_MODE_TRACK,
            str(same_audio_plan.get("clip_id") or ""),
            str(same_audio_plan.get("source_path") or ""),
            same_audio_plan,
            user_seek=True,
            current_position_seconds=float(same_audio_plan.get("source_start") or 0.0),
        )
        check(bool(seek_policy.get("restart_audio")), "seeking the playhead triggers one controlled audio seek/restart")

        small_drift = audio_track_runtime_policy(
            AUDIO_MODE_TRACK,
            str(same_audio_plan.get("clip_id") or ""),
            str(same_audio_plan.get("source_path") or ""),
            same_audio_plan,
            current_position_seconds=float(same_audio_plan.get("source_start") or 0.0) + 0.10,
        )
        big_drift = audio_track_runtime_policy(
            AUDIO_MODE_TRACK,
            str(same_audio_plan.get("clip_id") or ""),
            str(same_audio_plan.get("source_path") or ""),
            same_audio_plan,
            current_position_seconds=float(same_audio_plan.get("source_start") or 0.0) + 0.75,
        )
        check(not bool(small_drift.get("seek_correction")) and bool(big_drift.get("seek_correction")), "drift correction only happens when drift is above tolerance")

        visual_gap_audio_plan = timeline_audio_follow_plan(audio_project, 9.0, AUDIO_MODE_TRACK)
        visual_gap_audio_policy = audio_track_runtime_policy(
            AUDIO_MODE_TRACK,
            str(visual_gap_audio_plan.get("clip_id") or ""),
            str(visual_gap_audio_plan.get("source_path") or ""),
            visual_gap_audio_plan,
            current_position_seconds=float(visual_gap_audio_plan.get("source_start") or 0.0),
        )
        check(bool(visual_gap_audio_plan.get("ok")) and bool(visual_gap_audio_policy.get("keep_audio")), "visual gap with active audio track keeps audio playing normally")

        video_mode_policy = audio_track_runtime_policy(AUDIO_MODE_VIDEO, same_audio_plan.get("clip_id"), same_audio_plan.get("source_path"), same_audio_plan)
        mute_mode_policy = audio_track_runtime_policy(AUDIO_MODE_MUTE, same_audio_plan.get("clip_id"), same_audio_plan.get("source_path"), same_audio_plan)
        check(bool(video_mode_policy.get("stop_separate_audio")), "Video Audio mode disables/stops separate audio-track playback")
        check(bool(mute_mode_policy.get("stop_separate_audio")) and bool(mute_mode_policy.get("visual_audio_muted")), "Mute mode disables/stops both audio paths")

        # v17 bugfix: timeline playback is separated from explicit selected preview.
        check(playback_mode_for_play_request(False) == "timeline", "main Play chooses timeline playback even when a clip is selected")
        check(playback_mode_for_play_request(True) == "selected_preview", "selected preview must be triggered explicitly")

        timeline_sources = timeline_playback_sources_for_time(audio_project, 3.0, AUDIO_MODE_TRACK)
        check(
            timeline_sources.get("mode") == "timeline"
            and timeline_sources.get("visual_clip_id") == lower_visual.clip_id
            and timeline_sources.get("audio_clip_id") == audio_top_clip.clip_id,
            "Audio Track mode uses music/audio track while visual clip comes from top visual track",
        )

        video_audio_sources = timeline_playback_sources_for_time(audio_project, 3.0, AUDIO_MODE_VIDEO)
        check(
            video_audio_sources.get("audio_clip_id") == lower_visual.clip_id,
            "Video Audio mode uses active visual clip audio and ignores separate audio tracks",
        )

        mute_sources = timeline_playback_sources_for_time(audio_project, 3.0, AUDIO_MODE_MUTE)
        check(bool(mute_sources.get("audio_silent")), "Mute mode disables audio during timeline playback")

        selected_audio_does_not_own_visual = timeline_playback_sources_for_time(audio_project, 3.0, AUDIO_MODE_TRACK)
        check(
            selected_audio_does_not_own_visual.get("visual_clip_id") == lower_visual.clip_id,
            "selecting an audio clip does not make Timeline Play ignore visual clips",
        )

        seek_restart = timeline_seek_during_playback_result(7.25, was_playing=True)
        check(
            bool(seek_restart.get("restart_timeline")) and seek_restart.get("mode") == "timeline" and abs(float(seek_restart.get("timeline_time") or 0.0) - 7.25) < 1e-9,
            "moving the playhead during timeline playback updates/restarts timeline playback from the new time",
        )

        timeline_from_selected_preview = playback_mode_transition("selected_preview", "timeline")
        check(
            timeline_from_selected_preview.get("mode") == "timeline" and bool(timeline_from_selected_preview.get("stop_selected_preview")),
            "starting Timeline Playback stops Selected Preview",
        )

        selected_preview_from_timeline = playback_mode_transition("timeline", "selected_preview")
        check(
            selected_preview_from_timeline.get("mode") == "selected_preview" and bool(selected_preview_from_timeline.get("stop_timeline")),
            "starting Selected Preview stops Timeline Playback",
        )

        not_stuck_to_selection = timeline_playback_sources_for_time(audio_project, 6.0, AUDIO_MODE_TRACK)
        check(
            not_stuck_to_selection.get("visual_clip_id") == lower_visual.clip_id
            and not_stuck_to_selection.get("mode") == "timeline",
            "playback does not remain stuck to the previously selected clip",
        )

        # v17/3 bugfix: live timeline edits invalidate cached playback sources and remap once.
        remap_project = TimelineProject(media_items=[visual_media, audio_media], clips=[lower_visual, audio_top_clip], tracks=audio_tracks)
        active_before_move = timeline_playback_remap_plan_after_edit(
            remap_project,
            3.0,
            current_clip_id=lower_visual.clip_id,
            current_clip_start=0.0,
            current_clip_duration=10.0,
            current_source_start=8.0,
        )
        check(bool(active_before_move.get("ok")) and not bool(active_before_move.get("source_changed")), "Playback source unchanged after edit is detected")

        moved_clip = remap_project.get_clip(lower_visual.clip_id)
        assert moved_clip is not None
        moved_clip.start = 1.0
        moved_remap = timeline_playback_remap_plan_after_edit(
            remap_project,
            3.0,
            current_clip_id=lower_visual.clip_id,
            current_clip_start=0.0,
            current_clip_duration=10.0,
            current_source_start=8.0,
        )
        check(
            bool(moved_remap.get("ok"))
            and str(moved_remap.get("state")) == "clip"
            and bool(moved_remap.get("source_changed"))
            and abs(float(moved_remap.get("plan", {}).get("source_start") or 0.0) - 7.0) < 1e-9,
            "moving an active clip changes source_start based on current playhead time",
        )

        moved_clip.start = 6.0
        out_from_under = timeline_playback_remap_plan_after_edit(
            remap_project,
            3.0,
            current_clip_id=lower_visual.clip_id,
            current_clip_start=1.0,
            current_clip_duration=10.0,
            current_source_start=7.0,
        )
        check(str(out_from_under.get("state")) in {"gap", "end"}, "moving an active clip out from under the playhead enters gap or ends visual playback")

        moved_clip.start = 2.0
        back_under = timeline_playback_remap_plan_after_edit(
            remap_project,
            3.0,
            current_clip_id=None,
            current_clip_start=0.0,
            current_clip_duration=0.0,
            current_source_start=0.0,
        )
        check(bool(back_under.get("ok")) and str(back_under.get("state")) == "clip" and back_under.get("clip_id") == lower_visual.clip_id, "moving or expanding a clip back under the playhead restores active visual playback")

        moved_clip.start = 0.0
        moved_clip.duration = 2.5
        trimmed_out = timeline_playback_remap_plan_after_edit(
            remap_project,
            3.0,
            current_clip_id=lower_visual.clip_id,
            current_clip_start=0.0,
            current_clip_duration=10.0,
            current_source_start=8.0,
        )
        check(str(trimmed_out.get("state")) in {"gap", "end"}, "trimming a clip smaller than current playhead enters gap")

        moved_clip.duration = 7.0
        expanded_back = timeline_playback_remap_plan_after_edit(
            remap_project,
            3.0,
            current_clip_id=lower_visual.clip_id,
            current_clip_start=0.0,
            current_clip_duration=2.5,
            current_source_start=3.0,
        )
        check(bool(expanded_back.get("ok")) and str(expanded_back.get("state")) == "clip", "expanding the clip again restores playback when playhead is inside it")

        delete_project = TimelineProject(media_items=[visual_media], clips=[lower_visual], tracks=audio_tracks)
        check(delete_project.delete_clip(lower_visual.clip_id), "test active clip can be deleted")
        deleted_remap = timeline_playback_remap_plan_after_edit(delete_project, 3.0, current_clip_id=lower_visual.clip_id, current_clip_start=0.0, current_clip_duration=10.0, current_source_start=8.0)
        check(str(deleted_remap.get("state")) in {"gap", "end"}, "deleting the active clip re-evaluates playback safely")

        visibility_project = TimelineProject(media_items=[visual_media], clips=[lower_visual, higher_visual], tracks=visual_tracks)
        vis_before = timeline_playback_remap_plan_after_edit(visibility_project, 3.0, current_clip_id=lower_visual.clip_id, current_clip_start=0.0, current_clip_duration=10.0, current_source_start=8.0)
        visibility_project.tracks[0].visible = True
        visibility_project.tracks[1].visible = False
        vis_after = timeline_playback_remap_plan_after_edit(visibility_project, 3.0, current_clip_id=str(vis_before.get("clip_id") or ""), current_clip_start=float(vis_before.get("plan", {}).get("clip_start") or 0.0), current_clip_duration=float(vis_before.get("plan", {}).get("clip_duration") or 0.0), current_source_start=float(vis_before.get("plan", {}).get("source_start") or 0.0))
        check(bool(vis_after.get("ok")) and vis_after.get("clip_id") == higher_visual.clip_id, "track visibility/solo changes trigger playback re-evaluation")

        gen_policy_first = timeline_edit_remap_generation_policy(3, 2, True)
        gen_policy_second = timeline_edit_remap_generation_policy(3, int(gen_policy_first.get("handled_generation") or 0), True)
        check(bool(gen_policy_first.get("should_remap")) and not bool(gen_policy_second.get("should_remap")), "remap happens once per edit generation, not every timer tick")

        audio_before = timeline_audio_remap_policy_after_edit(
            audio_project,
            3.0,
            AUDIO_MODE_TRACK,
            active_visual_clip=lower_visual,
            active_audio_clip_id=audio_top_clip.clip_id,
            active_audio_source_path=audio_top_clip.file_path,
            active_audio_source_start=6.0,
        )
        check(not bool(audio_before.get("force_restart")), "Audio Track mode does not restart unchanged audio after edit")
        audio_top_clip.start = 1.0
        audio_after_move = timeline_audio_remap_policy_after_edit(
            audio_project,
            3.0,
            AUDIO_MODE_TRACK,
            active_visual_clip=lower_visual,
            active_audio_clip_id=audio_top_clip.clip_id,
            active_audio_source_path=audio_top_clip.file_path,
            active_audio_source_start=6.0,
        )
        check(bool(audio_after_move.get("force_restart")) and abs(float(audio_after_move.get("plan", {}).get("source_start") or 0.0) - 7.0) < 1e-9, "Audio Track mode remaps audio after clip move/trim without restarting unchanged audio repeatedly")
        audio_top_clip.start = 0.0

        # v17/4 bugfix: timeline playhead seek must not be owned by the active source.
        seek_policy_live = timeline_ruler_seek_policy(timeline_playing=True, timeline_paused=False, preview_playing=False)
        check(bool(seek_policy_live.get("freeze_timer_updates_during_drag")), "playhead drag during playback suspends timer-owned playhead updates")

        seek_lower = Clip(
            name="Seek lower",
            start=0.0,
            duration=10.0,
            track=1,
            media_id=visual_media.media_id,
            file_path=visual_media.path,
            media_type="video",
            in_point=5.0,
            out_point=15.0,
            track_id=visual_lower,
        )
        seek_higher = Clip(
            name="Seek higher",
            start=3.0,
            duration=2.0,
            track=0,
            media_id=visual_media.media_id,
            file_path=visual_media.path,
            media_type="video",
            in_point=20.0,
            out_point=22.0,
            track_id=visual_top,
        )
        seek_project = TimelineProject(media_items=[visual_media], clips=[seek_lower, seek_higher], tracks=default_tracks())
        # Rebind track ids to the fresh project track ids so previous mutable tests cannot affect this block.
        seek_project.clips[0].track_id = seek_project.tracks[1].track_id
        seek_project.clips[1].track_id = seek_project.tracks[0].track_id

        seek_to_other_clip = timeline_playhead_seek_release_plan(seek_project, 6.0, AUDIO_MODE_VIDEO, was_playing=True, selected_clip_id=seek_higher.clip_id)
        check(bool(seek_to_other_clip.get("restart_timeline")) and bool(seek_to_other_clip.get("invalidate_cached_source")), "release after drag remaps playback from the new timeline time")
        check(
            seek_to_other_clip.get("visual_clip_id") == seek_lower.clip_id
            and abs(float(seek_to_other_clip.get("visual_plan", {}).get("source_start") or 0.0) - 11.0) < 1e-9,
            "playhead seek inside a different clip starts that clip from the correct source_start",
        )

        seek_gap = timeline_playhead_seek_release_plan(seek_project, 22.0, AUDIO_MODE_VIDEO, was_playing=True)
        check(bool(seek_gap.get("entered_gap")) or not bool(seek_gap.get("visual_plan", {}).get("ok")), "playhead seek into a gap enters gap playback")

        paused_seek = timeline_playhead_seek_release_plan(seek_project, 4.5, AUDIO_MODE_VIDEO, was_playing=True, was_paused=True)
        check(bool(paused_seek.get("update_resume_time")) and abs(float(paused_seek.get("resume_time") or 0.0) - 4.5) < 1e-9, "playhead seek while paused updates resume time")
        check(not bool(seek_to_other_clip.get("selected_clip_overrides")), "selected clip does not override timeline playhead seek")
        check(bool(seek_to_other_clip.get("invalidate_cached_source")), "playback cache is invalidated after playhead seek")
        check(not bool(seek_to_other_clip.get("stop_required_before_seek")), "Stop is not required before moving the playhead")

        # v18 edit polish: start/end, history, copy/paste/duplicate, drop mapping
        empty_end_project = TimelineProject()
        go_start_playhead = 12.5
        go_start_playhead = timeline_project_start_time()
        check(abs(go_start_playhead - 0.0) < 1e-9, "Go Start sets playhead to 0")
        check(abs(timeline_project_end_time(empty_end_project) - 0.0) < 1e-9, "Go End uses 0 when no clips exist")

        end_project = TimelineProject()
        end_media = end_project.add_media_item(MediaItem(path="C:/a/end.mp4", name="end.mp4", media_type="video", duration=4.0))
        end_a = end_project.add_clip_from_media(end_media.media_id, 2.0, track=1, snap=False)
        end_b = end_project.add_clip_from_media(end_media.media_id, 12.5, track=2, snap=False)
        check(end_a is not None and end_b is not None, "Go End test clips added")
        check(abs(timeline_project_end_time(end_project) - end_b.end) < 1e-9, "Go End uses max clip.end")

        history_project = TimelineProject()
        history_media = history_project.add_media_item(MediaItem(path="C:/a/history.mp4", name="history.mp4", media_type="video", duration=8.0))
        history_clip = history_project.add_clip_from_media(history_media.media_id, 1.0, track=1, snap=False)
        check(history_clip is not None, "history test clip added")
        history = TimelineEditHistory(limit=100)
        before_move = timeline_project_edit_state(history_project)
        history_project.move_clip(history_clip.clip_id, 5.0, new_track=1, snap=False)
        after_move = timeline_project_edit_state(history_project)
        history.push(before_move, after_move, "move clip")
        undone_project, undone_reason = history.undo(history_project)
        undone_clip = undone_project.get_clip(history_clip.clip_id)
        check(undone_clip is not None and abs(undone_clip.start - 1.0) < 1e-9 and undone_reason == "move clip", "undo restores a moved clip")
        redone_project, redone_reason = history.redo(undone_project)
        redone_clip = redone_project.get_clip(history_clip.clip_id)
        check(redone_clip is not None and abs(redone_clip.start - 5.0) < 1e-9 and redone_reason == "move clip", "redo reapplies a moved clip")
        count_before_playhead_only = history.undo_count()
        _playhead_only_time = 9.25
        check(history.undo_count() == count_before_playhead_only, "undo history does not include playhead-only movement")

        copy_project = TimelineProject()
        copy_media = copy_project.add_media_item(MediaItem(path="C:/a/copy.mp4", name="copy.mp4", media_type="video", duration=20.0))
        copy_clip = copy_project.add_clip_from_media(copy_media.media_id, 3.0, track=1, snap=False)
        check(copy_clip is not None, "copy test clip added")
        copy_project.trim_clip_left(copy_clip.clip_id, 5.0, snap=False)
        copy_project.trim_clip_right(copy_clip.clip_id, 12.0, snap=False)
        copy_clip = copy_project.get_clip(copy_clip.clip_id)
        check(copy_clip is not None, "copy test clip still exists after trim")
        payload = timeline_copy_clip_payload(copy_clip)
        paste_track_id = timeline_find_unlocked_track_id(copy_project, str(payload.get("track_id") or ""), copy_project.tracks[1].track_id)
        check(paste_track_id is not None, "paste can resolve an unlocked target track")
        pasted = timeline_make_clip_copy_from_payload(copy_project, payload, 9.75, paste_track_id or "")
        check(pasted is not None, "paste creates a copied clip")
        check(
            pasted is not None
            and pasted.media_id == copy_clip.media_id
            and abs(pasted.in_point - copy_clip.in_point) < 1e-9
            and abs(pasted.duration - copy_clip.duration) < 1e-9
            and pasted.track_id == copy_clip.track_id,
            "copy/paste preserves media id, trim, duration, and track id",
        )
        check(pasted is not None and abs(pasted.start - 9.75) < 1e-9, "paste at playhead uses the current playhead time")
        duplicate = timeline_make_clip_copy_from_payload(copy_project, payload, copy_clip.end, copy_clip.track_id)
        check(duplicate is not None and duplicate.clip_id != copy_clip.clip_id, "duplicate creates a separate clip id")

        drop_math = TimelineMath(pixels_per_second=10.0, scroll_x=50.0)
        drop_project = TimelineProject()
        drop_x = 128.0 + 200.0
        drop_y = 42.0 + 10.0
        drop_plan = timeline_drop_plan(drop_project, drop_math, drop_x, drop_y, left_gutter=128, ruler_height=42, track_height=72, snap_enabled=False)
        check(abs(float(drop_plan["raw_drop_time"]) - 25.0) < 1e-9, "drop-time calculation maps local x to the exact expected timeline time")
        scroll_plan = timeline_drop_plan(drop_project, TimelineMath(pixels_per_second=10.0, scroll_x=75.0), drop_x, drop_y, left_gutter=128, ruler_height=42, track_height=72, snap_enabled=False)
        check(abs(float(scroll_plan["raw_drop_time"]) - 27.5) < 1e-9, "drop-time calculation respects scroll_x")
        unsnapped_plan = timeline_drop_plan(drop_project, TimelineMath(pixels_per_second=10.0, scroll_x=0.0), 128.0 + 253.1, drop_y, left_gutter=128, ruler_height=42, track_height=72, snap_enabled=False)
        check(abs(float(unsnapped_plan["final_drop_time"]) - 25.31) < 1e-9, "Snap off does not change drop time")
        snapped_plan = timeline_drop_plan(drop_project, TimelineMath(pixels_per_second=10.0, scroll_x=0.0), 128.0 + 253.1, drop_y, left_gutter=128, ruler_height=42, track_height=72, snap_enabled=True)
        check(abs(float(snapped_plan["final_drop_time"]) - 25.5) < 1e-9, "Snap on rounds drop time")
        locked_drop_project = TimelineProject()
        locked_drop_project.set_track_locked(1, True)
        locked_drop = timeline_drop_plan(locked_drop_project, TimelineMath(), 200.0, 42.0 + 72.0 + 4.0, left_gutter=128, ruler_height=42, track_height=72, snap_enabled=False)
