        check(old_fade_clip is not None and clip_video_fade_in_duration_value(old_fade_clip) == 0.0 and clip_video_fade_out_duration_value(old_fade_clip) == 0.0, "old clips load with video fade durations at 0.0")

        fade_project.set_clip_fade_in(fade_video.clip_id, 1.0)
        fade_project.set_clip_fade_out(fade_video.clip_id, 2.0)
        fade_save_loaded = load_timeline_project_payload(timeline_project_save_payload(fade_project, {})).project
        fade_loaded_clip = fade_save_loaded.get_clip(fade_video.clip_id)
        check(fade_loaded_clip is not None and abs(clip_fade_in_duration_value(fade_loaded_clip) - 1.0) < 1e-9 and abs(clip_fade_out_duration_value(fade_loaded_clip) - 2.0) < 1e-9, "save/load preserves fade durations")

        fade_copy = timeline_make_clip_copy_from_payload(fade_project, timeline_copy_clip_payload(fade_video), 12.0, fade_video.track_id)
        fade_dup = timeline_make_clip_copy_from_payload(fade_project, timeline_copy_clip_payload(fade_video), 14.0, fade_video.track_id)
        check(fade_copy is not None and fade_dup is not None and abs(clip_fade_in_duration_value(fade_copy) - 1.0) < 1e-9 and abs(clip_fade_out_duration_value(fade_dup) - 2.0) < 1e-9, "copy/paste/duplicate preserves fade durations")

        fade_project.reset_clip_fades(fade_video.clip_id)
        check(clip_fade_in_duration_value(fade_video) == 0.0 and clip_fade_out_duration_value(fade_video) == 0.0, "reset fades sets both fade durations to 0.0")
        fade_project.set_clip_fade_in(fade_video.clip_id, 99.0)
        check(abs(clip_fade_in_duration_value(fade_video) - (fade_video.duration / 2.0)) < 1e-9, "fade duration clamps to safe maximum")
        fade_project.set_clip_fade_in(fade_video.clip_id, 2.0)
        fade_project.set_clip_fade_out(fade_video.clip_id, 2.0)
        check(abs(audio_fade_multiplier_for_clip(fade_video, fade_video.start) - 0.0) < 1e-9 and abs(audio_fade_multiplier_for_clip(fade_video, fade_video.start + 2.0) - 1.0) < 1e-9, "fade-in multiplier is 0 at clip start and 1 after fade duration")
        check(abs(audio_fade_multiplier_for_clip(fade_video, fade_video.end - 3.0) - 1.0) < 1e-9 and abs(audio_fade_multiplier_for_clip(fade_video, fade_video.end) - 0.0) < 1e-9, "fade-out multiplier is 1 before fade-out starts and 0 at clip end")
        fade_project.set_clip_fade_in(fade_video.clip_id, 5.0)
        fade_project.set_clip_fade_out(fade_video.clip_id, 5.0)
        check(abs(audio_fade_multiplier_for_clip(fade_video, fade_video.start + 2.0) - 0.4) < 1e-9, "overlapping fades use safe multiplier behavior")
        fade_project.set_clip_volume(fade_video.clip_id, 50.0)
        fade_project.set_track_volume(fade_project.clip_track_index(fade_video), 80.0)
        fade_project.set_clip_fade_in(fade_video.clip_id, 2.0)
        fade_project.set_clip_fade_out(fade_video.clip_id, 0.0)
        check(abs(effective_audio_volume_percent(fade_project, fade_video, fade_video.start + 1.0) - 20.0) < 1e-9, "effective volume combines clip volume, track volume, mute state, and fade multiplier")
        fade_project.set_track_muted(fade_project.clip_track_index(fade_video), True)
        check(effective_audio_volume_percent(fade_project, fade_video, fade_video.start + 1.0) == 0.0, "track mute overrides fade volume")
        fade_project.set_track_muted(fade_project.clip_track_index(fade_video), False)
        fade_video_plan = timeline_audio_follow_plan(fade_project, fade_video.start + 1.0, AUDIO_MODE_VIDEO, active_visual_clip=fade_video)
        check(abs(float(fade_video_plan.get("fade_multiplier") or 0.0) - 0.5) < 1e-9 and abs(float(fade_video_plan.get("effective_volume") or 0.0) - 20.0) < 1e-9, "Video Audio mode applies fade to active visual clip audio")
        fade_project.set_clip_fade_in(fade_audio.clip_id, 2.0)
        fade_audio_plan = timeline_audio_follow_plan(fade_project, fade_audio.start + 1.0, AUDIO_MODE_TRACK)
        check(abs(float(fade_audio_plan.get("fade_multiplier") or 0.0) - 0.5) < 1e-9, "Audio Track mode applies fade to active audio clip")
        fade_mute_plan = timeline_audio_follow_plan(fade_project, fade_video.start + 1.0, AUDIO_MODE_MUTE, active_visual_clip=fade_video)
        check(not bool(fade_mute_plan.get("ok")) and bool(fade_mute_plan.get("silent")), "Mute mode ignores fade and stays silent")
        runtime_fade_policy = audio_track_runtime_policy(AUDIO_MODE_TRACK, fade_audio_plan.get("clip_id"), fade_audio_plan.get("source_path", ""), fade_audio_plan, current_position_seconds=float(fade_audio_plan.get("source_start") or 0.0))
        check(not bool(runtime_fade_policy.get("restart_audio")) and not bool(runtime_fade_policy.get("stop_separate_audio")), "changing fades during playback does not create duplicate players or restart source every tick")

        fade_project.set_clip_video_fade_in(fade_video.clip_id, 2.0)
        fade_project.set_clip_video_fade_out(fade_video.clip_id, 2.0)
        check(abs(clip_fade_in_duration_value(fade_video) - 2.0) < 1e-9 and abs(clip_fade_out_duration_value(fade_video) - 0.0) < 1e-9, "audio fade fields remain separate from video fade fields")
        check(abs(clip_video_fade_in_duration_value(fade_video) - 2.0) < 1e-9 and abs(clip_video_fade_out_duration_value(fade_video) - 2.0) < 1e-9, "video fade fields are stored separately")
        check(abs(video_fade_multiplier_for_clip(fade_video, fade_video.start) - 0.0) < 1e-9 and abs(video_fade_multiplier_for_clip(fade_video, fade_video.start + 2.0) - 1.0) < 1e-9, "video fade opacity is 0 at fade-in start and 1 after fade-in")
        check(abs(video_fade_multiplier_for_clip(fade_video, fade_video.end - 3.0) - 1.0) < 1e-9 and abs(video_fade_multiplier_for_clip(fade_video, fade_video.end) - 0.0) < 1e-9, "video fade opacity is 1 before fade-out and 0 at clip end")
        fade_video.transform_opacity = 0.5
        check(abs(clip_effective_visual_opacity(fade_video, fade_video.start + 1.0) - 0.25) < 1e-9, "visual transform opacity combines with video fade opacity")
        fade_video.transform_opacity = 1.0
        fade_project.set_clip_video_fade_in(fade_audio.clip_id, 2.0)
        check(clip_video_fade_in_duration_value(fade_audio) == 0.0 and clip_video_fade_out_duration_value(fade_audio) == 0.0, "audio-only clips keep video fade defaults at 0.0")
        fade_project.set_clip_video_fade_in(fade_image.clip_id, 1.0)
        check(abs(clip_video_fade_in_duration_value(fade_image) - 1.0) < 1e-9 and video_fade_multiplier_for_clip(fade_image, fade_image.start) == 0.0, "image clips support visual fade-in")
        fade_video_loaded = load_timeline_project_payload(timeline_project_save_payload(fade_project, {})).project.get_clip(fade_video.clip_id)
        check(fade_video_loaded is not None and abs(clip_video_fade_in_duration_value(fade_video_loaded) - 2.0) < 1e-9 and abs(clip_video_fade_out_duration_value(fade_video_loaded) - 2.0) < 1e-9, "save/load preserves video fade durations")
        fade_render_map = build_timeline_render_map(fade_project)
        fade_render_segment = next(seg for seg in fade_render_map.get("visual_segments", []) if seg.get("clip_id") == fade_video.clip_id and abs(float(seg.get("timeline_start") or 0.0) - fade_video.start) < 1e-9)
        check(abs(float(fade_render_segment.get("video_fade_in_duration") or 0.0) - 2.0) < 1e-9 and abs(float(fade_render_segment.get("video_fade_out_duration") or 0.0) - 2.0) < 1e-9, "preview/export render map reads video fade values")
        fade_export_filters: List[str] = []
        fade_export_warnings: List[str] = []
        for seg in fade_render_map.get("visual_segments", []):
            if seg.get("clip_id") != fade_video.clip_id:
                continue
            seg_filter, seg_warnings = timeline_export_visual_filter_for_segment(seg, 1280, 720, 30, include_speed=False)
            fade_export_filters.append(seg_filter)
            fade_export_warnings.extend(seg_warnings)
        fade_filter = ",".join(fade_export_filters)
        check(not fade_export_warnings and "fade=t=in" in fade_filter and "fade=t=out" in fade_filter, "export path applies video fade filters")

        # v23 audio volume automation / keyframes
        key_project = TimelineProject()
        key_video_media = key_project.add_media_item(MediaItem(path="C:/a/key_video.mp4", name="key_video.mp4", media_type="video", duration=10.0))
        key_audio_media = key_project.add_media_item(MediaItem(path="C:/a/key_audio.mp3", name="key_audio.mp3", media_type="audio", duration=10.0))
        key_image_media = key_project.add_media_item(MediaItem(path="C:/a/key_image.png", name="key_image.png", media_type="image", duration=5.0))
        key_video = key_project.add_clip_from_media(key_video_media.media_id, 0.0, track=1, snap=False)
        key_audio = key_project.add_clip_from_media(key_audio_media.media_id, 0.0, track=2, snap=False)
        key_image = key_project.add_clip_from_media(key_image_media.media_id, 0.0, track=1, snap=False)
        check(key_video is not None and key_audio is not None and key_image is not None, "v23 keyframe test clips added")

        old_key_payload = timeline_project_save_payload(key_project, {})
        for item in old_key_payload.get("clips", []):
            item.pop("audio_keyframes", None)
        old_key_loaded = load_timeline_project_payload(old_key_payload).project
        old_key_clip = old_key_loaded.get_clip(key_video.clip_id)
        check(old_key_clip is not None and normalize_audio_keyframes_for_clip(old_key_clip) == [], "old clips load with empty audio_keyframes")

        key_project.set_clip_audio_keyframe(key_video.clip_id, 0.0, 0.0)
        key_project.set_clip_audio_keyframe(key_video.clip_id, 10.0, 100.0)
        key_save_loaded = load_timeline_project_payload(timeline_project_save_payload(key_project, {})).project
        key_loaded_clip = key_save_loaded.get_clip(key_video.clip_id)
        check(key_loaded_clip is not None and len(normalize_audio_keyframes_for_clip(key_loaded_clip)) == 2 and normalize_audio_keyframes_for_clip(key_loaded_clip)[0]["volume"] == 0.0, "save/load preserves audio_keyframes")

        key_copy = timeline_make_clip_copy_from_payload(key_project, timeline_copy_clip_payload(key_video), 12.0, key_video.track_id)
        key_dup = timeline_make_clip_copy_from_payload(key_project, timeline_copy_clip_payload(key_video), 14.0, key_video.track_id)
        check(key_copy is not None and key_dup is not None and len(normalize_audio_keyframes_for_clip(key_copy)) == 2 and len(normalize_audio_keyframes_for_clip(key_dup)) == 2, "copy/paste/duplicate preserves audio_keyframes")

        key_project.set_clip_audio_keyframe(key_video.clip_id, -5.0, 999.0)
        key_points = normalize_audio_keyframes_for_clip(key_video)
        check(any(abs(point["time"] - 0.0) < 1e-9 and abs(point["volume"] - 200.0) < 1e-9 for point in key_points), "adding a point clamps time and volume safely")
        before_count = len(normalize_audio_keyframes_for_clip(key_video))
        key_project.set_clip_audio_keyframe(key_video.clip_id, 0.03, 25.0)
        after_points = normalize_audio_keyframes_for_clip(key_video)
        check(len(after_points) == before_count and any(abs(point["time"] - 0.03) < 1e-9 and abs(point["volume"] - 25.0) < 1e-9 for point in after_points), "adding a point near existing point updates instead of duplicating")

        interp_clip = Clip("interp", 0.0, 10.0, media_type="audio", audio_keyframes=[{"time": 0.0, "volume": 0.0}, {"time": 10.0, "volume": 100.0}])
        check(abs(audio_automation_multiplier_for_clip(interp_clip, 5.0) - 0.5) < 1e-9, "linear interpolation works between two points")
        check(abs(audio_automation_multiplier_for_clip(interp_clip, -1.0) - 0.0) < 1e-9, "before first keyframe uses first volume")
        check(abs(audio_automation_multiplier_for_clip(interp_clip, 99.0) - 1.0) < 1e-9, "after last keyframe uses last volume")
        no_key_clip = Clip("nokey", 0.0, 10.0, media_type="audio")
        check(abs(audio_automation_multiplier_for_clip(no_key_clip, 5.0) - 1.0) < 1e-9, "no keyframes returns multiplier 1.0")

        key_project.set_clip_volume(key_video.clip_id, 50.0)
        key_project.set_track_volume(key_project.clip_track_index(key_video), 80.0)
        key_project.set_clip_fade_in(key_video.clip_id, 2.0)
        key_project.set_clip_audio_keyframe(key_video.clip_id, 1.0, 50.0)
        check(abs(effective_audio_volume_percent(key_project, key_video, key_video.start + 1.0) - 10.0) < 1e-9, "effective volume combines track volume, clip volume, fade multiplier, and automation multiplier")

        key_project.clear_clip_audio_keyframes(key_video.clip_id)
        check(normalize_audio_keyframes_for_clip(key_video) == [], "clear automation removes all points")
        key_project.apply_clip_audio_keyframe_preset(key_video.clip_id, "middle")
        middle_points = normalize_audio_keyframes_for_clip(key_video)
        check(len(middle_points) == 3 and abs(middle_points[0]["volume"] - 0.0) < 1e-9 and abs(middle_points[1]["time"] - key_video.duration / 2.0) < 1e-9 and abs(middle_points[2]["volume"] - 50.0) < 1e-9, "preset 0% start → 100% middle → 50% end creates correct points")

        split_key_project = TimelineProject()
        split_key_media = split_key_project.add_media_item(MediaItem(path="C:/a/split_key.mp4", name="split_key.mp4", media_type="video", duration=10.0))
        split_key_clip = split_key_project.add_clip_from_media(split_key_media.media_id, 0.0, track=1, snap=False)
        check(split_key_clip is not None, "v23 split keyframe clip added")
        split_key_project.set_clip_audio_keyframe(split_key_clip.clip_id, 2.0, 20.0)
        split_key_project.set_clip_audio_keyframe(split_key_clip.clip_id, 7.0, 70.0)
        split_pair_key = split_key_project.split_clip_at(split_key_clip.clip_id, 5.0)
        check(split_pair_key is not None and len(normalize_audio_keyframes_for_clip(split_pair_key[0])) == 1 and len(normalize_audio_keyframes_for_clip(split_pair_key[1])) == 1 and abs(normalize_audio_keyframes_for_clip(split_pair_key[1])[0]["time"] - 2.0) < 1e-9, "split keep both shifts right-side keyframes correctly")

        trim_key_project = TimelineProject()
        trim_key_media = trim_key_project.add_media_item(MediaItem(path="C:/a/trim_key.mp3", name="trim_key.mp3", media_type="audio", duration=10.0))
        trim_key_clip = trim_key_project.add_clip_from_media(trim_key_media.media_id, 0.0, track=2, snap=False)
        check(trim_key_clip is not None, "v23 trim keyframe clip added")
        trim_key_project.set_clip_audio_keyframe(trim_key_clip.clip_id, 1.0, 20.0)
        trim_key_project.set_clip_audio_keyframe(trim_key_clip.clip_id, 8.0, 80.0)
        trim_key_project.trim_clip_right(trim_key_clip.clip_id, 5.0, snap=False)
        trimmed_points = normalize_audio_keyframes_for_clip(trim_key_clip)
        check(trimmed_points and all(0.0 <= point["time"] <= trim_key_clip.duration + 1e-9 for point in trimmed_points), "trimming clamps/removes out-of-range keyframes safely")

        key_video_plan = timeline_audio_follow_plan(key_project, key_video.start + 1.0, AUDIO_MODE_VIDEO, active_visual_clip=key_video)
        check("automation_multiplier" in key_video_plan, "Video Audio mode applies automation to active visual clip audio")
        key_project.set_clip_audio_keyframe(key_audio.clip_id, 0.0, 0.0)
        key_project.set_clip_audio_keyframe(key_audio.clip_id, 10.0, 100.0)
        key_audio_plan = timeline_audio_follow_plan(key_project, key_audio.start + 5.0, AUDIO_MODE_TRACK)
        check(abs(float(key_audio_plan.get("automation_multiplier") or 0.0) - 0.5) < 1e-9, "Audio Track mode applies automation to active audio clip")
        key_mute_plan = timeline_audio_follow_plan(key_project, key_video.start + 1.0, AUDIO_MODE_MUTE, active_visual_clip=key_video)
        check(not bool(key_mute_plan.get("ok")) and bool(key_mute_plan.get("silent")), "Mute mode ignores automation and stays silent")
        runtime_key_policy = audio_track_runtime_policy(AUDIO_MODE_TRACK, key_audio_plan.get("clip_id"), key_audio_plan.get("source_path", ""), key_audio_plan, current_position_seconds=float(key_audio_plan.get("source_start") or 0.0))
        check(not bool(runtime_key_policy.get("restart_audio")) and not bool(runtime_key_policy.get("stop_separate_audio")), "changing automation during playback does not create duplicate players or restart source every tick")

        # v24 detach audio from video foundation
        detach_tracks = [
            TimelineTrack("vtrack", "Video", locked=False),
            TimelineTrack("aud", "Audio", locked=False),
        ]
        detach_video = Clip(
            "Scene video",
            3.0,
            6.0,
            0,
            media_type="video",
            track_id="vtrack",
            media_id="mvid",
            file_path="/tmp/source.mp4",
            in_point=2.0,
            out_point=8.0,
            audio_enabled=True,
            clip_volume=75.0,
            fade_in_duration=1.0,
            fade_out_duration=2.0,
            audio_keyframes=[{"time": 0.0, "volume": 20.0}, {"time": 6.0, "volume": 90.0}],
        )
        detach_project = TimelineProject(tracks=detach_tracks, media_items=[MediaItem("source.mp4", "/tmp/source.mp4", "video", 10.0, media_id="mvid")], clips=[detach_video])
        ok_detach, detach_message, detached_audio = detach_project.detach_audio_from_video(detach_video.clip_id)
        check(ok_detach and detached_audio is not None and clip_media_type(detached_audio) == "audio", "detach audio creates an audio clip from a video clip")
        check(abs(detached_audio.start - detach_video.start) < 1e-9 and abs(detached_audio.duration - detach_video.duration) < 1e-9 and abs(detached_audio.in_point - detach_video.in_point) < 1e-9 and abs(detached_audio.source_end - detach_video.source_end) < 1e-9, "detached audio has same start/duration/in/out as video")
        check(not clip_audio_enabled_value(detach_video), "original video audio_enabled becomes false")
        check(clip_audio_enabled_value(detached_audio), "detached audio audio_enabled becomes true")
        check(detached_audio.track_id == "aud" and not detach_project.is_track_locked(detached_audio.track_id), "detached audio is placed on an unlocked audio/mixed track")

        no_target_project = TimelineProject(tracks=[TimelineTrack("video", "Video", locked=False)], clips=[Clip("Free video", 0.0, 4.0, 0, media_type="video", track_id="video", file_path="/tmp/free.mp4")])
        ok_new_track, _msg_new_track, new_track_audio = no_target_project.detach_audio_from_video(no_target_project.clips[0].clip_id)
        check(ok_new_track and new_track_audio is not None and any(track.label == "Audio" for track in no_target_project.tracks), "a new Audio track is created if no safe target exists")

        image_detach = TimelineProject(clips=[Clip("Still", 0.0, 5.0, media_type="image")])
        ok_image_detach, image_detach_msg, _ = image_detach.detach_audio_from_video(image_detach.clips[0].clip_id)
        audio_detach = TimelineProject(clips=[Clip("Song", 0.0, 5.0, media_type="audio")])
        ok_audio_detach, audio_detach_msg, _ = audio_detach.detach_audio_from_video(audio_detach.clips[0].clip_id)
        check(not ok_image_detach and not ok_audio_detach and "not available" in image_detach_msg and "not available" in audio_detach_msg, "image/audio clips reject detach audio safely")

        check(abs(clip_volume_percent_value(detached_audio) - 75.0) < 1e-9 and abs(clip_fade_in_duration_value(detached_audio) - 1.0) < 1e-9 and len(normalize_audio_keyframes_for_clip(detached_audio)) == 2, "detach audio preserves/copies volume, fades, and automation")

        undo_project_source = TimelineProject(tracks=[TimelineTrack("v", "Video"), TimelineTrack("a", "Audio")], clips=[Clip("Undo video", 0.0, 4.0, 0, media_type="video", track_id="v", audio_enabled=True)])
        undo_history = TimelineEditHistory()
        before_detach_state = timeline_project_edit_state(undo_project_source)
        ok_undo_detach, _msg_undo_detach, undo_audio = undo_project_source.detach_audio_from_video(undo_project_source.clips[0].clip_id)
        after_detach_state = timeline_project_edit_state(undo_project_source)
        undo_history.push(before_detach_state, after_detach_state, "detach audio")
        undo_project, _undo_reason = undo_history.undo(undo_project_source)
        undo_video = undo_project.get_clip(undo_project_source.clips[0].clip_id)
        check(ok_undo_detach and undo_video is not None and clip_audio_enabled_value(undo_video) and len(undo_project.clips) == 1, "undo restores the original state")
        redo_project, _redo_reason = undo_history.redo(undo_project)
        redo_video = redo_project.get_clip(undo_project_source.clips[0].clip_id)
        check(redo_video is not None and not clip_audio_enabled_value(redo_video) and len(redo_project.clips) == 2, "redo restores detached audio state")

        detach_saved = load_timeline_project_payload(timeline_project_save_payload(detach_project, {})).project
        saved_video = detach_saved.get_clip(detach_video.clip_id)
        saved_audio = detach_saved.get_clip(detached_audio.clip_id)
        check(saved_video is not None and saved_audio is not None and not clip_audio_enabled_value(saved_video) and getattr(saved_video, "detached_audio_clip_id", "") == saved_audio.clip_id and getattr(saved_audio, "source_video_clip_id", "") == saved_video.clip_id, "save/load preserves detached audio clip and link metadata")

        audio_track_plan = timeline_audio_follow_plan(detach_project, detached_audio.start + 1.0, AUDIO_MODE_TRACK)
        video_audio_plan = timeline_audio_follow_plan(detach_project, detach_video.start + 1.0, AUDIO_MODE_VIDEO, active_visual_clip=detach_video)
        check(audio_track_plan.get("clip_id") == detached_audio.clip_id and bool(audio_track_plan.get("ok")), "Audio Track mode can select the detached audio clip as active audio")
        check(not bool(video_audio_plan.get("ok")) and bool(video_audio_plan.get("silent")), "Video Audio mode does not play original video audio after detach")

        locked_audio_project = TimelineProject(tracks=[TimelineTrack("video", "Video", locked=False), TimelineTrack("audio", "Audio", locked=True), TimelineTrack("mix", "Mixed", locked=False)], clips=[Clip("Locked target video", 0.0, 4.0, 0, media_type="video", track_id="video")])
        ok_locked_target, _msg_locked_target, locked_target_audio = locked_audio_project.detach_audio_from_video(locked_audio_project.clips[0].clip_id)
        check(ok_locked_target and locked_target_audio is not None and locked_target_audio.track_id != "audio" and not locked_audio_project.is_track_locked(locked_target_audio.track_id), "locked tracks are not used as detach targets")

        speed_detach_project = TimelineProject(clips=[Clip("Fast video", 0.0, 4.0, media_type="video", speed=2.0)])
        ok_speed_detach, speed_detach_msg, _ = speed_detach_project.detach_audio_from_video(speed_detach_project.clips[0].clip_id)
