        check(not preview_zoom_restarts_playback(), "Qt preview zoom does not restart playback state")


        # v149 visual transform keyframe foundation
        key_clip = Clip("Key", 0.0, 4.0, media_type="video", transform_x=10.0, transform_scale=1.5)
