        set_visual_keyframe_at_clip_time(key_clip, 0.0, {"transform_x": -100.0, "transform_y": 0.0, "transform_scale": 1.0, "transform_opacity": 1.0})
        check(abs(float(visual_transform_at_clip_time(key_clip, 3.0)["transform_x"]) + 100.0) < 1e-9, "one visual keyframe holds transform across clip")
        set_visual_keyframe_at_clip_time(key_clip, 2.0, {"transform_x": 100.0, "transform_y": 20.0, "transform_scale": 3.0, "transform_opacity": 0.5})
