        check(abs(float(visual_transform_at_clip_time(key_clip, -1.0)["transform_x"]) + 100.0) < 1e-9, "before first visual keyframe holds first value")
        check(abs(float(visual_transform_at_clip_time(key_clip, 99.0)["transform_x"]) - 100.0) < 1e-9, "after last visual keyframe holds last value")
