        set_visual_keyframe_at_clip_time(key_clip, 1.0, {"transform_x": 50.0, "transform_rotation": 30.0})
        check(set_default_visual_keyframe_at_clip_time(key_clip, 1.0) and abs(float(visual_transform_at_clip_time(key_clip, 1.0)["transform_x"])) < 1e-9, "Add Default Keyframe creates true default transform")
        check("X 0.0" in visual_transform_readout_text(key_clip, local_time=1.0) and "R 0.0" in visual_transform_readout_text(key_clip, local_time=1.0), "transform readout uses interpolated keyframe transform")
