        check(not viewer_mode_changes_clip_transform_fit_mode(viewer_transform, "fill"), "viewer fit/fill mode does not change clip transform_fit_mode")
        check(not clip_transform_changes_viewer_zoom(2.0, {"transform_scale": 4.0}), "clip transform changes do not alter viewer zoom")
        fit_rect = preview_canvas_draw_rect(800, 600, 1920, 1080, 1.0, 0.5, 0.5, "fit")
