        action_history.push(before_action_state, after_action_state, "selected transform action")
        undone_action_project, _action_undo_reason = action_history.undo(action_project)
        check(clip_has_default_visual_transform(undone_action_project.get_clip(action_a.clip_id)) and clip_has_default_visual_transform(undone_action_project.get_clip(action_b.clip_id)), "undo restores multi-clip transform changes")
        reset_result = apply_visual_transform_to_clips(action_project, [action_a, action_b], default_visual_transform())
        check(reset_result.get("changed") == 2 and clip_has_default_visual_transform(action_a) and clip_has_default_visual_transform(action_b), "reset transform restores defaults on selected visual clips")

        media_only_v26 = make_media_only_clip_payload(source_effect_clip)
        media_only_v26_copy = timeline_make_clip_copy_from_payload(action_project, media_only_v26, 8.0, "v")
        full_v26_copy = timeline_make_clip_copy_from_payload(action_project, timeline_copy_clip_payload(source_effect_clip), 11.0, "v")
        check(media_only_v26_copy is not None and clip_has_default_visual_transform(media_only_v26_copy) and not clip_has_mirror(media_only_v26_copy), "Copy Media Only uses default transform and mirror fields")
        check(full_v26_copy is not None and abs(float(normalize_clip_visual_transform(full_v26_copy)["transform_scale"]) - 2.25) < 1e-9, "Copy Everything preserves transform fields")
        check(full_v26_copy is not None and clip_mirror_x_value(full_v26_copy) and clip_mirror_y_value(full_v26_copy), "Copy Everything preserves mirror fields")
        info_v26 = preview_info_for_clip(action_project, source_effect_clip)
        check(info_v26.get("transform_x") == "31.0" and info_v26.get("visual_transform_default") == "no" and "Visual transform:" in info_v26.get("body", ""), "clip info reports transform fields")
        separate_transform = normalize_clip_visual_transform(source_effect_clip)
        check(not viewer_zoom_changes_clip_transform_scale(separate_transform, 4.0) and not viewer_mode_changes_clip_transform_fit_mode(separate_transform, "fill") and not clip_transform_changes_viewer_zoom(2.5, {"transform_scale": 6.0}), "viewer zoom/fit/fill remains separate from clip transform")

        # v24 bugfix: detached audio clips must use the audio-only path even when the source is a video file.
        detached_bug_project = TimelineProject()
        detached_bug_project.tracks = [TimelineTrack("video_track", "Video", visible=True, muted=False, solo=False, locked=False), TimelineTrack("audio_track", "Audio", visible=True, muted=False, solo=False, locked=False)]
        detached_video = Clip("Source Video", 1.0, 6.0, track=0, track_id="video_track", media_type="video", file_path="C:/media/source_video.mp4", in_point=2.0, out_point=8.0, audio_enabled=True, clip_volume=80.0, fade_in_duration=1.0, fade_out_duration=2.0, audio_keyframes=[{"time": 0.0, "volume": 50.0}, {"time": 6.0, "volume": 100.0}])
        detached_bug_project.clips = [detached_video]
        ok, _msg, detached_audio = detached_bug_project.detach_audio_from_video(detached_video.clip_id)
        check(ok and detached_audio is not None and detached_audio.media_type == "audio" and detached_audio.file_path.endswith(".mp4"), "detached audio clip has media_type=audio even if file_path is a video file")
        detached_spec = preview_playback_spec_for_clip(detached_bug_project, detached_audio)
        detached_plan = preview_start_plan_from_spec(detached_spec, 0.5)
        check(bool(detached_plan and detached_plan.get("audio_only_playback")) and not bool(detached_plan.get("uses_media_player")), "preview plan for detached audio uses audio-only playback path")
        check(detached_plan is not None and not preview_plan_uses_visual_player(detached_plan), "detached audio preview does not use visual/video player path")
        detached_bug_project.delete_clip(detached_video.clip_id)
        orphan_audio = detached_bug_project.get_clip(detached_audio.clip_id)
        status = detached_audio_link_status(detached_bug_project, orphan_audio)
        orphan_plan = preview_start_plan_from_spec(preview_playback_spec_for_clip(detached_bug_project, orphan_audio), 0.0)
        check(orphan_audio is not None and bool(status.get("linked_video_missing")) and bool(orphan_plan and orphan_plan.get("audio_only_playback")), "detached audio remains playable after original video clip is deleted")
        check(orphan_audio is not None and clip_audio_enabled_value(orphan_audio) and not clip_audio_enabled_value(detached_video), "original video audio_enabled=false does not mute detached audio")
        detached_bug_project.clips = [detached_video, detached_audio]
        audio_mode_plan = timeline_audio_follow_plan(detached_bug_project, detached_audio.start + 1.0, AUDIO_MODE_TRACK, active_visual_clip=detached_video)
        check(bool(audio_mode_plan.get("ok")) and audio_mode_plan.get("clip_id") == detached_audio.clip_id, "Audio Track mode selects detached audio as active audio source")
        video_mode_plan = timeline_audio_follow_plan(detached_bug_project, detached_video.start + 1.0, AUDIO_MODE_VIDEO, active_visual_clip=detached_video)
        check(not bool(video_mode_plan.get("ok")) and str(video_mode_plan.get("reason")) == "Clip audio disabled", "Video Audio mode keeps original detached video silent")
        volume_time = detached_audio.start + 1.0
        expected_detached_volume = effective_audio_volume_percent(detached_bug_project, detached_audio, volume_time)
        check(expected_detached_volume > 0.0 and abs(float(audio_mode_plan.get("effective_volume") or 0.0) - expected_detached_volume) < 1e-9, "clip volume/fades/automation apply to detached audio")
        audio_only_timeline_plan = timeline_audio_only_playback_plan_under_playhead(detached_bug_project, detached_audio.start + 1.0, AUDIO_MODE_TRACK)
        check(bool(audio_only_timeline_plan.get("ok")) and bool(audio_only_timeline_plan.get("audio_only_playback")), "audio-only timeline playback can plan detached audio without a visual clip")
        missing_source_audio = Clip("Missing Detached Audio", 0.0, 4.0, track=1, track_id="audio_track", media_type="audio", file_path="Z:/missing/source.mp4", source_video_clip_id="gone", audio_enabled=True)
        missing_source_plan = preview_start_plan_from_spec(preview_playback_spec_for_clip(detached_bug_project, missing_source_audio), 0.0)
        check(missing_source_plan is not None and bool(missing_source_plan.get("audio_only_playback")) and not Path(missing_source_audio.file_path).exists(), "source file missing fails safely for detached audio plan")

        # v27 real audio mixing preview: multiple active audio sources share one timeline clock.
        mix_tracks = [
            TimelineTrack("v", "Video", visible=True, muted=False, solo=False, locked=False, track_volume=80.0),
            TimelineTrack("a1", "Audio 1", visible=True, muted=False, solo=False, locked=False, track_volume=50.0),
            TimelineTrack("a2", "Audio 2", visible=True, muted=False, solo=False, locked=False, track_volume=75.0),
        ]
        mix_audio_a = Clip("Music A", 0.0, 10.0, track=1, track_id="a1", media_type="audio", media_id="am1", file_path="C:/media/a.wav", in_point=2.0, out_point=12.0, clip_volume=80.0, fade_in_duration=2.0, audio_keyframes=[{"time": 0.0, "volume": 50.0}, {"time": 10.0, "volume": 100.0}])
        mix_audio_b = Clip("Music B", 3.0, 10.0, track=2, track_id="a2", media_type="audio", media_id="am2", file_path="C:/media/b.wav", in_point=1.0, out_point=11.0, clip_volume=60.0, fade_out_duration=2.0)
        mix_detached = Clip("Detached From Video", 2.0, 6.0, track=1, track_id="a1", media_type="audio", media_id="dm1", file_path="C:/media/source_video.mp4", in_point=4.0, out_point=10.0, source_video_clip_id="source_video", audio_enabled=True)
        mix_video = Clip("Video With Audio", 0.0, 8.0, track=0, track_id="v", media_type="video", media_id="vm1", file_path="C:/media/v.mp4", clip_volume=70.0)
        mix_project = TimelineProject(tracks=mix_tracks, clips=[mix_video, mix_audio_a, mix_audio_b, mix_detached])
        mix_sources = timeline_audio_mix_sources(mix_project, 4.0, AUDIO_MODE_TRACK, active_visual_clip=mix_video)
        mix_ids = {str(source.get("clip_id")) for source in mix_sources}
        check({mix_audio_a.clip_id, mix_audio_b.clip_id, mix_detached.clip_id}.issubset(mix_ids), "Audio Track mode selects multiple overlapping audio clips")
        check(all(str(source.get("clip_id")) != mix_video.clip_id for source in mix_sources), "Audio Track mode ignores visual embedded audio")
        check(any(bool(source.get("detached_audio")) and source.get("clip_id") == mix_detached.clip_id for source in mix_sources), "detached audio clips are eligible for the audio mix")
        source_a = next(source for source in mix_sources if source.get("clip_id") == mix_audio_a.clip_id)
        check(abs(float(source_a.get("source_start") or 0.0) - 6.0) < 1e-9, "source_start maps from timeline time and in_point")
        expected_volume_a = effective_audio_volume_percent(mix_project, mix_audio_a, 4.0)
        check(abs(float(source_a.get("effective_volume") or 0.0) - expected_volume_a) < 1e-9, "effective volume combines track volume, clip volume, fades, and automation")

        muted_mix_tracks = [TimelineTrack("v", "Video", visible=True), TimelineTrack("a1", "Audio 1", visible=True, muted=True), TimelineTrack("a2", "Audio 2", visible=True)]
        muted_mix_project = TimelineProject(tracks=muted_mix_tracks, clips=[mix_audio_a, mix_audio_b])
        muted_ids = set(timeline_audio_mix_clip_ids(muted_mix_project, 4.0, AUDIO_MODE_TRACK))
        check(mix_audio_a.clip_id not in muted_ids and mix_audio_b.clip_id in muted_ids, "muted tracks are excluded from the audio mix")

        solo_mix_tracks = [TimelineTrack("v", "Video", visible=True), TimelineTrack("a1", "Audio 1", visible=True, solo=True), TimelineTrack("a2", "Audio 2", visible=True)]
        solo_mix_project = TimelineProject(tracks=solo_mix_tracks, clips=[mix_audio_a, mix_audio_b])
        solo_ids = set(timeline_audio_mix_clip_ids(solo_mix_project, 4.0, AUDIO_MODE_TRACK))
        check(solo_ids == {mix_audio_a.clip_id}, "soloed tracks limit eligible audio clips")

        disabled_audio = Clip("Disabled Audio", 0.0, 10.0, track=1, track_id="a1", media_type="audio", file_path="C:/media/disabled.wav", audio_enabled=False)
        disabled_project = TimelineProject(tracks=mix_tracks, clips=[disabled_audio, mix_audio_b])
        disabled_ids = set(timeline_audio_mix_clip_ids(disabled_project, 4.0, AUDIO_MODE_TRACK))
        check(disabled_audio.clip_id not in disabled_ids and mix_audio_b.clip_id in disabled_ids, "disabled clip audio excludes that clip")

        active_policy = audio_mix_runtime_policy([], mix_sources, force_seek=False, should_play=True)
        check(len(active_policy.get("start_clip_ids", [])) == len(mix_sources), "new audio mix sources are started once")
        repeat_policy = audio_mix_runtime_policy(list(mix_ids), mix_sources, force_seek=False, should_play=True)
        check(bool(repeat_policy.get("unchanged_kept")) and not repeat_policy.get("start_clip_ids") and not repeat_policy.get("seek_clip_ids"), "unchanged active audio clips are not restarted on repeated ticks")
        seek_policy = audio_mix_runtime_policy(list(mix_ids), mix_sources, force_seek=True, should_play=True)
        check(set(seek_policy.get("seek_clip_ids", [])) == mix_ids, "seeking remaps all active audio clips once")
        pause_policy = audio_mix_runtime_policy(list(mix_ids), mix_sources, force_seek=False, should_play=False)
        check(not bool(pause_policy.get("should_play")) and bool(pause_policy.get("unchanged_kept")), "pause/resume policy applies to all active audio players without restart")
        stop_policy = audio_mix_runtime_policy(list(mix_ids), [], force_seek=False, should_play=False)
        check(set(stop_policy.get("stop_clip_ids", [])) == mix_ids and int(stop_policy.get("active_count") or 0) == 0, "stop clears all active audio players")
        check(timeline_audio_mix_sources(mix_project, 4.0, AUDIO_MODE_MUTE) == [], "Mute mode clears/silences all audio")
        video_mode_sources = timeline_audio_mix_sources(mix_project, 4.0, AUDIO_MODE_VIDEO, active_visual_clip=mix_video)
        check(len(video_mode_sources) == 1 and video_mode_sources[0].get("clip_id") == mix_video.clip_id, "Video only mode does not mix separate audio tracks")

        # v27/2 audio mode selector: practical real-editor mixing modes.
        check(normalize_audio_mode("Video audio") == AUDIO_MODE_VIDEO and normalize_audio_mode(LEGACY_AUDIO_MODE_VIDEO) == AUDIO_MODE_VIDEO, "old Video audio setting maps to Video only")
        check(normalize_audio_mode("Audio track") == AUDIO_MODE_TRACK and normalize_audio_mode(LEGACY_AUDIO_MODE_TRACK) == AUDIO_MODE_TRACK, "old Audio track setting maps to Audio tracks only")
        check(default_project_editor_state().get("audio_mode") == AUDIO_MODE_MIX_ALL, "default audio mode is Mix all audio")

        mix_all_sources = timeline_audio_mix_sources(mix_project, 4.0, AUDIO_MODE_MIX_ALL, active_visual_clip=mix_video)
        mix_all_ids = {str(source.get("clip_id")) for source in mix_all_sources}
        check({mix_video.clip_id, mix_audio_a.clip_id, mix_audio_b.clip_id, mix_detached.clip_id}.issubset(mix_all_ids), "Mix all audio includes active video audio plus overlapping audio clips")
        check(mix_audio_a.clip_id in mix_all_ids and mix_audio_b.clip_id in mix_all_ids, "Mix all audio allows voice MP3 and music MP3 together")
        check(any(bool(source.get("embedded_video_audio")) and source.get("clip_id") == mix_video.clip_id for source in mix_all_sources), "Mix all audio tags embedded video audio as a mix source")

        tracks_only_sources = timeline_audio_mix_sources(mix_project, 4.0, AUDIO_MODE_TRACK, active_visual_clip=mix_video)
        tracks_only_ids = {str(source.get("clip_id")) for source in tracks_only_sources}
        check(mix_video.clip_id not in tracks_only_ids and {mix_audio_a.clip_id, mix_audio_b.clip_id}.issubset(tracks_only_ids), "Audio tracks only excludes embedded video audio")
        check(timeline_audio_mix_sources(mix_project, 4.0, AUDIO_MODE_MUTE, active_visual_clip=mix_video) == [], "Mute silences all audio mix sources")
        check(mix_detached.clip_id in mix_all_ids, "detached audio is included as an audio clip in Mix all audio")

        detached_no_duplicate_sources = timeline_audio_mix_sources(detached_bug_project, detached_audio.start + 1.0, AUDIO_MODE_MIX_ALL, active_visual_clip=detached_video)
        detached_no_duplicate_ids = [str(source.get("clip_id")) for source in detached_no_duplicate_sources]
        check(detached_audio.clip_id in detached_no_duplicate_ids and detached_video.clip_id not in detached_no_duplicate_ids, "disabled original video audio after detach is not duplicated")

        visual_plan_before_mode_change = timeline_visual_playback_plan_under_playhead(mix_project, 4.0)
        visual_plan_after_mode_change = timeline_visual_playback_plan_under_playhead(mix_project, 4.0)
        check(visual_plan_before_mode_change.get("clip_id") == visual_plan_after_mode_change.get("clip_id") == mix_video.clip_id, "changing audio mode during playback does not restart visual playback")
        duplicate_policy = audio_mix_runtime_policy([mix_audio_a.clip_id], [source_a, source_a], force_seek=False, should_play=True)
        check(int(duplicate_policy.get("active_count") or 0) == 1 and not duplicate_policy.get("start_clip_ids"), "duplicate audio players are not created for the same clip")

        # v32/12 stopped/paused timeline inspection: playhead drives preview without playback.
        cleanup_state = new_project_preview_cleanup_state()
        check(bool(cleanup_state.get("show_black_preview")) and bool(cleanup_state.get("clear_current_frame")), "New Project clears active preview state")
        check(not bool(cleanup_state.get("preview_qt_active")) and not bool(cleanup_state.get("preview_image_active")), "New Project clears old active clip/frame references")
        with tempfile.TemporaryDirectory() as inspect_tmp_dir:
            inspect_tmp = Path(inspect_tmp_dir)
            inspect_video_path = inspect_tmp / "inspect_video.mp4"
            inspect_image_path = inspect_tmp / "inspect_image.png"
            inspect_audio_path = inspect_tmp / "inspect_audio.wav"
            inspect_video_path.write_bytes(b"video-placeholder")
            inspect_image_path.write_bytes(b"image-placeholder")
            inspect_audio_path.write_bytes(b"audio-placeholder")
            inspect_tracks = [TimelineTrack("top", "Top", visible=True), TimelineTrack("lower", "Lower", visible=True), TimelineTrack("audio", "Audio", visible=True)]
            lower_video = Clip("Lower Video", 0.0, 10.0, track=1, track_id="lower", media_type="video", file_path=str(inspect_video_path), in_point=2.0, out_point=12.0, speed=1.0)
            top_video = Clip("Top Video", 1.0, 5.0, track=0, track_id="top", media_type="video", file_path=str(inspect_video_path), in_point=4.0, out_point=14.0, speed=2.0)
            image_inspect_clip = Clip("Still Image", 12.0, 4.0, track=0, track_id="top", media_type="image", file_path=str(inspect_image_path))
            audio_inspect_clip = Clip("Audio Only", 20.0, 5.0, track=2, track_id="audio", media_type="audio", file_path=str(inspect_audio_path), in_point=1.0, out_point=6.0)
            inspect_project = TimelineProject(tracks=inspect_tracks, clips=[lower_video, top_video, image_inspect_clip, audio_inspect_clip])
            stopped_video_plan = timeline_inspection_plan_at_playhead(inspect_project, 2.0)
            check(stopped_video_plan.get("kind") == "video" and stopped_video_plan.get("clip_id") == top_video.clip_id, "Moving playhead while stopped over a video returns a video inspection plan")
            check(abs(float(stopped_video_plan.get("source_time") or 0.0) - 6.0) < 1e-9, "Inspection source_time respects clip.in_point")
            check(abs(float(stopped_video_plan.get("speed") or 0.0) - 2.0) < 1e-9 and abs(float(stopped_video_plan.get("source_time") or 0.0) - 6.0) < 1e-9, "Inspection source_time respects clip.speed")
            image_inspection_plan = timeline_inspection_plan_at_playhead(inspect_project, 13.0)
            check(image_inspection_plan.get("kind") == "image" and image_inspection_plan.get("clip_id") == image_inspect_clip.clip_id, "Moving playhead while stopped over an image returns an image inspection plan")
            gap_inspection_plan = timeline_inspection_plan_at_playhead(inspect_project, 17.5)
            check(gap_inspection_plan.get("kind") == "gap" and gap_inspection_plan.get("display") == "black", "Moving playhead while stopped over a gap returns black preview")
            audio_inspection_plan = timeline_inspection_plan_at_playhead(inspect_project, 21.0)
            check(audio_inspection_plan.get("kind") == "audio_only" and audio_inspection_plan.get("display") == "black", "Moving playhead while stopped over audio-only returns audio-only/black preview")
            inspect_project.set_track_visible(0, False)
            hidden_plan = timeline_inspection_plan_at_playhead(inspect_project, 2.0)
            check(hidden_plan.get("clip_id") == lower_video.clip_id, "Hidden tracks are ignored during inspection")
            playback_after_hide = timeline_visual_playback_plan_under_playhead(inspect_project, 2.0)
            check(hidden_plan.get("clip_id") == playback_after_hide.get("clip_id"), "Top-track priority during inspection matches playback selection")
            inspect_project.set_track_visible(0, True)
            top_priority_plan = timeline_inspection_plan_at_playhead(inspect_project, 2.0)
            check(top_priority_plan.get("clip_id") == top_video.clip_id, "Top-track priority during inspection chooses highest visible visual track")
            paused_resume_before = 2.0
            paused_resume_after = 7.5
            check(paused_resume_after != paused_resume_before and abs(paused_resume_after - 7.5) < 1e-9, "Paused playhead move updates resume time")
            check(not bool(stopped_video_plan.get("starts_audio")) and not bool(audio_inspection_plan.get("starts_audio")), "Preview inspection does not start audio playback")
            check(not bool(stopped_video_plan.get("creates_player")) and bool(stopped_video_plan.get("uses_existing_player")), "Preview inspection does not create duplicate players")
            missing_project = TimelineProject(tracks=inspect_tracks, clips=[Clip("Missing", 0.0, 3.0, track=0, track_id="top", media_type="video", file_path=str(inspect_tmp / "missing.mp4"))])
            missing_plan = timeline_inspection_plan_at_playhead(missing_project, 1.0)
            check(missing_plan.get("kind") == "missing_source" and missing_plan.get("display") == "black", "Missing source inspection returns black preview")

            # v35 timeline monitor ownership: stopped/paused playhead motion refreshes the
            # main preview from timeline time without launching export/FFmpeg.
            stopped_refresh = timeline_preview_refresh_request_plan(timeline_playback_active=False, timeline_playback_paused=False, selected_preview_active=False, dragging=True, reason="playhead_drag")
            check(bool(stopped_refresh.get("request_preview_refresh")) and bool(stopped_refresh.get("debounced")) and not bool(stopped_refresh.get("exact")), "playhead movement requests timeline preview refresh while stopped")
            paused_refresh = timeline_preview_refresh_request_plan(timeline_playback_active=True, timeline_playback_paused=True, selected_preview_active=False, dragging=True, reason="playhead_drag")
            check(bool(paused_refresh.get("request_preview_refresh")) and bool(paused_refresh.get("debounced")), "playhead movement requests timeline preview refresh while paused")
            live_refresh = timeline_preview_refresh_request_plan(timeline_playback_active=True, timeline_playback_paused=False, selected_preview_active=False, dragging=True, reason="playhead_drag")
            check(not bool(live_refresh.get("request_preview_refresh")) and str(live_refresh.get("skip_reason")), "playhead movement during active playback does not break playback path")
            release_refresh = timeline_preview_refresh_request_plan(timeline_playback_active=False, timeline_playback_paused=False, selected_preview_active=True, dragging=True, release=True, reason="playhead_release")
            check(bool(release_refresh.get("exact")) and not bool(release_refresh.get("debounced")), "release after drag forces exact preview refresh")
            selected_owner_refresh = timeline_preview_refresh_request_plan(timeline_playback_active=False, timeline_playback_paused=False, selected_preview_active=True, dragging=False, reason="playhead_move")
            check(bool(selected_owner_refresh.get("stop_selected_preview")) and bool(selected_owner_refresh.get("timeline_monitor_owner")), "selected clip preview does not automatically steal main preview during normal playhead move")
            gap_v35_plan = timeline_inspection_plan_at_playhead(inspect_project, 17.5)
            check(gap_v35_plan.get("kind") == "gap" and gap_v35_plan.get("display") == "black", "gap at playhead produces black/empty preview plan")
            image_v35_plan = timeline_inspection_plan_at_playhead(inspect_project, 13.0)
            check(image_v35_plan.get("kind") == "image" and image_v35_plan.get("clip_id") == image_inspect_clip.clip_id, "image clip at playhead produces image preview plan")
            video_v35_plan = timeline_inspection_plan_at_playhead(inspect_project, 2.0)
            check(video_v35_plan.get("kind") == "video" and abs(float(video_v35_plan.get("source_time") or 0.0) - 6.0) < 1e-9, "video clip at playhead produces video preview plan with correct source time")
            transition_outgoing = Clip("Outgoing", 0.0, 6.0, track=0, track_id="top", media_type="video", file_path=str(inspect_video_path), in_point=0.0, out_point=6.0)
            transition_incoming = Clip("Incoming", 4.0, 6.0, track=0, track_id="top", media_type="image", file_path=str(inspect_image_path), in_point=0.0, out_point=6.0)
            transition_project = TimelineProject(
                tracks=inspect_tracks[:2],
                clips=[transition_outgoing, transition_incoming],
                transitions=[TimelineTransition(mask_path=str(inspect_tmp / "mask.png"), mask_name="mask.png", outgoing_clip_id=transition_outgoing.clip_id, incoming_clip_id=transition_incoming.clip_id, boundary_time=4.0, duration=2.0, enabled=True)],
            )
            (inspect_tmp / "mask.png").write_bytes(b"mask-placeholder")
            transition_v35_plan = timeline_inspection_plan_at_playhead(transition_project, 4.5)
            check(bool(transition_v35_plan.get("transition_active")) and bool(transition_v35_plan.get("transition_fallback_ok")), "transition time at playhead produces safe preview plan or safe fallback")
            check(transition_v35_plan.get("kind") == "transition" and transition_v35_plan.get("display") == "transition", "stopped playhead inside transition requests transition preview instead of black")
            transition_paused_refresh = timeline_preview_refresh_request_plan(timeline_playback_active=True, timeline_playback_paused=True, selected_preview_active=False, dragging=False, reason="playhead_move")
            check(bool(transition_paused_refresh.get("request_preview_refresh")) and transition_v35_plan.get("kind") == "transition", "paused playhead inside transition requests transition preview instead of black")
            transition_start_plan = timeline_inspection_plan_at_playhead(transition_project, 4.0)
            transition_mid_plan = timeline_inspection_plan_at_playhead(transition_project, 5.0)
            transition_end_plan = timeline_inspection_plan_at_playhead(transition_project, 6.0)
            check(abs(float(transition_start_plan.get("transition_progress") or 0.0) - 0.0) < 1e-6, "transition progress calculation at start")
            check(0.45 <= float(transition_mid_plan.get("transition_progress") or 0.0) <= 0.55, "transition progress calculation at middle")
            check(abs(float(transition_end_plan.get("transition_progress") or 0.0) - 1.0) < 1e-6, "transition progress calculation at end")
            missing_mask_project = TimelineProject(
                tracks=inspect_tracks[:2],
                clips=[transition_outgoing, transition_incoming],
                transitions=[TimelineTransition(mask_path=str(inspect_tmp / "missing_mask.png"), mask_name="missing_mask.png", outgoing_clip_id=transition_outgoing.clip_id, incoming_clip_id=transition_incoming.clip_id, boundary_time=4.0, duration=2.0, enabled=True)],
            )
            missing_mask_plan = timeline_inspection_plan_at_playhead(missing_mask_project, 4.5)
            check(missing_mask_plan.get("kind") == "transition" and bool(missing_mask_plan.get("transition_mask_missing")), "missing transition mask uses safe fallback, not crash")
            no_transition_plan = timeline_inspection_plan_at_playhead(transition_project, 3.0)
            check(no_transition_plan.get("kind") != "transition", "no transition at playhead still uses normal visual/gap preview")
            image_to_video_project = TimelineProject(
                tracks=inspect_tracks[:2],
                clips=[transition_incoming, transition_outgoing],
                transitions=[TimelineTransition(mask_path=str(inspect_tmp / "mask.png"), mask_name="mask.png", outgoing_clip_id=transition_incoming.clip_id, incoming_clip_id=transition_outgoing.clip_id, boundary_time=4.0, duration=2.0, enabled=True)],
            )
            image_to_video_plan = timeline_inspection_plan_at_playhead(image_to_video_project, 4.5)
            check(image_to_video_plan.get("kind") == "transition" and image_to_video_plan.get("transition_outgoing_media_type") in {"image", "video"}, "image-to-video or video-to-image transition produces safe preview plan")
            transition_project.set_track_visible(0, False)
            hidden_transition_plan = timeline_inspection_plan_at_playhead(transition_project, 4.5)
            check(hidden_transition_plan.get("kind") in {"gap", "empty"} or hidden_transition_plan.get("clip_id") != transition_incoming.clip_id, "hidden tracks ignored in preview refresh plan")
            check(hidden_transition_plan.get("kind") != "transition", "hidden track transition is ignored")
            check(bool(stopped_refresh.get("debounced")) and bool(release_refresh.get("exact")), "dragging across transition does not spam or bypass debounce")
            check(not bool(stopped_refresh.get("launches_ffmpeg")) and not bool(release_refresh.get("starts_playback")), "preview refresh self-tests do not launch real FFmpeg rendering")

            # v36 source preview popup routing: source/media previews do not steal
            # the main timeline monitor and do not launch export/FFmpeg.
            media_spec = preview_playback_spec_for_media(MediaItem(path=str(inspect_video_path), name="Media bin video", media_type="video", duration=7.0))
            media_popup_plan = source_preview_request_plan(media_spec, timeline_playback_active=True, timeline_playback_paused=False, timeline_playhead=3.25)
            check(media_popup_plan.get("ok") and media_popup_plan.get("route") == "source_preview_popup", "media-bin preview action routes to popup, not main timeline preview ownership")
            check(media_popup_plan.get("main_preview_owner") == "timeline_monitor" and bool(media_popup_plan.get("pause_timeline")), "source preview popup can pause timeline playback without stealing main preview")
            media_select_policy = media_bin_selection_main_preview_policy()
            check(media_select_policy.get("main_preview_owner") == "timeline_monitor", "media-bin selection leaves main preview owned by timeline")
            check(not bool(media_select_policy.get("update_main_preview")) and not bool(media_select_policy.get("show_media_info_in_main_preview")), "media-bin selection does not replace main preview with media info")
            check(not bool(media_select_policy.get("stop_timeline_playback")) and not bool(media_select_policy.get("stop_selected_preview")), "media-bin selection does not stop timeline or selected preview playback")
            check(not bool(media_select_policy.get("clear_selected_clip")) and not bool(media_select_policy.get("changes_timeline_playhead")), "media-bin selection does not clear timeline selection or move playhead")
            clip_popup_spec = preview_playback_spec_for_clip(inspect_project, top_video)
            clip_popup_plan = source_preview_request_plan(clip_popup_spec, timeline_playback_active=False, timeline_playback_paused=False, timeline_playhead=2.0)
            check(clip_popup_plan.get("ok") and clip_popup_plan.get("is_clip") and clip_popup_plan.get("clip_id") == top_video.clip_id, "timeline clip right-click source preview routes to popup")
            check(not bool(clip_popup_plan.get("changes_timeline_playhead")) and abs(float(clip_popup_plan.get("timeline_playhead") or 0.0) - 2.0) < 1e-9, "opening source preview does not change timeline playhead")
            close_popup_plan = source_preview_closure_plan(2.0)
            check(close_popup_plan.get("main_preview_owner") == "timeline_monitor" and bool(close_popup_plan.get("request_timeline_refresh")), "closing source preview leaves main preview as timeline-owned")
            after_popup_refresh = timeline_preview_refresh_request_plan(timeline_playback_active=False, timeline_playback_paused=False, selected_preview_active=False, dragging=False, reason="source_preview_closed")
            check(bool(after_popup_refresh.get("request_preview_refresh")), "timeline playhead preview still refreshes after popup closes")
            select_refresh_v36 = timeline_preview_refresh_request_plan(timeline_playback_active=False, timeline_playback_paused=False, selected_preview_active=False, dragging=False, reason="selection_changed")
            check(bool(select_refresh_v36.get("timeline_monitor_owner")), "selected clip does not automatically steal main preview")
            missing_source_plan = source_preview_request_plan({"title": "Missing", "source_path": str(inspect_tmp / "no_such_file.mp4"), "media_type": "video"})
            check(not bool(missing_source_plan.get("ok")) and missing_source_plan.get("reason") == "missing_source_file", "missing source file fails safely")
            detached_clip = Clip("Detached source", 0.0, 4.0, track=2, track_id="audio", media_type="audio", file_path=str(inspect_video_path), source_video_clip_id=top_video.clip_id)
            detached_plan = source_preview_request_plan(preview_playback_spec_for_clip(inspect_project, detached_clip), require_existing_source=True)
            check(detached_plan.get("ok") and bool(detached_plan.get("detached_audio")) and detached_plan.get("media_type") == "audio", "detached audio clip source path can be passed to popup safely")
            check(not bool(media_popup_plan.get("uses_export")) and not bool(media_popup_plan.get("launches_ffmpeg")), "source preview self-tests do not launch real FFmpeg rendering")
            check(not bool(media_popup_plan.get("requires_real_popup_playback")), "source preview self-tests do not require real popup playback/audio hardware")

            # v36.1 main Preview scrubber: timeline monitor uses absolute timeline
            # time, while SourcePreviewDialog keeps source-time behavior.
            timeline_ui = timeline_preview_time_ui_state(30.0, 14.25)
            check(timeline_ui["slider_range"] == (0, 30000), "main preview slider range uses full timeline duration")
            check(timeline_ui["slider_value"] == 14250 and abs(float(timeline_ui["position"]) - 14.25) < 1e-9, "main preview slider value uses timeline playhead time")
            first_clip_ui = timeline_preview_time_ui_state(30.0, 9.75)
            second_clip_ui = timeline_preview_time_ui_state(30.0, 10.25)
            check(first_clip_ui["slider_value"] == 9750 and second_clip_ui["slider_value"] == 10250, "slider does not reset when moving from one clip to another")
            gap_slider_ui = timeline_preview_time_ui_state(30.0, 22.0)
            check(gap_slider_ui["slider_value"] == 22000, "slider continues through visual gaps")
            transition_slider_ui = timeline_preview_time_ui_state(30.0, 4.5)
            check(transition_slider_ui["slider_value"] == 4500, "slider continues through transitions")
            stopped_seek_plan = timeline_preview_slider_seek_plan(12500, 30.0)
            check(abs(float(stopped_seek_plan["timeline_time"]) - 12.5) < 1e-9 and bool(stopped_seek_plan["seek_timeline_playhead"]), "stopped/paused playhead movement updates slider to timeline time")
            duration_change_ui = timeline_preview_time_ui_state(246.0, 24.708333)
            check(duration_change_ui["slider_range"] == (0, 246000), "timeline duration change updates slider maximum")
            empty_ui = timeline_preview_time_ui_state(0.0, 99.0)
            check(empty_ui["slider_range"] == (0, 0) and empty_ui["slider_value"] == 0, "empty timeline resets slider safely")
            slider_seek_timeline = timeline_preview_slider_seek_plan(18000, 30.0)
            check(bool(slider_seek_timeline["seek_timeline_playhead"]) and not bool(slider_seek_timeline["seek_source_media"]), "main preview slider seek updates timeline playhead, not source media position")
            source_popup_time = preview_time_label_text(3.0, 7.0)
            check(source_popup_time == "00:03.000 / 00:07.000" and not bool(timeline_ui["uses_source_time"]), "source preview popup keeps source-time behavior")

        # v29 audio mixer polish: master output level and simple clipping protection.
        check(abs(mixer_output_volume_percent(100.0, 50.0) - 50.0) < 1e-9, "master volume scales effective volume")
        check(mixer_output_volume_percent(100.0, 100.0, master_muted=True) == 0.0, "master mute forces volume 0")
        check(mixer_output_volume_percent(100.0, 100.0, audio_mode=AUDIO_MODE_MUTE) == 0.0, "mute mode still forces volume 0")
        check(abs(clip_protection_scale_for_count(1, True) - 1.0) < 1e-9, "clipping protection does not reduce single-source audio")
        protection_scale_two = clip_protection_scale_for_count(2, True)
        check(0.0 < protection_scale_two < 1.0, "clipping protection reduces volume when multiple sources are active")
        adjusted_sources, adjusted_scale = apply_audio_mixer_gain_to_sources(mix_sources, master_volume_percent=50.0, master_muted=False, clip_protection_enabled=True, audio_mode=AUDIO_MODE_TRACK)
        adjusted_a = next(source for source in adjusted_sources if source.get("clip_id") == mix_audio_a.clip_id)
        check(abs(float(adjusted_a.get("effective_volume") or 0.0) - expected_volume_a * 0.5 * adjusted_scale) < 1e-6, "effective volume combines master, protection, track, clip, fade, and automation")
        master_change_policy = audio_mix_runtime_policy(list(mix_ids), mix_sources, force_seek=False, should_play=True)
        check(bool(master_change_policy.get("unchanged_kept")) and not master_change_policy.get("start_clip_ids") and not master_change_policy.get("stop_clip_ids"), "changing master volume during playback does not restart audio sources")
        saved_mixer_state = sanitize_project_editor_state({"master_volume": 135.0, "master_muted": True, "clip_protection_enabled": False})
        check(abs(float(saved_mixer_state.get("master_volume") or 0.0) - 135.0) < 1e-9 and bool(saved_mixer_state.get("master_muted")) and not bool(saved_mixer_state.get("clip_protection_enabled")), "settings save/load preserves master volume, mute, and clip protection")
        old_mixer_state = sanitize_project_editor_state({})
        check(abs(float(old_mixer_state.get("master_volume") or 0.0) - DEFAULT_MASTER_VOLUME) < 1e-9 and not bool(old_mixer_state.get("master_muted")) and bool(old_mixer_state.get("clip_protection_enabled")), "old settings default audio mixer safely")

        # v37 two-band layout polish + professional title cleanup.
        check(sanitize_editor_font_size(999) == MAX_EDITOR_FONT_SIZE and sanitize_editor_font_size(-5) == MIN_EDITOR_FONT_SIZE, "editor font size is clamped safely")
        font_state = sanitize_project_editor_state({"editor_font_size": 11})
        check(font_state.get("editor_font_size") == 11, "editor font size saves/loads through editor state")
        old_settings_state = sanitize_project_editor_state({"pixels_per_second": 70.0, "scroll_x": 12.0, "playhead_time": 3.5})
        check(old_settings_state.get("layout_preset") == LAYOUT_PRESET_MEDIA_TOP, "old settings JSON without layout preset loads to Media Top safely")
        invalid_layout_state = sanitize_project_editor_state({"layout_preset": "banana", "media_collapsed": True})
        check(invalid_layout_state.get("layout_preset") == LAYOUT_PRESET_MEDIA_TOP, "invalid layout preset falls back to Media Top")
        check(list(LAYOUT_PRESET_LABELS.values()) == ["Editing", "Timeline Top", "Media Top", "Classic"], "layout preset list contains the useful v37 layout names")
        check("Preview Left" not in LAYOUT_PRESET_LABELS.values() and "Timeline Focus" not in LAYOUT_PRESET_LABELS.values() and "Media Focus" not in LAYOUT_PRESET_LABELS.values(), "old broken layout names are not exposed")
        legacy_preview_left_state = sanitize_project_editor_state({
            "layout_preset": "Preview Left",
            "media_collapsed": False,
            "timeline_collapsed": False,
            "preview_collapsed": True,
            "logs_collapsed": True,
        })
        check(legacy_preview_left_state.get("layout_preset") == LAYOUT_PRESET_EDITING and bool(legacy_preview_left_state.get("preview_collapsed")), "legacy Preview Left settings remap safely to Editing")
        reset_state = default_layout_state_for_preset(LAYOUT_PRESET_EDITING)
        check(reset_state.get("layout_preset") == LAYOUT_PRESET_EDITING and bool(reset_state.get("media_collapsed")) and bool(reset_state.get("transitions_collapsed")) and bool(reset_state.get("preview_collapsed")) and bool(reset_state.get("logs_collapsed")), "Editing layout is timeline-only with extra panels collapsed")
        timeline_top_state = default_layout_state_for_preset(LAYOUT_PRESET_TIMELINE_TOP)
        check(timeline_top_state.get("right_splitter_sizes", [])[0] > timeline_top_state.get("right_splitter_sizes", [0, 0])[1], "Timeline Top gives the timeline band priority")
        media_top_state = default_layout_state_for_preset(LAYOUT_PRESET_MEDIA_TOP)
        check(media_top_state.get("right_splitter_sizes", [])[0] >= 360 and media_top_state.get("right_splitter_sizes", [0, 0])[1] > media_top_state.get("right_splitter_sizes", [0, 0])[0] and bool(media_top_state.get("logs_collapsed")), "Media Top keeps a useful top media band while giving the timeline default height priority")
        media_top_widths = list(media_top_state.get("preview_left_top_splitter_sizes", []))
        check(len(media_top_widths) == 3 and media_top_widths[2] > media_top_widths[1] and media_top_widths[1] < media_top_widths[0], "Media Top default gives Transitions less width and Preview more width")
        classic_state = default_layout_state_for_preset(LAYOUT_PRESET_CLASSIC)
        check(classic_state.get("layout_preset") == LAYOUT_PRESET_CLASSIC and classic_state.get("main_splitter_sizes", [0])[0] >= 260, "Classic remains available and safe")
        check(not bool(classic_state.get("transitions_collapsed")) and not bool(classic_state.get("media_collapsed")), "Classic opens Media Bin and Transitions together")
        collapsed_transition_state = sanitize_layout_state({"layout_preset": "Media Top", "transitions_collapsed": True})
        check(bool(collapsed_transition_state.get("transitions_collapsed")) and not bool(collapsed_transition_state.get("preview_collapsed")), "transition collapse state stays separate from preview collapse")
        classic_to_media_state = sanitize_layout_state({"layout_preset": "Classic", "logs_collapsed": True})
        media_after_classic_state = sanitize_layout_state({"layout_preset": "Media Top", "logs_collapsed": True})
        check(classic_to_media_state.get("layout_preset") == LAYOUT_PRESET_CLASSIC and media_after_classic_state.get("layout_preset") == LAYOUT_PRESET_MEDIA_TOP, "layout state supports switching from Classic back to Media Top safely")
        check(APP_NAME == "FrameVision Timeline Editor" and "Prototype" not in APP_NAME and "v32" not in APP_NAME, "window title no longer contains old prototype/debug text")
        status_before = {"playing": True, "time": 1.25, "clip_id": "c1"}
        status_after = dict(status_before)
        _ = active_playback_status_text("Playing", status_after["time"], 8.0)
        check(status_before == status_after, "toolbar/status label text generation does not alter timeline/playback state")
        layout_save_payload = timeline_project_save_payload(TimelineProject(), {
            "layout_preset": LAYOUT_PRESET_MEDIA_TOP,
            "main_splitter_sizes": [1, 1200],
            "right_splitter_sizes": [410, 470, 34],
            "preview_qt_active": True,
            "timeline_playback_active": True,
            "hover_time": 9.0,
        })
        saved_editor_state = layout_save_payload.get("editor_state", {})
        check(saved_editor_state.get("layout_preset") == LAYOUT_PRESET_MEDIA_TOP and "timeline_playback_active" not in saved_editor_state and "hover_time" not in saved_editor_state, "layout state does not save active playback state or hover text")
        math_before = {"pixels_per_second": 88.0, "scroll_x": 22.0, "playhead_time": 7.25, "layout_preset": LAYOUT_PRESET_EDITING}
        math_after = sanitize_project_editor_state({**math_before, "layout_preset": LAYOUT_PRESET_TIMELINE_TOP})
        check(abs(float(math_after.get("pixels_per_second")) - 88.0) < 1e-9 and abs(float(math_after.get("scroll_x")) - 22.0) < 1e-9 and abs(float(math_after.get("playhead_time")) - 7.25) < 1e-9, "changing layout does not alter timeline zoom/scroll/playhead math")
        layout_project = TimelineProject(media_items=[MediaItem(name="a", path="a.mp4", media_type="video", duration=5.0)], clips=[Clip(name="c", start=0.0, duration=2.0, media_type="video")], tracks=[TimelineTrack(track_id="t", label="T")])
        layout_project_payload = timeline_project_save_payload(layout_project, {"layout_preset": LAYOUT_PRESET_TIMELINE_TOP})
        layout_loaded = load_timeline_project_payload(layout_project_payload)
        check(len(layout_loaded.project.media_items) == 1 and len(layout_loaded.project.clips) == 1 and len(layout_loaded.project.tracks) == 1, "changing layout does not alter project clips/tracks/media")
        check(layout_loaded.editor_state.get("layout_preset") == LAYOUT_PRESET_TIMELINE_TOP, "layout preset save/load")

        # Better Media Bin metadata and sorting.
        media_bin_video = MediaItem(path="C:/media/source.mp4", name="source.mp4", media_type="video", duration=5.0, display_name="Scene A", favorite=True)
        media_bin_audio = MediaItem(path="C:/media/audio.wav", name="audio.wav", media_type="audio", duration=4.0)
        media_bin_payload = timeline_project_save_payload(TimelineProject(media_items=[media_bin_audio, media_bin_video]), {})
        media_bin_loaded = load_timeline_project_payload(media_bin_payload)
        loaded_items = {item.path: item for item in media_bin_loaded.project.media_items}
        check(media_item_display_name(loaded_items.get("C:/media/source.mp4")) == "Scene A" and media_item_is_favorite(loaded_items.get("C:/media/source.mp4")), "Media Bin display name and favorite save/load")
        legacy_media = MediaItem.from_dict({"path": "C:/media/legacy.png", "name": "legacy.png", "media_type": "image", "duration": 3.0})
        check(media_item_display_name(legacy_media) == "legacy.png" and not media_item_is_favorite(legacy_media), "older media JSON loads without Media Bin polish fields")
        sorted_media = media_bin_sorted_items([media_bin_audio, media_bin_video], "name")
        check(sorted_media and sorted_media[0].path == "C:/media/source.mp4", "Media Bin favorites sort to the top")
        original_path = media_bin_video.path
        changed_display = media_item_set_display_name(media_bin_video, "Renamed only in editor")
        check(changed_display and media_bin_video.path == original_path and media_item_display_name(media_bin_video) == "Renamed only in editor", "Media Bin editor rename does not change the real file path")
        check(media_type_dot_color("video") != media_type_dot_color("audio") and media_type_dot_color(TEXT_MEDIA_TYPE) != media_type_dot_color("image"), "Media Bin media-type colors are distinct")

        # v30 timeline thumbnails and optional waveform display.
        visual_cache_state = sanitize_project_editor_state({"show_timeline_thumbnails": True, "show_timeline_waveforms": True})
        check(bool(visual_cache_state.get("show_timeline_thumbnails")) and bool(visual_cache_state.get("show_timeline_waveforms")), "thumbnail and waveform toggles save/load")
        old_visual_cache_state = sanitize_project_editor_state({})
        check(old_visual_cache_state.get("show_timeline_thumbnails") is False and old_visual_cache_state.get("show_timeline_waveforms") is False, "old settings default visual aids safely")

        cache_video_a = Clip("Cache Video A", 0.0, 5.0, track=0, track_id="v", media_type="video", file_path="C:/media/cache.mp4", in_point=1.0, out_point=6.0)
        cache_video_b = Clip("Cache Video B", 20.0, 5.0, track=0, track_id="v", media_type="video", file_path="C:/media/cache.mp4", in_point=2.0, out_point=7.0)
        cache_audio = Clip("Cache Audio", 0.0, 8.0, track=1, track_id="a", media_type="audio", file_path="C:/media/voice.wav", in_point=3.0, out_point=11.0)
        cache_audio_trimmed = Clip("Cache Audio Trimmed", 0.0, 7.0, track=1, track_id="a", media_type="audio", file_path="C:/media/voice.wav", in_point=4.0, out_point=11.0)
        cache_audio_moved = Clip.from_dict(cache_audio.to_dict())
        cache_audio_moved.start = 42.0
        cache_image = Clip("Cache Image", 0.0, 5.0, track=0, track_id="v", media_type="image", file_path="C:/media/still.png")
        cache_detached = Clip("Detached Cache Audio", 0.0, 5.0, track=1, track_id="a", media_type="audio", file_path="C:/media/source_video.mp4", source_video_clip_id="video1")

        check(thumbnail_cache_key_for_clip(cache_video_a) != thumbnail_cache_key_for_clip(cache_video_b), "thumbnail cache keys include file path and trim/in-point where needed")
        check(waveform_cache_key_for_clip(cache_audio) != waveform_cache_key_for_clip(cache_audio_trimmed), "waveform cache keys include file path and trim/in-point")
        check(not timeline_paint_path_requests_media_generation(), "paint path does not request thumbnail/waveform regeneration directly")
        placeholder = timeline_missing_source_placeholder_info("thumbnail", "Missing Clip")
        check(bool(placeholder.get("placeholder")) and placeholder.get("reason") == "missing source", "missing file returns placeholder safely")
        check(timeline_waveform_cache_invalidated(cache_audio, cache_audio_trimmed), "trim change invalidates relevant waveform cache")
        check(waveform_cache_key_for_clip(cache_audio) == waveform_cache_key_for_clip(cache_audio_moved), "simple clip move does not invalidate waveform cache")
        check(timeline_waveform_cache_preserved_by_clip_move(cache_audio, 99.0), "simple clip move preserves waveform cache helper")
        check(image_thumbnail_uses_image_path(cache_image), "image thumbnail uses image path directly")
        check(clip_waveform_eligible(cache_audio), "audio clip waveform is eligible")
        check(clip_waveform_eligible(cache_detached), "detached audio waveform is eligible")
        check(timeline_thumbnail_display_mode_default() == "start_only", "thumbnail drawing mode is start-only by default")
        short_thumb_area = timeline_thumbnail_area_rect(10.0, 20.0, 38.0, 52.0)
        medium_thumb_area = timeline_thumbnail_area_rect(10.0, 20.0, 180.0, 52.0)
        long_thumb_area = timeline_thumbnail_area_rect(10.0, 20.0, 900.0, 52.0)
        check(not bool(short_thumb_area.get("visible")), "thumbnail area hides safely for very short clips")
        check(bool(medium_thumb_area.get("visible")) and TIMELINE_THUMBNAIL_MIN_WIDTH <= float(medium_thumb_area.get("w") or 0.0) <= TIMELINE_THUMBNAIL_MAX_WIDTH, "thumbnail area width is clamped for normal clips")
        check(float(long_thumb_area.get("w") or 0.0) <= TIMELINE_THUMBNAIL_MAX_WIDTH, "thumbnail area width stays compact on long clips")
        check(20 <= timeline_thumbnail_brighten_alpha() <= 120, "thumbnail paint uses safe brightness overlay")
        check(timeline_thumbnail_border_alpha() >= 80, "thumbnail paint keeps a visible bright border")
        check(timeline_waveform_dimmed_background_enabled(True, [0.2, 0.5]), "waveform-visible mode uses dimmed clip background")
        check(not timeline_waveform_dimmed_background_enabled(True, []), "missing waveform keeps normal clip color")
        check(timeline_waveform_dimmed_rgb(220, 80, 40)[0] < 220, "waveform dimming reduces bright clip colors")
        check(not timeline_waveform_toggle_invalidates_cache(), "waveform toggle does not invalidate cache unnecessarily")
        missing_thumb = timeline_missing_thumbnail_placeholder_info("Missing Clip")
        check(bool(missing_thumb.get("placeholder")) and missing_thumb.get("reason") == "missing thumbnail", "missing thumbnail still returns safe placeholder")
        check(timeline_selected_clip_border_enabled_with_visual_aids(True, True, True), "selected clip border remains enabled when thumbnails/waveform are drawn")
        check(str(timeline_media_cache_dir(Path("C:/FrameVision-main"))).replace("\\", "/").endswith("/temp/timeline_editor_cache"), "cache folder resolves under root/temp/timeline_editor_cache/")
        visual_cache_project = TimelineProject(media_items=[], clips=[cache_video_a], tracks=[TimelineTrack("v", "Video")])
        visual_cache_payload = timeline_project_save_payload(visual_cache_project, {"show_timeline_thumbnails": True, "show_timeline_waveforms": True, "preview_zoom": 5.0})
        visual_cache_loaded = load_timeline_project_payload(visual_cache_payload)
        check(bool(visual_cache_loaded.editor_state.get("show_timeline_thumbnails")) and bool(visual_cache_loaded.editor_state.get("show_timeline_waveforms")), "project save/load stores thumbnail/waveform toggles")
        check(visual_cache_loaded.editor_state.get("preview_zoom") == 1.0, "project save/load does not corrupt transient preview viewer state")

        # v31 project actions bar + New Project safety helpers.
        dirty_project = TimelineProject()
        dirty_media = dirty_project.add_media_item(MediaItem(path="C:/media/dirty.mp4", name="dirty.mp4", media_type="video", duration=4.0))
        clean_state = timeline_project_edit_state(dirty_project)
        dirty_project.add_clip_from_media(dirty_media.media_id, 0.0, track=1, snap=False)
        changed_state = timeline_project_edit_state(dirty_project)
        check(project_dirty_after_clean_state(clean_state, changed_state), "dirty state becomes true after a project edit")
        check(not project_dirty_after_clean_state(changed_state, changed_state), "save/clean state clears dirty state")
        check(project_window_title("Editor", True).endswith("*") and project_window_title("Editor", False) == "Editor", "dirty state is shown lightly in the window title")

        preserved_ui_state = {
            "layout_preset": LAYOUT_PRESET_MEDIA_TOP,
            "main_splitter_sizes": [1, 1200],
            "right_splitter_sizes": [360, 520, 34],
            "media_collapsed": True,
            "preview_collapsed": True,
            "logs_collapsed": True,
            "show_timeline_thumbnails": True,
            "show_timeline_waveforms": True,
            "master_volume": 77.0,
            "scroll_x": 123.0,
            "playhead_time": 9.5,
            "selected_clip_id": "old_clip",
            "selected_media_id": "old_media",
            "preview_qt_active": True,
            "timeline_playback_active": True,
        }
        new_state = new_project_editor_state_preserving_ui(preserved_ui_state)
        check(float(new_state.get("playhead_time") or 0.0) == 0.0 and float(new_state.get("scroll_x") or 0.0) == 0.0, "New Project reset returns playhead and scroll to zero")
        check(str(new_state.get("selected_clip_id") or "") == "" and str(new_state.get("selected_media_id") or "") == "", "New Project clears saved preview/selection state")
        check(new_state.get("layout_preset") == LAYOUT_PRESET_EDITING and bool(new_state.get("media_collapsed")) and bool(new_state.get("show_timeline_thumbnails")), "New Project does not wipe UI layout or visual-aid preferences")
        check("preview_qt_active" not in new_state and "timeline_playback_active" not in new_state, "New Project does not preserve transient playback state")

        # v32 PNG mask transition engine foundation.
        with tempfile.TemporaryDirectory() as tmp_transition_root:
            tmp_root = Path(tmp_transition_root)
            transition_folder = transition_assets_dir(tmp_root)
            check(str(transition_folder).replace("\\", "/").endswith("/assets/transitions"), "transition folder path resolves to root/assets/transitions/")
            missing_scan = scan_transition_mask_assets(tmp_root, create_missing=False)
            check(missing_scan == [], "missing transition folder fails safely")
            created_scan = scan_transition_mask_assets(tmp_root, create_missing=True)
            check(created_scan == [] and transition_folder.exists(), "missing transition folder is created safely")
            (transition_folder / "circle_wipe.png").write_bytes(b"not a real png for scanner test")
            (transition_folder / "diagonal-soft.jpg").write_bytes(b"jpg")
            (transition_folder / "ignore.txt").write_text("x", encoding="utf-8")
            masks = scan_transition_mask_assets(tmp_root, create_missing=False)
            check(len(masks) == 2 and masks[0]["name"].lower().endswith((".jpg", ".png")), "transition mask scanner finds PNG/JPG files")
            check(transition_display_name_from_filename("circle_wipe.png") == "Circle Wipe", "transition display name is generated from filename")

        v32_tracks = [TimelineTrack(track_id="v", label="Video"), TimelineTrack(track_id="a", label="Audio")]
        out_clip = Clip("Out Video", 0.0, 2.0, track=0, track_id="v", clip_id="out", media_type="video", file_path="C:/media/out.mp4")
        in_clip = Clip("In Image", 2.0, 2.0, track=0, track_id="v", clip_id="in", media_type="image", file_path="C:/media/in.png")
        audio_clip = Clip("Audio", 2.0, 2.0, track=1, track_id="a", clip_id="aud", media_type="audio", file_path="C:/media/a.wav")
        transition_project = TimelineProject(clips=[out_clip, in_clip, audio_clip], tracks=v32_tracks)
        old_transition_payload = timeline_project_save_payload(TimelineProject(clips=[out_clip], tracks=[TimelineTrack(track_id="v", label="Video")]), {})
        old_transition_payload.pop("transitions", None)
        old_loaded = load_timeline_project_payload(old_transition_payload)
        check(getattr(old_loaded.project, "transitions", []) == [], "old project JSON loads with empty transitions")

        ok_add, add_message, added_transition = transition_project.add_mask_transition_to_next_clip("out", "C:/FrameVision-main/assets/transitions/circle_wipe.png", 1.0, "circle_wipe.png")
        check(ok_add and added_transition is not None and len(transition_project.transitions) == 1, "add transition between two touching visual clips")
        check(added_transition is not None and added_transition.mask_name == "circle_wipe.png", "transition metadata stores mask name")
        transition_payload = timeline_project_save_payload(transition_project, {})
        transition_loaded = load_timeline_project_payload(transition_payload)
        check(len(transition_loaded.project.transitions) == 1 and transition_loaded.project.transitions[0].mask_name == "circle_wipe.png", "save/load preserves transition metadata")
        missing_mask_payload = json.loads(json.dumps(transition_payload))
        missing_mask_payload["transitions"][0]["mask_path"] = "C:/missing/nope.png"
        missing_loaded = load_timeline_project_payload(missing_mask_payload)
        check(len(missing_loaded.project.transitions) == 1, "missing saved transition mask does not crash")

        audio_same_track = Clip("Audio", 2.0, 2.0, track=0, track_id="v", clip_id="aud_same", media_type="audio", file_path="C:/media/a.wav")
        bad_project = TimelineProject(clips=[out_clip, audio_same_track], tracks=v32_tracks)
        ok_bad, bad_message, _bad_transition = bad_project.add_mask_transition_to_next_clip("out", "mask.png", 1.0, "mask.png")
        check((not ok_bad) and "eligible" in bad_message.lower(), "reject transition between visual and audio clip")

        locked_tracks = [TimelineTrack(track_id="v", label="Video", locked=True)]
        locked_project = TimelineProject(clips=[Clip("A", 0.0, 2.0, track=0, track_id="v", clip_id="la", media_type="video"), Clip("B", 2.0, 2.0, track=0, track_id="v", clip_id="lb", media_type="image")], tracks=locked_tracks)
        ok_locked, locked_message, _locked_transition = locked_project.add_mask_transition_to_next_clip("la", "mask.png", 1.0, "mask.png")
        check((not ok_locked) and "locked" in locked_message.lower(), "reject transition on locked track")

        gap_project = TimelineProject(clips=[Clip("A", 0.0, 2.0, track=0, track_id="v", clip_id="ga", media_type="video"), Clip("B", 3.0, 2.0, track=0, track_id="v", clip_id="gb", media_type="image")], tracks=[TimelineTrack(track_id="v", label="Video")])
        ok_gap, gap_message, _gap_transition = gap_project.add_mask_transition_to_next_clip("ga", "mask.png", 1.0, "mask.png")
        check((not ok_gap) and "touching" in gap_message.lower(), "reject transition when clips have a large gap")

        clamp_project = TimelineProject(clips=[Clip("A", 0.0, 0.4, track=0, track_id="v", clip_id="ca", media_type="video"), Clip("B", 0.4, 5.0, track=0, track_id="v", clip_id="cb", media_type="image")], tracks=[TimelineTrack(track_id="v", label="Video")])
        ok_clamp, clamp_message, clamp_transition = clamp_project.add_mask_transition_to_next_clip("ca", "mask.png", 5.0, "mask.png")
        check(ok_clamp and clamp_transition is not None and clamp_transition.duration <= 0.4 + 1e-9 and "clamped" in clamp_message.lower(), "clamp transition duration to available clip durations")

        overlap_project = TimelineProject(clips=[Clip("A", 0.0, 3.0, track=0, track_id="v", clip_id="oa", media_type="video"), Clip("B", 2.25, 2.0, track=0, track_id="v", clip_id="ob", media_type="image")], tracks=[TimelineTrack(track_id="v", label="Video")])
        ok_overlap, _overlap_message, overlap_transition = overlap_project.add_mask_transition_to_next_clip("oa", "mask.png", 1.0, "mask.png")
        check(ok_overlap and overlap_transition is not None and abs(overlap_transition.duration - 0.75) < 1e-9 and getattr(overlap_transition, "placement_mode", "") == "overlap", "overlap transition duration comes from clip overlap")
        check(overlap_transition is not None and abs(transition_time_window(overlap_transition)[0] - 2.25) < 1e-9 and abs(transition_time_window(overlap_transition)[1] - 3.0) < 1e-9, "overlap transition time window matches overlap area")
        check(transition_preview_state(overlap_project, 2.0) is None, "active transition lookup before transition returns none")
        overlap_state_mid = transition_preview_state(overlap_project, 2.625)
        check(overlap_state_mid is not None and abs(float(overlap_state_mid.get("progress") or 0.0) - 0.5) < 1e-6, "active transition lookup inside transition returns progress")
        check(transition_preview_state(overlap_project, 3.1) is None, "active transition lookup after transition returns none")
        check(abs((transition_progress_at_time(overlap_transition, 2.25) if overlap_transition else -1.0) - 0.0) < 1e-6, "transition progress at start is zero")
        check(abs((transition_progress_at_time(overlap_transition, 3.0) if overlap_transition else -1.0) - 1.0) < 1e-6, "transition progress at end is one")
        check(transition_mask_threshold_alpha_value(0, 0.0) == 0 and transition_mask_threshold_alpha_value(255, 0.0) == 0, "mask threshold progress 0 returns outgoing")
        check(transition_mask_threshold_alpha_value(0, 1.0) == 255 and transition_mask_threshold_alpha_value(255, 1.0) == 255, "mask threshold progress 1 returns incoming")
        check(transition_mask_threshold_alpha_value(0, 0.5) == 255 and transition_mask_threshold_alpha_value(255, 0.5) == 0, "mask threshold progress 0.5 creates mixed mask")
        check(transition_mask_threshold_alpha_value(0, 0.5, invert=True) == 0 and transition_mask_threshold_alpha_value(255, 0.5, invert=True) == 255, "invert changes mask reveal direction")
        info = transition_info_data(overlap_project, overlap_transition) if overlap_transition else {}
        check(info.get("outgoing") == "A" and info.get("incoming") == "B" and abs(float(info.get("duration") or 0.0) - 0.75) < 1e-9, "transition info data can be generated without GUI")
        held_clip = transition_visual_hold_clip_at_time(overlap_project, 2.5)
        check(held_clip is None, "overlap preview no longer blocks incoming clip playback")
        visual_during_overlap = timeline_visual_playback_plan_under_playhead(overlap_project, 2.5)
        check(bool(visual_during_overlap.get("ok")) and visual_during_overlap.get("clip_id") == "ob", "overlap playback starts incoming clip during transition so video/audio can be active")
        visual_after_overlap = timeline_visual_playback_plan_under_playhead(overlap_project, 3.01)
        check(bool(visual_after_overlap.get("ok")) and visual_after_overlap.get("clip_id") == "ob", "overlap playback stays on incoming clip after transition window")

        # v32/17c transition audio overlap: audio must follow timeline overlap,
        # not the visual transition switch.
        audio_out = Clip("Audio Out", 0.0, 4.0, track=0, track_id="v", clip_id="aud_out", media_type="video", file_path="C:/media/aud_out.mp4", in_point=1.0)
        audio_in = Clip("Audio In", 3.0, 4.0, track=0, track_id="v", clip_id="aud_in", media_type="video", file_path="C:/media/aud_in.mp4", in_point=5.0)
        audio_overlap_project = TimelineProject(clips=[audio_out, audio_in], tracks=[TimelineTrack(track_id="v", label="Video")])
        ok_audio_transition, _audio_message, audio_transition = audio_overlap_project.add_mask_transition_to_next_clip("aud_out", "mask.png", 1.0, "mask.png")
        check(ok_audio_transition and audio_transition is not None, "transition audio overlap test project builds")
        transition_audio_ids = transition_audio_overlap_clip_ids(audio_overlap_project, 3.5, AUDIO_MODE_MIX_ALL)
        check(transition_audio_ids == ["aud_out", "aud_in"], "transition audio overlap exposes outgoing and incoming video clips")
        mix_sources_mid = timeline_audio_mix_sources(audio_overlap_project, 3.5, AUDIO_MODE_MIX_ALL, active_visual_clip=audio_in)
        mix_ids_mid = [str(source.get("clip_id") or "") for source in mix_sources_mid]
        check("aud_out" in mix_ids_mid and "aud_in" in mix_ids_mid, "outgoing audio remains active after transition start")
        check(timeline_audio_source_start_for_clip(audio_out, 3.5) is not None, "outgoing audio stops at clip end, not transition start")
        check(abs(float(timeline_audio_source_start_for_clip(audio_in, 3.0) or 0.0) - 5.0) < 1e-9, "incoming audio starts at its own clip start")
        mix_sources_after = timeline_audio_mix_sources(audio_overlap_project, 4.01, AUDIO_MODE_MIX_ALL, active_visual_clip=audio_in)
        mix_ids_after = [str(source.get("clip_id") or "") for source in mix_sources_after]
        check("aud_out" not in mix_ids_after and "aud_in" in mix_ids_after, "outgoing audio stops at clip end, not transition start")
        video_only_sources_mid = timeline_audio_mix_sources(audio_overlap_project, 3.5, AUDIO_MODE_VIDEO, active_visual_clip=audio_in)
        check({str(source.get("clip_id") or "") for source in video_only_sources_mid} == {"aud_out", "aud_in"}, "Video-only transition overlap can mix both video audio sources")
        muted_out_project = TimelineProject(clips=[Clip("Muted Out", 0.0, 4.0, track=0, track_id="v", clip_id="mut_out", media_type="video", file_path="C:/media/mut_out.mp4", audio_enabled=False), Clip("Live In", 3.0, 4.0, track=0, track_id="v", clip_id="live_in", media_type="video", file_path="C:/media/live_in.mp4")], tracks=[TimelineTrack(track_id="v", label="Video")])
        muted_out_project.add_mask_transition_to_next_clip("mut_out", "mask.png", 1.0, "mask.png")
        muted_out_ids = [str(source.get("clip_id") or "") for source in timeline_audio_mix_sources(muted_out_project, 3.5, AUDIO_MODE_MIX_ALL)]
        check("mut_out" not in muted_out_ids and "live_in" in muted_out_ids, "muted outgoing audio does not play")
        muted_in_project = TimelineProject(clips=[Clip("Live Out", 0.0, 4.0, track=0, track_id="v", clip_id="live_out", media_type="video", file_path="C:/media/live_out.mp4"), Clip("Muted In", 3.0, 4.0, track=0, track_id="v", clip_id="mut_in", media_type="video", file_path="C:/media/mut_in.mp4", audio_enabled=False)], tracks=[TimelineTrack(track_id="v", label="Video")])
        muted_in_project.add_mask_transition_to_next_clip("live_out", "mask.png", 1.0, "mask.png")
        muted_in_ids = [str(source.get("clip_id") or "") for source in timeline_audio_mix_sources(muted_in_project, 3.5, AUDIO_MODE_MIX_ALL)]
        check("live_out" in muted_in_ids and "mut_in" not in muted_in_ids, "muted incoming audio does not play")
        runtime_same = audio_mix_runtime_policy(mix_ids_mid, mix_sources_mid, force_seek=False, should_play=True)
        check(not runtime_same.get("start_clip_ids") and not runtime_same.get("stop_clip_ids") and set(runtime_same.get("keep_clip_ids") or []) == {"aud_out", "aud_in"}, "transition audio overlap does not create duplicate audio players")
        runtime_seek = audio_mix_runtime_policy(mix_ids_mid, mix_sources_mid, force_seek=True, should_play=True)
        check(not runtime_seek.get("start_clip_ids") and not runtime_seek.get("stop_clip_ids") and set(runtime_seek.get("seek_clip_ids") or []) == {"aud_out", "aud_in"}, "seeking inside transition does not create duplicate audio players")
        runtime_pause = audio_mix_runtime_policy(mix_ids_mid, mix_sources_mid, force_seek=True, should_play=False)
        check(runtime_pause.get("should_play") is False and set(runtime_pause.get("seek_clip_ids") or []) == {"aud_out", "aud_in"}, "pause/resume keeps transition overlap audio position correct")

        # v32/16 transition authority cleanup: badge, preview, and active lookup
        # must read the same central timing data.
        overlap_authority = transition_authority_state(overlap_project, overlap_transition, 2.625) if overlap_transition else {}
        check(bool(overlap_authority.get("ok")) and abs(float(overlap_authority.get("effective_duration") or 0.0) - 0.75) < 1e-9, "auto transition effective duration equals overlap when no manual duration is set")
        check(abs(transition_effective_duration_for_project(overlap_project, overlap_transition) - float(overlap_state_mid.get("effective_duration") or 0.0)) < 1e-9, "badge duration equals preview duration")
        authority_start = float(overlap_authority.get("start") or 0.0)
        authority_end = float(overlap_authority.get("end") or 0.0)
        check(abs((transition_progress_at_time_for_project(overlap_project, overlap_transition, authority_end) or 0.0) - 1.0) < 1e-6, "progress reaches 1.0 at effective transition end")
        p0 = transition_progress_at_time_for_project(overlap_project, overlap_transition, authority_start) or 0.0
        p1 = transition_progress_at_time_for_project(overlap_project, overlap_transition, (authority_start + authority_end) / 2.0) or 0.0
        p2 = transition_progress_at_time_for_project(overlap_project, overlap_transition, authority_end) or 0.0
        check(p0 <= p1 <= p2 and abs(p0) < 1e-6 and abs(p2 - 1.0) < 1e-6, "progress does not reset during active transition")

        manual_overlap_project = TimelineProject(clips=[Clip("A", 0.0, 10.0, track=0, track_id="v", clip_id="ma", media_type="video"), Clip("B", 4.0, 10.0, track=0, track_id="v", clip_id="mb", media_type="image")], tracks=[TimelineTrack(track_id="v", label="Video")])
        ok_manual_auto, _manual_auto_message, manual_transition = manual_overlap_project.add_mask_transition_to_next_clip("ma", "mask.png", 1.0, "mask.png")
        check(ok_manual_auto and manual_transition is not None and getattr(manual_transition, "placement_mode", "") == "overlap" and abs(transition_effective_duration_for_project(manual_overlap_project, manual_transition) - 6.0) < 1e-9, "v32/18 manual-only regression does not return")
        ok_set_manual, _set_manual_message = manual_overlap_project.set_transition_duration(manual_transition.transition_id, 2.0)
        manual_authority = transition_authority_state(manual_overlap_project, manual_transition, 7.0)
        check(ok_set_manual and getattr(manual_transition, "placement_mode", "") == "manual" and abs(float(manual_authority.get("effective_duration") or 0.0) - 2.0) < 1e-9, "manual duration applies only when explicitly set")
        ok_clamp_manual, _clamp_manual_message = manual_overlap_project.set_transition_duration(manual_transition.transition_id, 99.0)
        clamped_manual_authority = transition_authority_state(manual_overlap_project, manual_transition, 7.0)
        check(ok_clamp_manual and abs(float(clamped_manual_authority.get("effective_duration") or 0.0) - 6.0) < 1e-9, "manual duration clamps to overlap")

        autosize_project = TimelineProject(clips=[Clip("A", 0.0, 5.0, track=0, track_id="v", clip_id="asa", media_type="video"), Clip("B", 6.0, 3.0, track=0, track_id="v", clip_id="asb", media_type="image")], tracks=[TimelineTrack(track_id="v", label="Video")])
        autosize_project.move_clip("asb", 3.25, new_track=0, snap=False)
        auto_changed, _auto_messages = autosize_project.sync_overlap_transitions_for_clip("asb", "mask.png", "mask.png", create_missing=True)
        auto_transition = autosize_project.transitions[0] if autosize_project.transitions else None
        check(auto_changed and auto_transition is not None and getattr(auto_transition, "placement_mode", "") == "overlap" and abs(transition_effective_duration_for_project(autosize_project, auto_transition) - 1.75) < 1e-9, "moving two clips together still auto-sizes the transition")

        # v32/7 transition preview source-time plan. The compositor must be
        # driven by current timeline time, not by one frozen frame captured when
        # the transition starts.
        vv_out = Clip("VV Out", 0.0, 4.0, track=0, track_id="v", clip_id="vv_out", media_type="video", file_path="C:/media/vv_out.mp4")
        vv_in = Clip("VV In", 3.0, 4.0, track=0, track_id="v", clip_id="vv_in", media_type="video", file_path="C:/media/vv_in.mp4", in_point=5.0)
        vv_project = TimelineProject(clips=[vv_out, vv_in], tracks=[TimelineTrack(track_id="v", label="Video")])
        ok_vv, _msg_vv, vv_transition = vv_project.add_mask_transition_to_next_clip("vv_out", "mask.png", 1.0, "mask.png")
        check(ok_vv and vv_transition is not None, "video → video transition test project builds")
        vv_start = transition_frame_plan(vv_project, 3.0)
        vv_mid = transition_frame_plan(vv_project, 3.5)
        vv_end = transition_frame_plan(vv_project, 4.0)
        check(vv_start is not None and vv_mid is not None and vv_end is not None, "transition frame plan is available at start/middle/end")
        check(abs(float(vv_mid.get("outgoing_source_time") or 0.0) - float(vv_start.get("outgoing_source_time") or 0.0)) > 0.1, "outgoing source_time changes as timeline_time advances during transition")
        check(abs(float(vv_mid.get("incoming_source_time") or 0.0) - float(vv_start.get("incoming_source_time") or 0.0)) > 0.1, "incoming source_time changes as timeline_time advances during transition")
        check(abs(float(vv_mid.get("incoming_source_time") or 0.0) - 5.5) < 1e-6, "incoming source_time respects clip in_point")
        check(float(vv_start.get("outgoing_source_time") or -1.0) != float(vv_mid.get("outgoing_source_time") or -1.0) != float(vv_end.get("outgoing_source_time") or -1.0), "transition frame plan at t=start/middle/end returns different outgoing source times for video")
        check(not bool(vv_mid.get("outgoing_static")) and bool(vv_mid.get("outgoing_requires_time_sample")), "video outgoing is not treated as static by transition plan")
        check(abs(float(vv_mid.get("outgoing_source_time") or 0.0) - float(transition_frame_plan(vv_project, 3.5).get("outgoing_source_time") or 0.0)) < 1e-9, "transition frame plan uses current timeline_time, not transition-enter time")

        speed_out = Clip("Speed Out", 0.0, 4.0, track=0, track_id="v", clip_id="speed_out", media_type="video", file_path="C:/media/speed_out.mp4", speed=2.0)
        speed_in = Clip("Speed In", 3.0, 4.0, track=0, track_id="v", clip_id="speed_in", media_type="video", file_path="C:/media/speed_in.mp4")
        speed_project = TimelineProject(clips=[speed_out, speed_in], tracks=[TimelineTrack(track_id="v", label="Video")])
        speed_project.add_mask_transition_to_next_clip("speed_out", "mask.png", 1.0, "mask.png")
        speed_plan = transition_frame_plan(speed_project, 3.5)
        check(speed_plan is not None and abs(float(speed_plan.get("outgoing_source_time") or 0.0) - 7.0) < 1e-6, "outgoing source_time respects clip speed")

        image_video_project = TimelineProject(clips=[Clip("Still Out", 0.0, 4.0, track=0, track_id="v", clip_id="still_out", media_type="image", file_path="C:/media/still.png"), Clip("Moving In", 3.0, 4.0, track=0, track_id="v", clip_id="moving_in", media_type="video", file_path="C:/media/moving.mp4")], tracks=[TimelineTrack(track_id="v", label="Video")])
