        check(bool(fallback_in.get("fallback")) and fallback_in.get("log_message") == "Transition fallback: incoming frame cached", "fallback is explicitly marked when an incoming current frame cannot be retrieved")

        mono_first = transition_monotonic_frame_decision(None, 1.0, True)
