        check(bool(mono_first.get("accept")) and bool(mono_forward.get("accept")), "outgoing cached frame time never goes backward during forward playback")
        check(bool(mono_forward.get("accept")), "incoming cached frame time never goes backward during forward playback")
        check(bool(mono_stale.get("stale")) and bool(mono_stale.get("hold_last")) and not bool(mono_stale.get("accept")), "older nearest frame is rejected when a newer frame was already displayed")
        check(bool(mono_stale.get("hold_last")), "last displayed frame is held when only stale frames are available")
        check(bool(mono_seek.get("accept")) and not bool(mono_seek.get("stale")), "monotonic state resets on seek")
        check(bool(transition_monotonic_frame_decision(None, 0.5, True).get("accept")), "monotonic state resets when transition changes")
        check(bool(mono_seek.get("accept")), "seeking into a transition can still display nearest frame")
        check(bool(mono_tolerated.get("accept")), "transition-start fallback is replaced when newer frame arrives")

