        auto_overlap_project = TimelineProject(clips=[Clip("A", 0.0, 3.0, track=0, track_id="v", clip_id="aa", media_type="video"), Clip("B", 4.0, 2.0, track=0, track_id="v", clip_id="ab", media_type="image")], tracks=[TimelineTrack(track_id="v", label="Video")])
