    class TimelineExportDialog(QDialog):
        def __init__(self, parent: Optional[QWidget] = None, *, default_path: str = "") -> None:
            super().__init__(parent)
            self.setWindowTitle("Export Timeline Video")
            self.setMinimumWidth(560)
            self.setWindowModality(Qt.WindowModality.ApplicationModal)
            self._export_running = False
            self._export_finished = False
            self._last_progress = 0

            layout = QVBoxLayout(self)
            info = QLabel("First real exporter: full timeline duration, MP4/libx264/AAC defaults.", self)
            info.setWordWrap(True)
            layout.addWidget(info)

            self._settings_widgets: List[QWidget] = []

            row_path = QHBoxLayout()
            self.output_edit = QLineEdit(self)
            self.output_edit.setText(str(default_path or default_timeline_export_output_path(framevision_root())))
            self.browse_btn = QPushButton("Browse...", self)
            self.browse_btn.clicked.connect(self._browse_output)
            row_path.addWidget(QLabel("Output:", self))
            row_path.addWidget(self.output_edit, 1)
            row_path.addWidget(self.browse_btn)
            layout.addLayout(row_path)
