            self.rotation_spin.setDecimals(2)
            self.rotation_spin.setSingleStep(1.0)
            self.rotation_spin.setSuffix("°")
            rotation_row = QWidget(self)
            rotation_layout = QHBoxLayout(rotation_row)
            rotation_layout.setContentsMargins(0, 0, 0, 0)
            rotation_layout.setSpacing(8)
            rotation_layout.addWidget(QLabel("Static rotation", rotation_row))
            rotation_layout.addWidget(self.rotation_spin)
            rotation_layout.addStretch(1)
            layout.addWidget(rotation_row)

            self.reveal_combo = QComboBox(self)
