                mirror_y_action = mirror_menu.addAction("Mirror vertical" + (" ✓" if clip_mirror_y_value(clip) else ""))
                mirror_both_action = mirror_menu.addAction("Mirror both")
                mirror_reset_action = mirror_menu.addAction("Reset mirror")
                mirror_reset_action.setEnabled(clip_has_mirror(clip))
                transform_menu.addSeparator()
                reset_transform_action = transform_menu.addAction("Reset transform on selected clip(s)")
                rotate_90_action = transform_menu.addAction("Rotate selected 90°")
                rotate_180_action = transform_menu.addAction("Rotate selected 180°")
