            self.transition_thumbnail_cache: Dict[str, Tuple[float, QPixmap]] = {}
            self.text_overlay_pixmap_cache: Dict[str, Tuple[float, QPixmap]] = {}
            self.text_overlay_bounds_cache: Dict[str, Tuple[float, QRect]] = {}
            self.active_transition_mask_path: str = ""
