        def open_editor_help(self) -> None:
            """Open the standalone Timeline Editor help window."""
            try:
                try:
                    from editor_help import show_timeline_editor_help
                except Exception:
                    from helpers.editor_help import show_timeline_editor_help  # type: ignore
                self._timeline_editor_help_window = show_timeline_editor_help(self)
            except Exception as exc:
                QMessageBox.warning(self, "Timeline Editor Help", f"Could not open the help window:\n\n{exc}")

        def _font_size_slider_value_changed(self, value: int) -> None:
            size = sanitize_editor_font_size(value)
            if hasattr(self, "font_size_value_label"):
                self.font_size_value_label.setText(str(size))

        def _font_size_slider_released(self) -> None:
            size = sanitize_editor_font_size(self.font_size_slider.value() if hasattr(self, "font_size_slider") else getattr(self, "editor_font_size", DEFAULT_EDITOR_FONT_SIZE))
            self._apply_editor_font_size(size, save=True, update_control=True)

        def _refresh_font_size_control(self) -> None:
            if not hasattr(self, "font_size_slider"):
                return
            size = sanitize_editor_font_size(getattr(self, "editor_font_size", DEFAULT_EDITOR_FONT_SIZE))
            self.font_size_slider.blockSignals(True)
            self.font_size_slider.setValue(size)
            self.font_size_slider.blockSignals(False)
            if hasattr(self, "font_size_value_label"):
                self.font_size_value_label.setText(str(size))

        def _apply_editor_font_size(self, size: Any, save: bool = False, update_control: bool = True) -> None:
            size = sanitize_editor_font_size(size)
            self.editor_font_size = size
            app = QApplication.instance()
            try:
                target_font = app.font() if app is not None else self.font()
                target_font.setPointSize(size)
                if app is not None:
                    app.setFont(target_font)
                # Update existing widgets too; layout panels are reparented often.
                if isinstance(self, QWidget):
                    self.setFont(target_font)
                    for child in self.findChildren(QWidget):
                        child.setFont(target_font)
                        child.updateGeometry()
                self.updateGeometry()
            except Exception:
                pass
            if update_control:
                self._refresh_font_size_control()
            try:
                self.update_scrollbar()
                self.update_labels()
                if hasattr(self, "canvas"):
                    self.canvas.updateGeometry()
                    self.canvas.update()
            except Exception:
                pass
            if save and not getattr(self, "_loading_settings", False):
                self.save_editor_state()

        def _refresh_canvas_label(self) -> None:
            if hasattr(self, "canvas_size_label"):
                try:
                    self.project.canvas_width, self.project.canvas_height = normalize_project_canvas_size(
                        getattr(self.project, "canvas_width", DEFAULT_PROJECT_CANVAS_WIDTH),
                        getattr(self.project, "canvas_height", DEFAULT_PROJECT_CANVAS_HEIGHT),
                    )
                    label = f"Canvas: {project_canvas_label(self.project.canvas_width, self.project.canvas_height)}"
                    self.canvas_size_label.setText(label)
                    self.canvas_size_label.setToolTip(
                        f"Project canvas / final composition size ({project_canvas_aspect_label(self.project.canvas_width, self.project.canvas_height)})"
                    )
                except Exception:
                    self.canvas_size_label.setText("Canvas: 1280x720")

        def _refresh_preview_quality_combo(self) -> None:
            if not hasattr(self, "preview_quality_combo"):
                return
            quality = normalize_preview_quality(getattr(self, "preview_quality", DEFAULT_PREVIEW_QUALITY))
            self.preview_quality_combo.blockSignals(True)
            try:
                for index in range(self.preview_quality_combo.count()):
                    if normalize_preview_quality(self.preview_quality_combo.itemData(index)) == quality:
                        self.preview_quality_combo.setCurrentIndex(index)
                        break
            finally:
                self.preview_quality_combo.blockSignals(False)

        def _preview_quality_combo_changed(self) -> None:
            if not hasattr(self, "preview_quality_combo"):
                return
            quality = normalize_preview_quality(self.preview_quality_combo.currentData())
            if quality == getattr(self, "preview_quality", DEFAULT_PREVIEW_QUALITY):
                return
            self.preview_quality = quality
            plan = project_canvas_preview_plan(self.project, self.preview_quality)
            self.log(f"Preview quality set: {preview_quality_label(quality)}")
            self.log(f"Preview composite target: {plan['preview_width']}x{plan['preview_height']}")
            self.save_editor_state()
            self._clear_transition_render_caches()
            self._refresh_preview_pixmap()

        def project_canvas_size(self) -> Tuple[int, int]:
            self.project.canvas_width, self.project.canvas_height = normalize_project_canvas_size(
                getattr(self.project, "canvas_width", DEFAULT_PROJECT_CANVAS_WIDTH),
                getattr(self.project, "canvas_height", DEFAULT_PROJECT_CANVAS_HEIGHT),
            )
            return int(self.project.canvas_width), int(self.project.canvas_height)

        def preview_composite_target_size(self) -> Tuple[int, int]:
            cw, ch = self.project_canvas_size()
            return preview_quality_target_size(cw, ch, getattr(self, "preview_quality", DEFAULT_PREVIEW_QUALITY))

        def _clear_transition_render_caches(self) -> None:
            for name in (
                "_transition_scaled_gray_cache",
                "_transition_alpha_cache",
                "_transition_composite_cache",
                "_transition_canvas_cache",
            ):
                cache = getattr(self, name, None)
                if isinstance(cache, dict):
                    cache.clear()

        def open_project_settings_dialog(self) -> None:
            cw, ch = self.project_canvas_size()
            preset_labels = [name for name, _w, _h in PROJECT_CANVAS_PRESETS] + ["Custom..."]
            current = project_canvas_label(cw, ch)
            current_index = preset_labels.index(current) if current in preset_labels else len(preset_labels) - 1
            choice, ok = QInputDialog.getItem(self, "Project Settings", "Canvas preset:", preset_labels, current_index, False)
            if not ok:
                return
            if str(choice) == "Custom...":
                text, ok = QInputDialog.getText(self, "Custom Canvas", "Canvas size (WIDTHxHEIGHT):", text=current)
                if not ok:
                    return
                match = re.match(r"^\s*(\d+)\s*[xX, ]\s*(\d+)\s*$", str(text or ""))
                if not match:
                    self.log("Project canvas change skipped: invalid custom size.")
                    return
                width, height = int(match.group(1)), int(match.group(2))
            else:
                width, height = next((w, h) for name, w, h in PROJECT_CANVAS_PRESETS if name == str(choice))
            self.set_project_canvas_size(width, height, push_undo=True)

        def set_project_canvas_size(self, width: Any, height: Any, push_undo: bool = True) -> bool:
            new_w, new_h = normalize_project_canvas_size(width, height)
            old_w, old_h = self.project_canvas_size()
            if (new_w, new_h) == (old_w, old_h):
                self._refresh_canvas_label()
                return False
            if push_undo:
                self._begin_project_edit("project canvas")
            self.project.canvas_width = new_w
            self.project.canvas_height = new_h
            self.project.normalize_tracks_and_clips()
            self._refresh_canvas_label()
            self._clear_transition_render_caches()
            self._refresh_preview_pixmap()
            if push_undo:
                self._commit_project_edit("project canvas")
            self.save_editor_state()
            self.log(f"Project canvas set: {new_w}x{new_h}")
            return True

        def _make_section_header(self, title_text: str, button_text: str) -> Tuple[QWidget, QLabel, QPushButton]:
            header = QWidget(self)
            layout = QHBoxLayout(header)
            layout.setContentsMargins(0, 0, 0, 0)
            layout.setSpacing(6)

            button = QPushButton(button_text)
            button.setFixedWidth(28)
            button.setToolTip(f"Collapse/expand {title_text}")
            label = QLabel(title_text)
            label.setStyleSheet("font-weight: bold; font-size: 13px;")
            layout.addWidget(button)
            layout.addWidget(label)
            layout.addStretch(1)
            return header, label, button

        def _build_media_panel(self) -> QWidget:
            panel = QWidget(self)
            panel.setMinimumWidth(220)
            panel.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
            layout = QVBoxLayout(panel)
            layout.setContentsMargins(0, 0, 0, 0)
            layout.setSpacing(6)

            header, self.media_title_label, self.media_collapse_btn = self._make_section_header("Media Bin", "▲")
            self.media_collapse_btn.clicked.connect(self.toggle_media_panel)
            layout.addWidget(header)

            self.media_button_row_widget = QWidget(panel)
            btn_row = QHBoxLayout(self.media_button_row_widget)
            btn_row.setContentsMargins(0, 0, 0, 0)
            btn_row.setSpacing(6)
            btn_add = QPushButton("Add Media")
            btn_remove = QPushButton("Remove")
            btn_to_timeline = QPushButton("Add")
            btn_add.clicked.connect(self.add_media_dialog)
            btn_remove.clicked.connect(self.remove_selected_media)
            btn_to_timeline.clicked.connect(self.add_selected_media_to_timeline)
            btn_row.addWidget(btn_add)
            btn_row.addWidget(btn_remove)
            btn_row.addWidget(btn_to_timeline)
            layout.addWidget(self.media_button_row_widget)

            self.media_target_row_widget = QWidget(panel)
            target_row = QHBoxLayout(self.media_target_row_widget)
            target_row.setContentsMargins(0, 0, 0, 0)
            target_row.setSpacing(6)
            target_label = QLabel("Target track:")
            self.target_track_combo = QComboBox(self.media_target_row_widget)
            self.target_track_combo.currentIndexChanged.connect(self._target_track_combo_changed)
            target_row.addWidget(target_label)
            target_row.addWidget(self.target_track_combo, 1)
            layout.addWidget(self.media_target_row_widget)

            self.media_table = MediaBinTable(self)
            layout.addWidget(self.media_table, 1)

            self.media_hint_label = QLabel("Double-click/Add uses Target track. Drag media directly onto any timeline track.")
            self.media_hint_label.setWordWrap(True)
            self.media_hint_label.setStyleSheet("color: #9aa3b6;")
            layout.addWidget(self.media_hint_label)

            self.media_content_widgets = [
                self.media_button_row_widget,
                self.media_target_row_widget,
                self.media_table,
                self.media_hint_label,
            ]
            return panel

        def _build_transitions_panel(self) -> QWidget:
            panel = QWidget(self)
            panel.setMinimumWidth(220)
            panel.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
            layout = QVBoxLayout(panel)
            layout.setContentsMargins(0, 0, 0, 0)
            layout.setSpacing(6)

            header, self.transitions_title_label, self.transitions_collapse_btn = self._make_section_header("Transitions", "▲")
            self.transitions_collapse_btn.clicked.connect(self.toggle_transitions_panel)
            self.refresh_transitions_btn = QPushButton("Refresh")
            self.refresh_transitions_btn.setToolTip("Reload PNG/JPG masks from assets/transitions/.")
            self.refresh_transitions_btn.clicked.connect(lambda: self.refresh_transition_masks(create_missing=True, log_result=True))
            self.debug_transitions_box = QCheckBox("Debug")
            self.debug_transitions_box.setToolTip("Log PNG transition cache/timing details. Off by default to avoid log spam.")
            self.debug_transitions_box.setChecked(bool(getattr(self, "debug_transitions", False)))
            self.debug_transitions_box.toggled.connect(self.set_debug_transitions)
            try:
                header.layout().addWidget(self.debug_transitions_box)
                header.layout().addWidget(self.refresh_transitions_btn)
            except Exception:
                pass
            layout.addWidget(header)

            self.transition_table = TransitionMaskTable(self)
            self.transition_table.setMaximumHeight(210)
            layout.addWidget(self.transition_table, 1)

            self.effects_section = QWidget(panel)
            effects_layout = QVBoxLayout(self.effects_section)
            effects_layout.setContentsMargins(0, 0, 0, 0)
            effects_layout.setSpacing(5)

            effects_header, self.effects_title_label, self.effects_collapse_btn = self._make_section_header("Effects", "▲")
            self.effects_collapse_btn.clicked.connect(self.toggle_effects_panel)
            self.refresh_effects_btn = QPushButton("Refresh")
            self.refresh_effects_btn.setToolTip("Reload transform effect presets from presets/effects/.")
            self.refresh_effects_btn.clicked.connect(lambda: self.refresh_effect_presets(create_missing=True, log_result=True))
            self.apply_effect_btn = QPushButton("Apply")
            self.apply_effect_btn.setToolTip("Apply the selected effect preset to the selected visual clip")
            self.apply_effect_btn.clicked.connect(self.apply_selected_effect_preset)
            try:
                effects_header.layout().addWidget(self.refresh_effects_btn)
                effects_header.layout().addWidget(self.apply_effect_btn)
            except Exception:
                pass
            effects_layout.addWidget(effects_header)

            self.effects_controls_widget = QWidget(self.effects_section)
            effects_controls = QHBoxLayout(self.effects_controls_widget)
            effects_controls.setContentsMargins(0, 0, 0, 0)
            effects_controls.setSpacing(6)
            self.effect_duration_spin = QDoubleSpinBox(self.effects_section)
            self.effect_duration_spin.setRange(0.05, 60.0)
            self.effect_duration_spin.setDecimals(2)
            self.effect_duration_spin.setSingleStep(0.25)
            self.effect_duration_spin.setValue(1.0)
            self.effect_duration_spin.setSuffix("s")
            self.effect_duration_spin.setToolTip("Intro/Outro duration. Whole clip mode ignores this and uses the full clip.")
            self.effect_mode_combo = QComboBox(self.effects_section)
            for label, value in EFFECT_PRESET_MODE_LABELS:
                self.effect_mode_combo.addItem(label, value)
            self.effect_replace_keyframes_box = QCheckBox("Replace existing visual keyframes", self.effects_section)
            self.effect_replace_keyframes_box.setChecked(False)
            self.effect_replace_keyframes_box.setToolTip("Off = protect existing visual keyframes. On = replace only this clip's visual transform keyframes.")
            effects_controls.addWidget(QLabel("Duration:", self.effects_section))
            effects_controls.addWidget(self.effect_duration_spin)
            effects_controls.addWidget(QLabel("Mode:", self.effects_section))
            effects_controls.addWidget(self.effect_mode_combo)
            effects_controls.addWidget(self.effect_replace_keyframes_box, 1)
            effects_layout.addWidget(self.effects_controls_widget)

            self.effect_table = EffectPresetTable(self)
            effects_layout.addWidget(self.effect_table, 1)
            layout.addWidget(self.effects_section, 1)

            self.effects_content_widgets = [
                self.refresh_effects_btn,
                self.apply_effect_btn,
                self.effects_controls_widget,
                self.effect_table,
            ]
            self.transitions_content_widgets = [
                self.debug_transitions_box,
                self.refresh_transitions_btn,
                self.transition_table,
            ]
            return panel

        def _build_timeline_panel(self) -> QWidget:
            panel = QWidget(self)
            main = QVBoxLayout(panel)
            self.right_panel_layout = main
            main.setContentsMargins(0, 0, 0, 0)
            main.setSpacing(6)

            self.right_splitter = QSplitter(Qt.Orientation.Vertical)
            self.timeline_section = self._build_timeline_section()
            self.preview_section = self._build_preview_section()
            self.log_section = self._build_log_section()
            self.right_splitter.addWidget(self.timeline_section)
            self.right_splitter.addWidget(self.preview_section)
            self.right_splitter.addWidget(self.log_section)
            self.right_splitter.setStretchFactor(0, 3)
            self.right_splitter.setStretchFactor(1, 1)
            self.right_splitter.setStretchFactor(2, 1)
            self.right_splitter.setSizes([360, 270, 150])
            self.right_splitter.splitterMoved.connect(lambda *_args: self._schedule_preview_surface_resize_burst("splitter moved", log_first=True))
            self.right_splitter.installEventFilter(self)
            self.preview_section.installEventFilter(self)
            main.addWidget(self.right_splitter, 1)
            return panel

        def _new_workspace_splitter(self, orientation: Qt.Orientation) -> QSplitter:
            splitter = QSplitter(orientation, self.right_panel)
            splitter.splitterMoved.connect(lambda *_args: self._on_layout_splitter_moved())
            splitter.installEventFilter(self)
            return splitter

        def _clear_right_panel_layout(self) -> None:
            if not hasattr(self, "right_panel_layout"):
                return
            while self.right_panel_layout.count():
                item = self.right_panel_layout.takeAt(0)
                widget = item.widget() if item is not None else None
                if widget is not None:
                    # The removed widget is normally an old temporary splitter. Hide it
                    # before detaching so Qt never promotes it to a small top-level
                    # window during layout switches. Reusable panels are detached
                    # separately before this splitter is removed.
                    try:
                        widget.hide()
                    except Exception:
                        pass
                    try:
                        widget.setParent(None)
                    except Exception:
                        pass
                    try:
                        widget.deleteLater()
                    except Exception:
                        pass

        def _detach_layout_widget(self, widget: Optional[QWidget]) -> None:
            """Safely detach a reusable editor panel before rebuilding layout splitters.

            Important: never leave a visible QWidget parentless. On Windows/Qt that
            turns panels into separate little windows. The new layout explicitly shows
            only the panels it owns after reparenting them.
            """
            if widget is None:
                return
            try:
                widget.hide()
            except Exception:
                pass
            try:
                widget.setParent(None)
            except Exception:
                pass

        def _detach_reusable_layout_widgets(self) -> None:
            for name in ("media_panel", "transitions_panel", "timeline_section", "preview_section", "log_section"):
                self._detach_layout_widget(getattr(self, name, None))

        def _clear_classic_left_splitter(self) -> None:
            splitter = getattr(self, "classic_left_splitter", None)
            if splitter is None:
                return
            try:
                splitter.hide()
            except Exception:
                pass
            try:
                splitter.setParent(None)
            except Exception:
                pass
            try:
                splitter.deleteLater()
            except Exception:
                pass
            self.classic_left_splitter = None

        def _middle_effects_column_collapsed(self) -> bool:
            """The shared Transitions/Effects column collapses only when both sections are collapsed."""
            return bool(getattr(self, "transitions_collapsed", False)) and bool(getattr(self, "effects_collapsed", False))

        def _top_band_collapsed_flags(self) -> List[bool]:
            return [
                bool(getattr(self, "media_collapsed", False)),
                self._middle_effects_column_collapsed(),
                bool(getattr(self, "preview_collapsed", False)),
            ]

        def _top_band_is_collapsed_for_vertical_layout(self) -> bool:
            """Return True when the whole Media/Transitions/Preview band is header-only.

            In Media Top / Timeline Top layouts the Preview panel is inside a
            horizontal splitter. Collapsing Preview only by width is not enough
            when Media Bin and Transitions are also collapsed, because the outer
            vertical splitter can still reserve the old top-band height. Treat
            the entire top band as collapsed only when every panel inside it is
            collapsed.
            """
            flags = self._top_band_collapsed_flags()
            return bool(flags) and all(bool(flag) for flag in flags)

        def _top_band_panel_specs(self) -> List[Tuple[QWidget, bool, int]]:
            return [
                (self.media_panel, bool(getattr(self, "media_collapsed", False)), 220),
                (self.transitions_panel, self._middle_effects_column_collapsed(), 180),
                (self.preview_section, bool(getattr(self, "preview_collapsed", False)), 260),
            ]

        def _apply_top_band_width_rules(self) -> None:
            """Keep a fully-collapsed top band from shrinking the whole editor.

            Media Top / Timeline Top place Media Bin, Transitions, and Preview in
            a horizontal splitter. Making every collapsed child max-width 34px
            works while at least one panel is open, but when all three are
            collapsed Qt can treat the whole band as a narrow side panel and the
            Timeline below inherits that narrow width.

            Keep collapsed children narrow while another panel is open. When the
            whole top band is collapsed, relax max-widths so the band can still
            span the full workspace while its height stays compact.
            """
            top = getattr(self, "top_band_splitter", None)
            if top is None:
                return
            all_collapsed = self._top_band_is_collapsed_for_vertical_layout()
            try:
                top.setMinimumWidth(0)
                top.setMaximumWidth(16777215)
                top.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)
                top.setMinimumHeight(34 if all_collapsed else 0)
                top.setMaximumHeight(34 if all_collapsed else 16777215)
            except Exception:
                pass
            for panel, collapsed, min_open_width in self._top_band_panel_specs():
                try:
                    if panel.parent() is not top:
                        continue
                    if all_collapsed:
                        panel.setMinimumWidth(34)
                        panel.setMaximumWidth(16777215)
                        panel.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)
                        self._set_vertical_panel_collapsed(panel, False)
                    else:
                        self._set_horizontal_panel_collapsed(panel, collapsed, min_open_width=min_open_width)
                        self._set_vertical_panel_collapsed(panel, False)
                except Exception:
                    pass

        def _refresh_top_band_splitter_sizes(self, preferred_sizes: Optional[List[int]] = None) -> None:
            top = getattr(self, "top_band_splitter", None)
            if top is None:
                return
            self._apply_top_band_width_rules()
            try:
                current = [int(x) for x in top.sizes()]
            except Exception:
                current = []
            if preferred_sizes is not None:
                base = [max(1, int(x)) for x in list(preferred_sizes)[:3]]
            else:
                base = [int(x) for x in current[:3]]
            if len(base) != 3 or sum(base) <= 0:
                base = list(default_layout_state_for_preset(getattr(self, "layout_preset", LAYOUT_PRESET_MEDIA_TOP)).get("preview_left_top_splitter_sizes", [520, 300, 900]))
            if len(base) != 3 or sum(base) <= 0:
                base = [520, 300, 900]
            all_collapsed = self._top_band_is_collapsed_for_vertical_layout()
            if all_collapsed:
                try:
                    available = int(top.width())
                except Exception:
                    available = 0
                available = max(available, sum(base), 34 * 3)
                sizes = [34, 34, max(34, available - 68)]
            else:
                sizes = [34 if collapsed else max(160, int(value)) for value, collapsed in zip(base, self._top_band_collapsed_flags())]
            try:
                top.setSizes(sizes)
            except Exception:
                pass

        def _force_timeline_workspace_when_top_band_collapsed(self, reason: str = "") -> None:
            """Give Timeline the workspace when Media/Transitions/Preview are collapsed."""
            preset = normalize_layout_preset(getattr(self, "layout_preset", LAYOUT_PRESET_MEDIA_TOP))
            if preset not in (LAYOUT_PRESET_MEDIA_TOP, LAYOUT_PRESET_TIMELINE_TOP):
                return
            if not self._top_band_is_collapsed_for_vertical_layout() or bool(getattr(self, "timeline_collapsed", False)):
                return
            self._apply_top_band_width_rules()
            try:
                if hasattr(self, "main_splitter"):
                    self.main_splitter.setSizes([max(900, int(self.width() or 900))])
            except Exception:
                pass
            try:
                self._force_splitter_child_span(getattr(self, "right_splitter", None), getattr(self, "top_band_splitter", None), 34, min_other=260)
            except Exception:
                pass
            try:
                if bool(getattr(self, "logs_collapsed", False)):
                    self._force_splitter_child_span(getattr(self, "right_splitter", None), getattr(self, "log_section", None), 34, min_other=260)
            except Exception:
                pass
            try:
                self.timeline_section.setMinimumWidth(0)
                self.timeline_section.setMaximumWidth(16777215)
                self.timeline_section.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
                self.right_panel.setMinimumWidth(0)
                self.right_panel.setMaximumWidth(16777215)
                self.right_panel.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
                self.right_panel.updateGeometry()
                self.timeline_section.updateGeometry()
            except Exception:
                pass

        def _set_horizontal_panel_collapsed(self, section: QWidget, collapsed: bool, min_open_width: int = 160) -> None:
            try:
                if collapsed:
                    section.setMinimumWidth(34)
                    section.setMaximumWidth(34)
                else:
                    section.setMinimumWidth(min_open_width)
                    section.setMaximumWidth(16777215)
            except Exception:
                pass

        def _set_vertical_panel_collapsed(self, section: QWidget, collapsed: bool, min_open_height: int = 0) -> None:
            try:
                if collapsed:
                    section.setMinimumHeight(34)
                    section.setMaximumHeight(34)
                else:
                    section.setMinimumHeight(min_open_height)
                    section.setMaximumHeight(16777215)
            except Exception:
                pass

        def _force_splitter_child_span(self, splitter: Optional[QSplitter], child: Optional[QWidget], span: int, min_other: int = 80) -> None:
            """Force one splitter child to a compact span and give freed room to neighbors.

            Qt splitters sometimes keep a previous expanded size after a panel's
            min/max size changes. This helper is intentionally layout-only: it
            does not change timeline math, preview rendering, playback, or media
            behavior. It simply makes a collapsed section visibly collapse now.
            """
            if splitter is None or child is None:
                return
            try:
                index = splitter.indexOf(child)
            except Exception:
                index = -1
            if index < 0:
                return
            try:
                sizes = [int(x) for x in splitter.sizes()]
            except Exception:
                sizes = []
            count = 0
            try:
                count = int(splitter.count())
            except Exception:
                count = len(sizes)
            if count <= 0:
                return
            if len(sizes) != count or sum(sizes) <= 0:
                sizes = [max(min_other, span) for _ in range(count)]
            total = max(sum(sizes), span + min_other * max(0, count - 1))
            target = max(0, int(span))
            old_target = sizes[index] if index < len(sizes) else target
            sizes[index] = target
            extra = max(0, total - sum(sizes))
            candidates = [i for i in range(count) if i != index]
            if candidates:
                # Keep the user's existing proportions as much as possible by
                # giving the released room to the currently largest neighbor.
                receiver = max(candidates, key=lambda i: sizes[i] if i < len(sizes) else 0)
                sizes[receiver] = max(min_other, sizes[receiver] + extra)
            try:
                splitter.setSizes(sizes)
            except Exception:
                try:
                    fallback = [min_other for _ in range(count)]
                    fallback[index] = target
                    splitter.setSizes(fallback)
                except Exception:
                    pass

        def _refresh_layout_after_panel_toggle(self, reason: str) -> None:
            self._refresh_right_splitter_sizes()
            self._refresh_top_band_splitter_sizes()
            self._force_timeline_workspace_when_top_band_collapsed(reason)
            QTimer.singleShot(0, self.update_after_resize)
            QTimer.singleShot(0, lambda: self._force_timeline_workspace_when_top_band_collapsed(reason))
            self._schedule_timeline_scrollbar_refresh(reason)
            self._schedule_preview_surface_resize_burst(reason, log_first=True)

        def _refresh_layout_preset_combo(self) -> None:
            if not hasattr(self, "layout_preset_combo"):
                return
            preset = normalize_layout_preset(getattr(self, "layout_preset", LAYOUT_PRESET_MEDIA_TOP))
            self.layout_preset_combo.blockSignals(True)
            try:
                for index in range(self.layout_preset_combo.count()):
                    if normalize_layout_preset(self.layout_preset_combo.itemData(index)) == preset:
                        self.layout_preset_combo.setCurrentIndex(index)
                        break
            finally:
                self.layout_preset_combo.blockSignals(False)

        def _layout_preset_combo_changed(self, index: int) -> None:
            if index < 0 or not hasattr(self, "layout_preset_combo"):
                return
            self.apply_layout_preset(self.layout_preset_combo.itemData(index), save=True, log_change=True)

        def _on_layout_splitter_moved(self) -> None:
            if getattr(self, "_layout_switching", False):
                return
            self._capture_layout_splitter_sizes()
            self._schedule_preview_surface_resize_burst("layout splitter moved", log_first=False)
            QTimer.singleShot(0, self.update_after_resize)
            self._schedule_timeline_scrollbar_refresh("layout splitter moved")
            if not getattr(self, "_loading_settings", False):
                self.save_editor_state()

        def _capture_layout_splitter_sizes(self) -> None:
            try:
                if hasattr(self, "main_splitter"):
                    self.main_splitter_sizes = [int(x) for x in self.main_splitter.sizes()]
            except Exception:
                pass
            try:
                if hasattr(self, "right_splitter"):
                    self.right_splitter_sizes = [int(x) for x in self.right_splitter.sizes()]
            except Exception:
                pass
            try:
                if hasattr(self, "preview_left_top_splitter") and self.preview_left_top_splitter is not None:
                    self.preview_left_top_splitter_sizes = [int(x) for x in self.preview_left_top_splitter.sizes()]
            except Exception:
                pass
            try:
                if hasattr(self, "preview_left_outer_splitter") and self.preview_left_outer_splitter is not None:
                    self.preview_left_outer_splitter_sizes = [int(x) for x in self.preview_left_outer_splitter.sizes()]
            except Exception:
                pass

        def _ordered_vertical_sections_for_layout(self, preset: Optional[str] = None) -> List[Tuple[QWidget, bool, int]]:
            preset = normalize_layout_preset(preset or getattr(self, "layout_preset", LAYOUT_PRESET_MEDIA_TOP))
            if preset == LAYOUT_PRESET_EDITING:
                return [
                    (self.timeline_section, False, 900),
                    (self.log_section, self.logs_collapsed, 34),
                ]
            if preset == LAYOUT_PRESET_TIMELINE_TOP:
                top_band_collapsed = self._top_band_is_collapsed_for_vertical_layout()
                return [
                    (self.timeline_section, self.timeline_collapsed, 520),
                    (getattr(self, "top_band_splitter", self.preview_section), top_band_collapsed, 360),
                    (self.log_section, self.logs_collapsed, 34),
                ]
            if preset == LAYOUT_PRESET_MEDIA_TOP:
                top_band_collapsed = self._top_band_is_collapsed_for_vertical_layout()
                return [
                    (getattr(self, "top_band_splitter", self.preview_section), top_band_collapsed, 410),
                    (self.timeline_section, self.timeline_collapsed, 470),
                    (self.log_section, self.logs_collapsed, 34),
                ]
            return [
                (self.timeline_section, self.timeline_collapsed, 430),
                (self.preview_section, self.preview_collapsed, 330),
                (self.log_section, self.logs_collapsed, 34),
            ]

        def _sizes_with_collapsed(self, base: List[int], collapsed_flags: List[bool], fallback: List[int]) -> List[int]:
            values = list(base) if len(base) == len(collapsed_flags) else list(fallback)
            out: List[int] = []
            for value, collapsed in zip(values, collapsed_flags):
                out.append(34 if collapsed else max(80, int(value)))
            return out

        def _show_layout_widget(self, widget: Optional[QWidget]) -> None:
            if widget is None:
                return
            try:
                widget.setVisible(True)
                widget.show()
            except Exception:
                pass

        def _hide_layout_widget(self, widget: Optional[QWidget]) -> None:
            if widget is None:
                return
            try:
                widget.hide()
            except Exception:
                pass

        def _ensure_right_panel_only_in_main_splitter(self) -> None:
            self._clear_classic_left_splitter()
            try:
                if self.media_panel.parent() is self.main_splitter:
                    self.media_panel.hide()
                    self.media_panel.setParent(None)
                if self.transitions_panel.parent() is self.main_splitter:
                    self.transitions_panel.hide()
                    self.transitions_panel.setParent(None)
            except Exception:
                pass
            try:
                if self.right_panel.parent() is not self.main_splitter:
                    self.main_splitter.addWidget(self.right_panel)
                self.right_panel.setVisible(True)
                self.main_splitter.setStretchFactor(0, 1)
            except Exception:
                pass

        def _rebuild_workspace_for_layout(self, preset: str) -> None:
            preset = normalize_layout_preset(preset)
            # Detach reusable panels before removing the old temporary splitter. This
            # prevents Qt from creating parentless visible panel windows during layout
            # switches. Classic is kept as the old familiar layout; the new two-band
            # layouts are separate and do not mutate Classic.
            self._detach_reusable_layout_widgets()
            self._clear_classic_left_splitter()
            self._clear_right_panel_layout()
            self.preview_left_top_splitter = None
            self.preview_left_outer_splitter = None
            self.top_band_splitter = None

            if preset == LAYOUT_PRESET_CLASSIC:
                try:
                    left = QSplitter(Qt.Orientation.Vertical, self.main_splitter)
                    left.splitterMoved.connect(lambda *_args: self._on_layout_splitter_moved())
                    left.installEventFilter(self)
                    left.addWidget(self.media_panel)
                    left.addWidget(self.transitions_panel)
                    left.setStretchFactor(0, 1)
                    left.setStretchFactor(1, 1)
                    left.setSizes([1, 1])
                    self.classic_left_splitter = left
                    self.main_splitter.insertWidget(0, left)
                    if self.right_panel.parent() is not self.main_splitter:
                        self.main_splitter.addWidget(self.right_panel)
                    self.main_splitter.setStretchFactor(0, 0)
                    self.main_splitter.setStretchFactor(1, 1)
                except Exception:
                    pass
                self._show_layout_widget(self.media_panel)
                self._show_layout_widget(self.transitions_panel)
                self._show_layout_widget(self.right_panel)
                splitter = self._new_workspace_splitter(Qt.Orientation.Vertical)
                splitter.addWidget(self.timeline_section)
                splitter.addWidget(self.preview_section)
                splitter.addWidget(self.log_section)
                splitter.setStretchFactor(0, 2)
                splitter.setStretchFactor(1, 1)
                splitter.setStretchFactor(2, 0)
                self.right_splitter = splitter
                self.right_panel_layout.addWidget(splitter, 1)
                for widget in (self.timeline_section, self.preview_section, self.log_section):
                    self._show_layout_widget(widget)

            elif preset == LAYOUT_PRESET_EDITING:
                self._ensure_right_panel_only_in_main_splitter()
                # Timeline-only mode: keep extra panels hidden but preserved, so they
                # can return instantly when switching to Media Top / Timeline Top / Classic.
                for widget in (self.media_panel, self.transitions_panel, self.preview_section):
                    self._hide_layout_widget(widget)
                outer = self._new_workspace_splitter(Qt.Orientation.Vertical)
                outer.addWidget(self.timeline_section)
                outer.addWidget(self.log_section)
                outer.setStretchFactor(0, 1)
                outer.setStretchFactor(1, 0)
                self.right_splitter = outer
                self.right_panel_layout.addWidget(outer, 1)
                self._show_layout_widget(self.timeline_section)
                self._show_layout_widget(self.log_section)

            else:
                self._ensure_right_panel_only_in_main_splitter()
                top = self._new_workspace_splitter(Qt.Orientation.Horizontal)
                top.addWidget(self.media_panel)
                top.addWidget(self.transitions_panel)
                top.addWidget(self.preview_section)
                top.setStretchFactor(0, 1)
                top.setStretchFactor(1, 0)
                top.setStretchFactor(2, 2)
                self.top_band_splitter = top
                self.preview_left_top_splitter = top

                outer = self._new_workspace_splitter(Qt.Orientation.Vertical)
                if preset == LAYOUT_PRESET_TIMELINE_TOP:
                    outer.addWidget(self.timeline_section)
                    outer.addWidget(top)
                    outer.setStretchFactor(0, 2)
                    outer.setStretchFactor(1, 1)
                else:
                    outer.addWidget(top)
                    outer.addWidget(self.timeline_section)
                    outer.setStretchFactor(0, 1)
                    outer.setStretchFactor(1, 2)
                outer.addWidget(self.log_section)
                outer.setStretchFactor(2, 0)
                self.right_splitter = outer
                self.preview_left_outer_splitter = outer
                self.right_panel_layout.addWidget(outer, 1)
                for widget in (self.media_panel, self.transitions_panel, self.preview_section, self.timeline_section, self.log_section):
                    self._show_layout_widget(widget)

            try:
                self.right_panel.setVisible(True)
                self.right_panel.updateGeometry()
                self.main_splitter.updateGeometry()
            except Exception:
                pass
            try:
                self.right_splitter.installEventFilter(self)
            except Exception:
                pass

        def _apply_layout_splitter_sizes(self, state: Optional[Dict[str, Any]] = None) -> None:
            state = sanitize_layout_state(state if state is not None else default_layout_state_for_preset(getattr(self, "layout_preset", LAYOUT_PRESET_MEDIA_TOP)))
            preset = normalize_layout_preset(state.get("layout_preset", getattr(self, "layout_preset", LAYOUT_PRESET_MEDIA_TOP)))
            if hasattr(self, "main_splitter"):
                if preset == LAYOUT_PRESET_CLASSIC:
                    main_sizes = list(state.get("main_splitter_sizes") or default_layout_state_for_preset(preset)["main_splitter_sizes"])
                    if self.media_collapsed:
                        total = max(sum(main_sizes), self.width() or 1000)
                        main_sizes = [34, max(600, total - 34)]
                    self.main_splitter.setSizes(main_sizes)
                else:
                    # Two-band layouts keep Media Bin inside the workspace, not in a left side rail.
                    self.main_splitter.setSizes([max(900, self.width() or 900)])
            if hasattr(self, "top_band_splitter") and self.top_band_splitter is not None:
                top_sizes = list(state.get("preview_left_top_splitter_sizes") or default_layout_state_for_preset(preset).get("preview_left_top_splitter_sizes", [520, 300, 900]))
                self._refresh_top_band_splitter_sizes(top_sizes)
            if preset == LAYOUT_PRESET_CLASSIC and getattr(self, "classic_left_splitter", None) is not None:
                try:
                    left_sizes = [
                        34 if bool(getattr(self, "media_collapsed", False)) else 1,
                        34 if self._middle_effects_column_collapsed() else 1,
                    ]
                    self.classic_left_splitter.setSizes(left_sizes)
                except Exception:
                    pass
            if hasattr(self, "right_splitter"):
                base = list(state.get("right_splitter_sizes") or default_layout_state_for_preset(preset)["right_splitter_sizes"])
                collapsed_flags = [collapsed for _section, collapsed, _fallback in self._ordered_vertical_sections_for_layout(preset)]
                fallback = [fallback for _section, _collapsed, fallback in self._ordered_vertical_sections_for_layout(preset)]
                self.right_splitter.setSizes(self._sizes_with_collapsed(base, collapsed_flags, fallback))
            self._force_timeline_workspace_when_top_band_collapsed("layout splitter sizes applied")
            self._capture_layout_splitter_sizes()

        def apply_layout_preset(self, preset: Any, save: bool = False, layout_state: Optional[Dict[str, Any]] = None, log_change: bool = False) -> None:
            preset_key = normalize_layout_preset(preset)
            state = sanitize_layout_state(layout_state or default_layout_state_for_preset(preset_key))
            state["layout_preset"] = preset_key
            self._layout_switching = True
            try:
                self.layout_preset = preset_key
                self.media_collapsed = bool(state.get("media_collapsed", False))
                self.timeline_collapsed = bool(state.get("timeline_collapsed", False))
                self.preview_collapsed = bool(state.get("preview_collapsed", False))
                self.transitions_collapsed = bool(state.get("transitions_collapsed", False))
                self.effects_collapsed = bool(state.get("effects_collapsed", False))
                self.logs_collapsed = bool(state.get("logs_collapsed", False))
                if preset_key == LAYOUT_PRESET_EDITING:
                    self.media_collapsed = True
                    self.transitions_collapsed = True
                    self.effects_collapsed = True
                    self.preview_collapsed = True
                    self.logs_collapsed = True
                self._rebuild_workspace_for_layout(preset_key)
                self._refresh_layout_preset_combo()
                self._apply_all_collapsed_states()
                self._apply_layout_splitter_sizes(state)
                self._force_timeline_workspace_when_top_band_collapsed("layout preset applied")
            finally:
                self._layout_switching = False
            QTimer.singleShot(0, self.update_after_resize)
            QTimer.singleShot(0, lambda: self._force_timeline_workspace_when_top_band_collapsed("layout preset applied"))
            self._schedule_timeline_scrollbar_refresh("layout preset changed")
            self._schedule_preview_surface_resize_burst("layout preset changed", log_first=False)
            if log_change:
                self.log(f"Layout preset set: {layout_preset_label(preset_key)}")
            if save and not getattr(self, "_loading_settings", False):
                self.save_editor_state()

        def reset_layout(self) -> None:
            state = default_layout_state_for_preset(LAYOUT_PRESET_MEDIA_TOP)
            self.apply_layout_preset(LAYOUT_PRESET_MEDIA_TOP, save=True, layout_state=state, log_change=True)
            self.log("Layout reset: Media Top")

        def _build_timeline_section(self) -> QWidget:
            section = QWidget(self)
            main = QVBoxLayout(section)
            main.setContentsMargins(0, 0, 0, 0)
            main.setSpacing(6)

            header, self.timeline_title_label, self.timeline_collapse_btn = self._make_section_header("Timeline", "▲")
            self.timeline_collapse_btn.clicked.connect(self.toggle_timeline_panel)
            main.addWidget(header)

            self.timeline_nav_widget = QWidget(section)
            nav_row = QHBoxLayout(self.timeline_nav_widget)
            nav_row.setContentsMargins(0, 0, 0, 0)
            nav_row.setSpacing(6)

            self.timeline_edit_widget = QWidget(section)
            edit_row = QHBoxLayout(self.timeline_edit_widget)
            edit_row.setContentsMargins(0, 0, 0, 0)
            edit_row.setSpacing(6)

            self.playhead_label = QLabel("Playhead: 00:00.000")
            self.hover_label = QLabel("Hover: --")
            self.zoom_label = QLabel("Zoom: 60 px/s")
            self.active_playback_status_label = QLabel(active_playback_status_text("Stopped", 0.0, 0.0))

            # Keep status labels fixed-width so hover/playhead updates do not relayout the whole UI.
            status_font = QFont("Consolas", 9)
            for label, width in [
                (self.playhead_label, 154),
                (self.hover_label, 125),
                (self.zoom_label, 110),
                (self.active_playback_status_label, 360),
            ]:
                label.setFont(status_font)
                label.setFixedWidth(width)
                label.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Preferred)

            self.snap_box = QCheckBox("Snap")
            self.snap_box.setChecked(self.snap_enabled)
            self.snap_box.setToolTip("Snap rounds edits to the timeline grid.")
            self.snap_box.stateChanged.connect(self._snap_changed)

            self.show_thumbnails_box = QCheckBox("Show thumbnails", section)
            self.show_thumbnails_box.setChecked(bool(self.show_timeline_thumbnails))
            self.show_thumbnails_box.setToolTip("Show cached video/image thumbnails on visual clips. Off by default for performance.")
            self.show_thumbnails_box.toggled.connect(self.set_show_timeline_thumbnails)
            self.show_waveform_box = QCheckBox("Show waveform", section)
            self.show_waveform_box.setChecked(bool(self.show_timeline_waveforms))
            self.show_waveform_box.setToolTip("Show cached low-resolution waveform bars on audio clips.")
            self.show_waveform_box.toggled.connect(self.set_show_timeline_waveforms)
            self.show_thumbnails_box.hide()
            self.show_waveform_box.hide()

            # v37.5: keep timeline controls to two rows. Visual-aid toggles live
            # in a compact View menu instead of consuming a full third row.
            self.timeline_view_menu = QMenu(self)
            self.show_thumbnails_action = self.timeline_view_menu.addAction("Show thumbnails")
            self.show_thumbnails_action.setCheckable(True)
            self.show_thumbnails_action.setChecked(bool(self.show_timeline_thumbnails))
            self.show_thumbnails_action.setToolTip("Show cached video/image thumbnails on visual clips.")
            self.show_thumbnails_action.toggled.connect(self.set_show_timeline_thumbnails)
            self.show_waveform_action = self.timeline_view_menu.addAction("Show waveform")
            self.show_waveform_action.setCheckable(True)
            self.show_waveform_action.setChecked(bool(self.show_timeline_waveforms))
            self.show_waveform_action.setToolTip("Show cached low-resolution waveform bars on audio clips.")
            self.show_waveform_action.toggled.connect(self.set_show_timeline_waveforms)
            self.timeline_view_btn = QPushButton("View ▾")
            self.timeline_view_btn.setToolTip("Timeline visual aids")
            self.timeline_view_btn.setMenu(self.timeline_view_menu)
            self.timeline_view_btn.setSizePolicy(QSizePolicy.Policy.Maximum, QSizePolicy.Policy.Fixed)

            btn_zoom_out = QPushButton("Zoom -")
            btn_zoom_in = QPushButton("Zoom +")
            btn_zoom_playhead = QPushButton("Zoom @ Playhead")
            btn_fit = QPushButton("Fit Timeline")
            self.undo_btn = QPushButton("Undo")
            self.redo_btn = QPushButton("Redo")
            btn_add_track = QPushButton("Add Track")
            btn_text = QPushButton("Text")
            btn_split = QPushButton("Split")
            btn_delete = QPushButton("Delete")
            compact_buttons = [
                btn_zoom_out,
                btn_zoom_in,
                btn_fit,
                self.undo_btn,
                self.redo_btn,
                btn_add_track,
                btn_text,
                btn_split,
                btn_delete,
            ]
            for button in compact_buttons:
                button.setSizePolicy(QSizePolicy.Policy.Maximum, QSizePolicy.Policy.Fixed)

            btn_zoom_out.setToolTip("Timeline zoom out")
            btn_zoom_in.setToolTip("Timeline zoom in")
            btn_zoom_playhead.setToolTip("Zoom in around the current playhead position")
            btn_fit.setToolTip("Fit the whole timeline into the visible timeline area")

            btn_zoom_out.clicked.connect(lambda: self.zoom_around_playhead(1.0 / 1.2))
            btn_zoom_in.clicked.connect(lambda: self.zoom_around_playhead(1.2))
            btn_zoom_playhead.clicked.connect(lambda: self.zoom_around_playhead(1.35))
            btn_fit.clicked.connect(self.fit_timeline)
            self.undo_btn.clicked.connect(self.undo_edit)
            self.redo_btn.clicked.connect(self.redo_edit)
            btn_add_track.clicked.connect(lambda: self.add_track_dialog(index=None))
            btn_text.clicked.connect(self.create_text_asset_dialog)
            btn_split.clicked.connect(self.split_selected_clip)
            btn_delete.clicked.connect(self.delete_selected_clip)

            # Keep the live timeline status visible in the section header.
            # This removes the old dedicated status row and also keeps the
            # playhead/hover/zoom/playback readout visible while the Timeline
            # panel body is collapsed.
            try:
                timeline_header_layout = header.layout()
                if timeline_header_layout is not None:
                    insert_index = max(0, timeline_header_layout.count() - 1)
                    for widget in [self.playhead_label, self.hover_label, self.zoom_label, self.active_playback_status_label]:
                        timeline_header_layout.insertWidget(insert_index, widget)
                        insert_index += 1
            except Exception:
                pass

            for widget in [btn_zoom_out, btn_zoom_in, btn_zoom_playhead, btn_fit, self.undo_btn, self.redo_btn, btn_text, btn_split, btn_delete, btn_add_track]:
                edit_row.addWidget(widget)
            edit_row.addStretch(1)
            edit_row.addWidget(self.timeline_view_btn)
            edit_row.addWidget(self.snap_box)
            self.timeline_nav_widget.setVisible(False)

            main.addWidget(self.timeline_edit_widget)

            self.canvas_scroll_area = QScrollArea(section)
            # Keep the timeline canvas at its real content height.
            # V28 layout presets could otherwise resize the canvas down to the
            # viewport height, hiding lower tracks and removing the vertical scrollbar.
            # Horizontal timeline scrolling still uses the custom scrollbar below.
            self.canvas_scroll_area.setWidgetResizable(False)
            self.canvas_scroll_area.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
            self.canvas_scroll_area.setVerticalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAsNeeded)
            self.canvas = TimelineCanvas(self)
            self.canvas_scroll_area.setWidget(self.canvas)
            try:
                self.canvas_scroll_area.setAcceptDrops(True)
                self.canvas_scroll_area.viewport().setAcceptDrops(True)
            except Exception:
                pass
            try:
                self.canvas_scroll_area.viewport().installEventFilter(self)
            except Exception:
                pass
            main.addWidget(self.canvas_scroll_area, 1)

            self.hscroll = QScrollBar(Qt.Orientation.Horizontal)
            self.hscroll.valueChanged.connect(self._scrollbar_changed)
            main.addWidget(self.hscroll)

            self.timeline_content_widgets = [
                self.timeline_edit_widget,
                self.canvas_scroll_area,
                self.hscroll,
            ]
            return section

        def _build_preview_section(self) -> QWidget:
            section = QWidget(self)
            section.setObjectName("previewSection")
            main = QVBoxLayout(section)
            main.setContentsMargins(0, 0, 0, 0)
            main.setSpacing(6)

            header, self.preview_title_label, self.preview_collapse_btn = self._make_section_header("Preview", "▲")
            header.setObjectName("previewHeader")
            self.preview_transform_readout_label = QLabel("Transform: no visual clip", header)
            self.preview_transform_readout_label.setFont(QFont("Consolas", 9))
            self.preview_transform_readout_label.setToolTip("Current selected visual clip transform. X=0 and Y=0 are the original/default centered position.")
            self.preview_transform_readout_label.setSizePolicy(QSizePolicy.Policy.Maximum, QSizePolicy.Policy.Preferred)
            self.preview_keyframe_label = QLabel("Keyframes: 0", header)
            self.preview_keyframe_label.setFont(QFont("Consolas", 9))
            self.preview_keyframe_label.setToolTip("Number of transform keyframes on the selected visual clip.")
            self.preview_keyframe_label.setSizePolicy(QSizePolicy.Policy.Maximum, QSizePolicy.Policy.Preferred)
            try:
                header_layout = header.layout()
                if header_layout is not None:
                    insert_index = max(0, header_layout.count() - 1)
                    for widget in (self.preview_transform_readout_label, self.preview_keyframe_label):
                        header_layout.insertWidget(insert_index, widget)
                        insert_index += 1
            except Exception:
                pass
            self.preview_collapse_btn.clicked.connect(self.toggle_preview_panel)
            main.addWidget(header)

            # Keep the Preview body in one wrapper so the collapse button can
            # hide the whole canvas/control area and leave only the header.
