        def set_clip_rotation_dialog(self, clip: Clip) -> None:
            current = self._current_visual_transform_for_clip_edit(clip)
            value, ok = QInputDialog.getDouble(self, "Set rotation", "Rotation degrees:", float(current["transform_rotation"]), -36000.0, 36000.0, 1)
            if not ok:
                return
            self.set_clip_rotation(clip, value)

        def _apply_transform_to_selected_clips(self, build_transform: Any, reason: str, success_log: str) -> None:
            selected = self.selected_clips()
            if not selected:
                self.log("Transform skipped: no clip selected.")
                return
            changed = 0
            skipped_audio = 0
            skipped_locked = 0
            self._begin_project_edit(reason)
            seen: set[str] = set()
            for clip in selected:
                clip_id = str(getattr(clip, "clip_id", "") or "")
                if clip_id and clip_id in seen:
                    continue
                if clip_id:
                    seen.add(clip_id)
                if not clip_is_visual(clip):
                    skipped_audio += 1
                    continue
                can_edit, message = self.project.can_edit_clip(clip.clip_id)
                if not can_edit:
                    skipped_locked += 1
                    self.log(f"Transform skipped for {clip.name}: {message}")
                    continue
                before = visual_transform_at_timeline_time(clip, getattr(self, "playhead_time", 0.0)) if clip_has_visual_keyframes(clip) else normalize_clip_visual_transform(clip)
                transform = build_transform(clip)
                if clip_has_visual_keyframes(clip):
                    set_visual_keyframe_at_clip_time(clip, self._clip_local_time_at_playhead(clip), transform)
                    apply_visual_transform_to_clip(clip, default_visual_transform())
                    after = visual_transform_at_timeline_time(clip, getattr(self, "playhead_time", 0.0))
                else:
                    apply_visual_transform_to_clip(clip, transform)
                    after = normalize_clip_visual_transform(clip)
                if after != before:
                    changed += 1
            if changed <= 0:
                self._abort_project_edit()
                if skipped_audio:
                    self.log(f"Transform skipped: {skipped_audio} audio-only clip(s) ignored.")
                if skipped_locked:
                    self.log(f"Transform skipped: {skipped_locked} locked clip(s) ignored.")
                if not skipped_audio and not skipped_locked:
                    self.log("Transform skipped: selected visual clip(s) already had that setting.")
                return
            self.log(success_log.format(count=changed))
            if skipped_audio:
                self.log(f"Transform skipped audio-only clips: {skipped_audio}")
            if skipped_locked:
                self.log(f"Transform skipped locked clips: {skipped_locked}")
            self._after_transform_change(save_state=True, reason=reason)

        def set_selected_transform_fit_mode(self, mode: str) -> None:
            fit_mode = normalize_transform_fit_mode(mode)
            def build(clip: Clip) -> Dict[str, Any]:
                transform = self._current_visual_transform_for_clip_edit(clip)
                transform["transform_fit_mode"] = fit_mode
                return transform
            self._apply_transform_to_selected_clips(build, "set transform fit mode", f"Fit mode set: {{count}} clip(s) {fit_mode}")

        def set_selected_clip_mirror(self, mirror_x: bool, mirror_y: bool, reason: str = "set mirror") -> None:
            selected = self.selected_clips()
            if not selected:
                self.log("Mirror skipped: no clip selected.")
                return
            changed = 0
            skipped_audio = 0
            skipped_locked = 0
            self._begin_project_edit(reason)
            seen: set[str] = set()
            for clip in selected:
                clip_id = str(getattr(clip, "clip_id", "") or "")
                if clip_id and clip_id in seen:
                    continue
                if clip_id:
                    seen.add(clip_id)
                if not clip_is_visual(clip):
                    skipped_audio += 1
                    continue
                can_edit, message = self.project.can_edit_clip(clip.clip_id)
                if not can_edit:
                    skipped_locked += 1
                    self.log(f"Mirror skipped for {clip.name}: {message}")
                    continue
                if set_clip_mirror_state(clip, mirror_x, mirror_y):
                    changed += 1
            if changed <= 0:
                self._abort_project_edit()
                if skipped_audio:
                    self.log(f"Mirror skipped: {skipped_audio} audio/text clip(s) ignored.")
                if skipped_locked:
                    self.log(f"Mirror skipped: {skipped_locked} locked clip(s) ignored.")
                if not skipped_audio and not skipped_locked:
                    self.log("Mirror skipped: selected visual clip(s) already had that mirror setting.")
                return
            state = []
            if bool(mirror_x):
                state.append("horizontal")
            if bool(mirror_y):
                state.append("vertical")
            label = " + ".join(state) if state else "off"
            self.log(f"Mirror set: {changed} clip(s) {label}")
            if skipped_audio:
                self.log(f"Mirror skipped audio/text clips: {skipped_audio}")
            if skipped_locked:
                self.log(f"Mirror skipped locked clips: {skipped_locked}")
            self._after_transform_change(save_state=True, reason=reason)

        def toggle_selected_clip_mirror(self, axis: str) -> None:
            primary = self.project.get_clip(self.selected_clip_id) if self.selected_clip_id else None
            if primary is None or not clip_is_visual(primary):
                self.log("Mirror skipped: select a video or image clip.")
                return
            clean_axis = str(axis or "").strip().lower()
            if clean_axis == "x":
                self.set_selected_clip_mirror(not clip_mirror_x_value(primary), clip_mirror_y_value(primary), "toggle mirror horizontal")
            elif clean_axis == "y":
                self.set_selected_clip_mirror(clip_mirror_x_value(primary), not clip_mirror_y_value(primary), "toggle mirror vertical")
            else:
                self.log("Mirror skipped: unknown mirror axis.")

        def reset_selected_clip_transforms(self) -> None:
            self._apply_transform_to_selected_clips(lambda _clip: default_visual_transform(), "reset visual transform", "Transform reset: {count} clip(s)")

