            initial = float(self._current_visual_transform_for_clip_edit(primary)["transform_scale"]) if primary is not None else 1.0
            value, ok = QInputDialog.getDouble(self, "Set scale for selected", "Scale (0.05 to 20.0):", initial, TRANSFORM_SCALE_MIN, TRANSFORM_SCALE_MAX, 3)
