        def set_selected_clip_rotation_dialog(self) -> None:
            primary = self.project.get_clip(self.selected_clip_id) if self.selected_clip_id else None
            initial = float(self._current_visual_transform_for_clip_edit(primary)["transform_rotation"]) if primary is not None else 0.0
            value, ok = QInputDialog.getDouble(self, "Set rotation for selected", "Rotation degrees:", initial, -36000.0, 36000.0, 1)
            if not ok:
                return
            self.set_selected_clip_rotation(value)

        def duplicate_selected_clip(self) -> None:
            selected = self._sorted_selected_clips_for_group_ops()
            if not selected:
                self.log("Duplicate skipped: no clip selected.")
                return
            if len(selected) > 1:
                blocked: List[str] = []
                for source in selected:
                    can_edit, message = self.project.can_edit_clip(source.clip_id)
                    if not can_edit:
                        blocked.append(message or source.name or source.clip_id)
                if blocked:
                    self.log("Duplicate group skipped: selected group contains locked/uneditable clip(s).")
                    return
                base_start = min(float(clip.start) for clip in selected)
                group_end = max(float(clip.end) for clip in selected)
                duplicate_start = self._maybe_snap(group_end)
                new_clips: List[Clip] = []
                skipped = 0
                for source in selected:
                    payload = timeline_copy_clip_payload(source)
                    track_id = str(source.track_id or self.project.track_id_from_index(self.project.clip_track_index(source)) or "")
                    if not track_id or self.project.is_track_locked(track_id):
                        skipped += 1
                        continue
                    new_clip = timeline_make_clip_copy_from_payload(self.project, payload, duplicate_start + (float(source.start) - base_start), track_id)
                    if new_clip is None:
                        skipped += 1
                        continue
                    new_clips.append(new_clip)
                if not new_clips:
                    self.log("Duplicate group skipped: no selected clips could be duplicated.")
                    return
                self._begin_project_edit("duplicate clip group")
                self.project.clips.extend(new_clips)
                self.project.sort_clips()
                self._apply_clip_selection([clip.clip_id for clip in new_clips], new_clips[0].clip_id, new_clips[0].clip_id)
                self.log(f"Duplicated group: {len(new_clips)} clip(s) at {fmt_time(duplicate_start)}")
                if skipped:
                    self.log(f"Duplicate group skipped {skipped} clip(s).")
                self.update_after_timeline_change(save_state=True, reason="duplicate clip group")
                return

            source = selected[0]
            can_edit, message = self.project.can_edit_clip(source.clip_id)
            if not can_edit:
                self.log(f"Duplicate skipped: {message}")
                return
            track_id = source.track_id or self.project.track_id_from_index(self.project.clip_track_index(source))
            if self.project.is_track_locked(track_id):
                self.log("Duplicate skipped: Track locked")
                return
            payload = timeline_copy_clip_payload(source)
            start = self._maybe_snap(source.end)
            clip = timeline_make_clip_copy_from_payload(self.project, payload, start, track_id)
            if not clip:
                self.log("Duplicate skipped: target track is locked or missing.")
                return
            self._begin_project_edit("duplicate clip")
            self.project.clips.append(clip)
            self.project.sort_clips()
            self.select_clip(clip.clip_id)
            self.log(f"Duplicated clip at {fmt_time(clip.start)} on {self.project.track_label_for_clip(clip)}: {clip.name}")
            self.update_after_timeline_change(save_state=True, reason="duplicate clip")

        def detach_audio_from_clip(self, clip: Clip) -> None:
            if not clip:
                return
            if clip_media_type(clip) != "video":
                self.log("Detach audio not available for image/audio clips")
                return
            if abs(clip_speed_value(clip) - 1.0) > 1e-6:
                self.log("Detach audio from speed-changed video is not supported yet")
                return
            can_edit, message = self.project.can_edit_clip(clip.clip_id)
            if not can_edit:
                self.log(f"Detach audio skipped: {message}")
                return
            self._begin_project_edit("detach audio")
            ok, message, audio_clip = self.project.detach_audio_from_video(clip.clip_id)
            if not ok or audio_clip is None:
                self._abort_project_edit()
                self.log(message or "Detach audio skipped.")
                return
            self.select_clip(audio_clip.clip_id)
            self.log(f"Audio detached from video: {clip.name}")
            self.log(f"Created detached audio clip: {audio_clip.name}")
            self.log("Original video audio disabled")
            self._sync_timeline_audio_to_time(self.playhead_time, force=True)
            self.update_after_timeline_change(save_state=True, reason="detach audio")

        def select_linked_clip(self, clip: Clip) -> None:
            linked = self.project.linked_clip_for(clip)
            if linked is None:
                self.log("Select linked clip skipped: linked clip not found.")
                return
            self.select_clip(linked.clip_id)
            self.set_playhead_time(linked.start, save_state=True)
            self.log(f"Selected linked clip: {linked.name}")

        def open_clip_source_folder(self, clip: Clip) -> None:
            status = clip_source_folder_status(clip)
            if not bool(status.get("ok")):
                self.log(f"Open source folder skipped: {status.get('reason')}")
                return
            folder = Path(str(status.get("folder") or ""))
            try:
                if os.name == "nt":
                    os.startfile(str(folder))  # type: ignore[attr-defined]
                else:
                    QDesktopServices.openUrl(QUrl.fromLocalFile(str(folder)))
                self.log(f"Opened source folder: {folder}")
            except Exception as exc:
                self.log(f"Open source folder failed: {exc}")

