        def change_clip_speed_dialog(self, clip: Clip) -> None:
            if not clip:
                return
            can_edit, message = self.project.can_edit_clip(clip.clip_id)
            if not can_edit:
                self.log(f"Change speed skipped: {message}")
                return
            if clip_media_type(clip) == "image":
                self.log("Speed change is not used for image clips.")
                return
            if not clip_supports_speed(clip):
                self.log("Speed change is currently video-only.")
                return
            options = ["0.25x", "0.5x", "0.75x", "1.0x", "1.25x", "1.5x", "2.0x", "Custom..."]
            current_speed = clip_speed_value(clip)
            default_index = 3
            for i, opt in enumerate(options[:-1]):
                try:
                    if abs(float(opt.rstrip("x")) - current_speed) < 1e-6:
                        default_index = i
                        break
                except Exception:
                    pass
            choice, ok = QInputDialog.getItem(self, "Change speed", "Speed:", options, default_index, False)
            if not ok:
                return
            if str(choice) == "Custom...":
                value, ok = QInputDialog.getDouble(
                    self,
                    "Custom speed",
                    f"Speed ({MIN_CLIP_SPEED:.2f}x to {MAX_CLIP_SPEED:.2f}x):",
                    current_speed,
                    MIN_CLIP_SPEED,
                    MAX_CLIP_SPEED,
                    3,
                )
                if not ok:
                    return
                new_speed = float(value)
            else:
                try:
                    new_speed = float(str(choice).rstrip("x"))
                except Exception:
                    self.log("Change speed skipped: invalid speed.")
                    return
            self._begin_project_edit("change clip speed")
            ok, message = self.project.change_clip_speed(clip.clip_id, new_speed)
            if ok:
                self.log(f"Changed speed: {clip.name} -> {clip_speed_value(clip):.2f}x | duration {fmt_time(clip.duration)}")
                self.update_after_timeline_change(save_state=True, reason="change clip speed")
            else:
                self._abort_project_edit()
                self.log(message or "Change speed skipped.")

        def toggle_selected_clip_reverse_playback(self, clicked_clip: Optional[Clip] = None) -> None:
            selected = self.selected_clips()
            if not selected and clicked_clip is not None:
                selected = [clicked_clip]
            if not selected:
                self.log("Play backwards skipped: no clip selected.")
                return
            base_clip = clicked_clip if clicked_clip is not None else selected[0]
            target_value = not clip_reverse_playback_value(base_clip)
            changed = 0
            skipped_non_video = 0
            skipped_locked = 0
            self._begin_project_edit("toggle reverse playback")
            seen: set[str] = set()
            for clip in selected:
                clip_id = str(getattr(clip, "clip_id", "") or "")
                if clip_id and clip_id in seen:
                    continue
                if clip_id:
                    seen.add(clip_id)
                if clip_media_type(clip) != "video":
                    skipped_non_video += 1
                    continue
                can_edit, message = self.project.can_edit_clip(clip.clip_id)
                if not can_edit:
                    skipped_locked += 1
                    self.log(f"Play backwards skipped for {clip.name}: {message}")
                    continue
                if set_clip_reverse_playback_state(clip, target_value):
                    changed += 1
            if changed <= 0:
                self._abort_project_edit()
                if skipped_non_video:
                    self.log(f"Play backwards skipped: {skipped_non_video} non-video clip(s) ignored.")
                if skipped_locked:
                    self.log(f"Play backwards skipped: {skipped_locked} locked clip(s) ignored.")
                if not skipped_non_video and not skipped_locked:
                    self.log("Play backwards skipped: selected video clip(s) already had that setting.")
                return
            state_label = "on" if target_value else "off"
            self.log(f"Play backwards {state_label}: {changed} video clip(s)")
            if skipped_non_video:
                self.log(f"Play backwards skipped non-video clips: {skipped_non_video}")
            if skipped_locked:
                self.log(f"Play backwards skipped locked clips: {skipped_locked}")
            self.update_after_timeline_change(save_state=True, reason="toggle reverse playback")
            self.request_timeline_preview_refresh(reason="toggle_reverse_playback", exact=True)

