        def set_clip_fade(self, clip: Clip, fade_side: str, duration: Any) -> None:
            if not clip:
                return
            can_edit, message = self.project.can_edit_clip(clip.clip_id)
            if not can_edit:
                self.log(f"Fade change skipped: {message}")
                return
            if not clip_can_have_audio_fades(clip):
                self.log("Fade change skipped: clip has no audio.")
                return
            requested = max(0.0, safe_float(duration, 0.0))
            self._begin_project_edit("clip audio fade")
            if str(fade_side).lower() == "out":
                ok, message = self.project.set_clip_fade_out(clip.clip_id, requested)
                current = clip_fade_out_duration_value(clip)
                label = "Audio fade out"
            else:
                ok, message = self.project.set_clip_fade_in(clip.clip_id, requested)
                current = clip_fade_in_duration_value(clip)
                label = "Audio fade in"
            if ok:
                if message == "clamped":
                    self.log(f"Audio fade duration clamped: {clip.name} {current:g}s")
                self.log(f"{label} set: {clip.name} {current:g}s")
                self._sync_timeline_audio_to_time(self.playhead_time, force=True)
                self.update_after_timeline_change(save_state=True, reason="clip audio fade")
            else:
                self._abort_project_edit()
                self.log(message or "Fade change skipped.")

