        def set_clip_video_fade_duration_dialog(self, clip: Clip) -> None:
            if not clip:
                return
            current_values = [v for v in (clip_video_fade_in_duration_value(clip), clip_video_fade_out_duration_value(clip)) if v > 0.0]
            current = current_values[0] if current_values else DEFAULT_FADE_SHORT_DURATION
            value, ok = QInputDialog.getDouble(
                self,
                "Set video fade duration",
                "Duration for enabled video fades (seconds). If none are enabled, both are set:",
                current,
                0.0,
                max(0.0, float(clip.duration or 0.0)),
                2,
            )
            if not ok:
                return
            apply_in = clip_video_fade_in_duration_value(clip) > 0.0
            apply_out = clip_video_fade_out_duration_value(clip) > 0.0
            if not apply_in and not apply_out:
                apply_in = True
                apply_out = True
            self._begin_project_edit("clip video fade")
            ok_all = True
            messages = []
            if apply_in:
                ok, message = self.project.set_clip_video_fade_in(clip.clip_id, value)
                ok_all = ok_all and ok
                if message:
                    messages.append(message)
            if apply_out:
                ok, message = self.project.set_clip_video_fade_out(clip.clip_id, value)
                ok_all = ok_all and ok
                if message:
                    messages.append(message)
            if ok_all:
                if "clamped" in messages:
                    self.log(f"Video fade duration clamped: {clip.name}")
                self.log(f"Video fade duration set: {clip.name} in {clip_video_fade_in_duration_value(clip):g}s / out {clip_video_fade_out_duration_value(clip):g}s")
                self.update_after_timeline_change(save_state=True, reason="clip video fade")
            else:
                self._abort_project_edit()
                self.log("Video fade duration skipped.")

