        def _clip_local_time_at_playhead(self, clip: Clip) -> Optional[float]:
            if not clip:
                return None
            if self.playhead_time < clip.start - 0.0005 or self.playhead_time > clip.end + 0.0005:
                return None
            return clip_local_time_from_timeline(clip, self.playhead_time, clamp_to_clip=True)

        def _automation_clip_ready(self, clip: Clip, action_label: str = "Volume automation") -> bool:
            if not clip:
                return False
            can_edit, message = self.project.can_edit_clip(clip.clip_id)
            if not can_edit:
                self.log(f"{action_label} skipped: {message}")
                return False
            if not clip_can_have_audio_automation(clip):
                self.log(f"{action_label} skipped: clip has no audio.")
                return False
            return True

        def add_volume_point_at_playhead(self, clip: Clip) -> None:
            if not self._automation_clip_ready(clip, "Volume point add"):
                return
            local_time = self._clip_local_time_at_playhead(clip)
            if local_time is None:
                self.log("Volume point add skipped: playhead must be inside the clip.")
                return
            current_percent = audio_automation_multiplier_for_clip(clip, self.playhead_time) * 100.0
            value, ok = QInputDialog.getDouble(self, "Add volume point", "Volume (%):", current_percent, MIN_AUDIO_VOLUME, MAX_AUDIO_VOLUME, 1)
            if not ok:
                return
            self._begin_project_edit("volume automation")
            ok, message = self.project.set_clip_audio_keyframe(clip.clip_id, local_time, value)
            if ok:
                self.log(f"Volume point {'edited' if message == 'updated' else 'added'}: {clip.name} {local_time:g}s {clamp_audio_volume_percent(value):.0f}%")
                self._sync_timeline_audio_to_time(self.playhead_time, force=True)
                self.update_after_timeline_change(save_state=True, reason="volume automation")
            else:
                self._abort_project_edit()
                self.log(message or "Volume point add skipped.")

        def edit_nearest_volume_point(self, clip: Clip) -> None:
            if not self._automation_clip_ready(clip, "Volume point edit"):
                return
            local_time = self._clip_local_time_at_playhead(clip)
            if local_time is None:
                self.log("Volume point edit skipped: playhead must be inside the clip.")
                return
            points = normalize_audio_keyframes_for_clip(clip)
            index = nearest_audio_keyframe_index(clip, local_time)
            if index is None:
                self.log("Volume point edit skipped: no nearby volume point.")
                return
            point = points[index]
            value, ok = QInputDialog.getDouble(self, "Edit volume point", "Volume (%):", float(point.get("volume", DEFAULT_CLIP_VOLUME)), MIN_AUDIO_VOLUME, MAX_AUDIO_VOLUME, 1)
            if not ok:
                return
            self._begin_project_edit("volume automation")
            ok, message = self.project.edit_nearest_clip_audio_keyframe(clip.clip_id, local_time, value)
            if ok:
                self.log(f"Volume point edited: {clip.name}")
                self._sync_timeline_audio_to_time(self.playhead_time, force=True)
                self.update_after_timeline_change(save_state=True, reason="volume automation")
            else:
                self._abort_project_edit()
                self.log(message or "Volume point edit skipped.")

