        def apply_volume_automation_preset(self, clip: Clip, preset: str) -> None:
            if not self._automation_clip_ready(clip, "Volume automation preset"):
                return
            self._begin_project_edit("volume automation")
            ok, message = self.project.apply_clip_audio_keyframe_preset(clip.clip_id, preset)
            if ok:
                self.log(f"Volume automation preset applied: {clip.name}")
                self._sync_timeline_audio_to_time(self.playhead_time, force=True)
                self.update_after_timeline_change(save_state=True, reason="volume automation")
            else:
                self._abort_project_edit()
                self.log(message or "Volume automation preset skipped.")

        def show_clip_info(self, clip: Clip) -> None:
            QMessageBox.information(self, "Clip info", self._clip_info_text(clip))

        def reset_clip_trim(self, clip: Clip) -> None:
            if not clip:
                return
            can_edit, message = self.project.can_edit_clip(clip.clip_id)
            if not can_edit:
                self.log(f"Reset trim skipped: {message}")
                return
            self._begin_project_edit("reset trim")
            if self.project.reset_clip_trim(clip.clip_id):
                self.log(f"Reset trim: {clip.name} | duration {fmt_time(clip.duration)}")
                self.update_after_timeline_change(save_state=True, reason="reset trim")
            else:
                self._abort_project_edit()

        def set_clip_duration_dialog(self, clip: Clip) -> None:
            if not clip:
                return
            can_edit, message = self.project.can_edit_clip(clip.clip_id)
            if not can_edit:
                self.log(f"Set duration skipped: {message}")
                return
            max_value = 24.0 * 60.0 * 60.0 if clip.media_type == "image" else self.project.max_duration_for_clip(clip)
            label = "Duration in seconds:"
            if clip.media_type != "image":
                label += f" (max {max_value:.3f}s from source)"
            value, ok = QInputDialog.getDouble(
                self,
                "Set clip duration",
                label,
                float(clip.duration),
                MIN_CLIP_DURATION,
                max_value,
                3,
            )
            if not ok:
                return
            self._begin_project_edit("set duration")
            if self.project.set_clip_duration(clip.clip_id, value, snap=self.snap_enabled):
                self.log(f"Set duration: {clip.name} -> {fmt_time(clip.duration)}")
                self.update_after_timeline_change(save_state=True, reason="set duration")
            else:
                self._abort_project_edit()


        def _sync_timeline_canvas_geometry(self) -> None:
            """Keep vertical track scrolling independent from layout presets.

            QScrollArea does not always recalculate its vertical range after a
            splitter preset re-parents/resizes the timeline. Keep the canvas at
            the real content height and explicitly refresh the vertical scrollbar
            range so lower tracks are reachable immediately after startup and
            layout changes, without waiting for a manual window resize.
            """
            if not hasattr(self, "canvas"):
                return
            self.canvas.refresh_layout()
            if not hasattr(self, "canvas_scroll_area"):
                return
            try:
                viewport = self.canvas_scroll_area.viewport()
                viewport_width = int(viewport.width()) if viewport is not None else int(self.canvas.width())
                viewport_height = int(viewport.height()) if viewport is not None else int(self.canvas_scroll_area.height())
            except Exception:
                viewport_width = int(self.canvas.width()) if hasattr(self, "canvas") else 900
                viewport_height = int(self.canvas_scroll_area.height()) if hasattr(self, "canvas_scroll_area") else 240
            width = max(1, viewport_width)
            height = max(1, int(self.canvas.content_height()))
            if self.canvas.width() != width or self.canvas.height() != height:
                self.canvas.resize(width, height)
            self.canvas.setMinimumSize(width, height)
            self.canvas.setMaximumHeight(height)
            self.canvas.updateGeometry()
            try:
                vbar = self.canvas_scroll_area.verticalScrollBar()
                if vbar is not None:
                    old_value = int(vbar.value())
                    max_value = max(0, height - max(1, viewport_height))
                    vbar.blockSignals(True)
                    try:
                        vbar.setPageStep(max(1, viewport_height))
                        vbar.setSingleStep(max(8, int(TimelineCanvas.track_height // 4)))
                        vbar.setRange(0, max_value)
                        vbar.setValue(int(clamp(old_value, 0, max_value)))
                    finally:
                        vbar.blockSignals(False)
            except Exception:
                pass
            self.canvas_scroll_area.updateGeometry()
            try:
                self.canvas_scroll_area.viewport().update()
            except Exception:
                pass
            self.canvas.update()

        def _run_one_shot_timeline_layout_refresh(self) -> None:
            """One small timeline geometry refresh pass after a layout change.

            Keep this deliberately boring: it must not rebuild layouts, resize the
            main window, or schedule itself again. It only nudges the existing
            timeline widgets so Qt recalculates the scroll area after splitter
            reparenting.
            """
            try:
                self._sync_timeline_canvas_geometry()
            except Exception:
                pass
            try:
                if hasattr(self, "canvas"):
                    self.canvas.updateGeometry()
                    self.canvas.update()
                if hasattr(self, "canvas_scroll_area"):
                    self.canvas_scroll_area.updateGeometry()
                    viewport = self.canvas_scroll_area.viewport()
                    if viewport is not None:
                        viewport.update()
            except Exception:
                pass

        def _finish_one_shot_timeline_layout_refresh(self) -> None:
            try:
                self._run_one_shot_timeline_layout_refresh()
            finally:
                self._timeline_layout_refresh_pending = False

        def _schedule_timeline_scrollbar_refresh(self, reason: str = "") -> None:
            """Safely refresh timeline scrollbars once after applying a layout.

            A previous version stacked repeated delayed refreshes and could create
            a layout/update loop. This version uses a pending guard and schedules
            only one event-loop refresh plus one short final pass.
            """
            if not hasattr(self, "canvas_scroll_area"):
                return
            if getattr(self, "_timeline_layout_refresh_pending", False):
                return
            self._timeline_layout_refresh_pending = True
            self._run_one_shot_timeline_layout_refresh()
            QTimer.singleShot(0, self._run_one_shot_timeline_layout_refresh)
            QTimer.singleShot(100, self._finish_one_shot_timeline_layout_refresh)

        def refresh_timeline_layout(self) -> None:
            self.project.normalize_tracks_and_clips()
            self.refresh_target_track_combo()
            self._sync_timeline_canvas_geometry()

        def show_track_context_menu(self, source_widget: QWidget, pos: QPoint, track_index: int) -> None:
            if track_index < 0 or track_index >= self.project.track_count():
                return
            menu = QMenu(source_widget)
            rename_action = menu.addAction("Rename track")
            add_above_action = menu.addAction("Add track above")
            add_below_action = menu.addAction("Add track below")
            track_meta = self.project.tracks[track_index]
            visible_now = bool(getattr(track_meta, "visible", True))
            muted_now = bool(getattr(track_meta, "muted", False))
            solo_now = bool(getattr(track_meta, "solo", False))
            locked_now = bool(getattr(track_meta, "locked", False))
            visibility_action = menu.addAction("Hide track" if visible_now else "Show track")
            mute_action = menu.addAction("Unmute track" if muted_now else "Mute track")
            track_volume_action = menu.addAction(f"Set track volume... ({track_volume_percent_value(track_meta):.0f}%)")
            track_volume_reset_action = menu.addAction("Reset track volume")
            solo_action = menu.addAction("Unsolo track" if solo_now else "Solo track")
            lock_action = menu.addAction("Unlock track" if locked_now else "Lock track")
            menu.addSeparator()
            move_up_action = menu.addAction("Move up")
            move_down_action = menu.addAction("Move down")
            remove_action = menu.addAction("Remove track")
            move_up_action.setEnabled(track_index > 0)
            move_down_action.setEnabled(track_index < self.project.track_count() - 1)
            can_remove, _message = self.project.can_remove_track(track_index)
            remove_action.setEnabled(can_remove)
            chosen = menu.exec(source_widget.mapToGlobal(pos))
            if chosen == rename_action:
                self.rename_track_dialog(track_index)
            elif chosen == visibility_action:
                self.toggle_track_visibility(track_index)
            elif chosen == mute_action:
                self.toggle_track_mute(track_index)
            elif chosen == track_volume_action:
                self.set_track_volume_dialog(track_index)
            elif chosen == track_volume_reset_action:
                self.reset_track_volume(track_index)
            elif chosen == solo_action:
                self.toggle_track_solo(track_index)
            elif chosen == lock_action:
                self.toggle_track_lock(track_index)
            elif chosen == add_above_action:
                self.add_track_dialog(index=track_index)
            elif chosen == add_below_action:
                self.add_track_dialog(index=track_index + 1)
            elif chosen == move_up_action:
                self.move_track(track_index, -1)
            elif chosen == move_down_action:
                self.move_track(track_index, 1)
            elif chosen == remove_action:
                self.remove_track(track_index)

        def toggle_track_visibility(self, track_index: int) -> None:
            if track_index < 0 or track_index >= self.project.track_count():
                return
            self._begin_project_edit("hide/show track")
            visible = self.project.toggle_track_visible(track_index)
            track_name = self.project.track_label_by_index(track_index)
            if visible is None:
                self._abort_project_edit()
                return
            if visible:
                self.log(f"Track visible for visual playback: {track_name}")
            else:
                self.log(f"Track hidden from visual playback: {track_name}")
            self.update_after_timeline_change(save_state=True, reason="hide/show track")

        def toggle_track_mute(self, track_index: int) -> None:
            if track_index < 0 or track_index >= self.project.track_count():
                return
            self._begin_project_edit("mute/unmute track")
            muted = self.project.toggle_track_muted(track_index)
            track_name = self.project.track_label_by_index(track_index)
            if muted is None:
                self._abort_project_edit()
                return
            self.log(("Track muted: " if muted else "Track unmuted: ") + track_name)
            self._sync_timeline_audio_to_time(self.playhead_time, force=True)
            self.update_after_timeline_change(save_state=True, reason="mute/unmute track")

